","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","자세히","보상","수행","임무","현재 스테이지","배틀 로그","획득","전체","여름 축제 - 냥국무쌍\n이벤트 기간: 8월 10일 점검 후 ~ 9월 3일 05:59(GMT+9)\n\n냐무라이 이치히메 출전! 신의 도움을 받은 이치히메는 천하 무쌍이다냥!\n\n이벤트 기간 동안 등급전, 대회전, 친선전에서 AI를 제외한 대국을 진행하여 화료할 때, 냐무라이 이치히메가 공격을 시작합니다. 스테이지를 클리어하면 한정 후로 연출, 한정 라이브 작탁, 기원의 두루마리등 푸짐한 보상을 획득할 수 있습니다.\n* 화료 점수에 따른 공격 피해의 전환 비율은 4인 마작 100:1, 3인 마작 및 삼도라 모드등 특수 규칙 300:1로 적용됩니다.\n* 수라전 및 적혈전 제외\n\n이벤트 기간 동안 매일 3개의 새로운 스테이지가 오픈됩니다.\n스테이지 30 클리어 시, 한정 후로 연출: 꾸르륵을 획득할 수 있습니다.\n스테이지 45 클리어 시, 한정 라이브 작탁: 보라빛 노을을 획득할 수 있습니다.\n\n이벤트 기간 동안 임무를 완료하여 스킬 포인트를 획득할 수 있으며, 각 스킬에는 3개의 레벨이 있습니다. 수행을 통해 이치히메를 더욱 강하게 만들어 주세요!\n\n기초 수행: 모든 피해량 증가\n리듬 마스터: 일정 순에 화료 시, 피해량 증가\n일격필살: 일정 역의 개수를 달성하여 화료 시, 피해량 증가\n다재다능: 일정 역 종류의 개수를 달성하여 화료 시, 피해량 증가\n책략가: 일정 텐파이 면의 개수를 달성하여 화료 시, 피해량 증가\n\n* 자세한 내용은 인게임 화면에서 확인할 수 있습니다.","기초 수행","리듬 마스터","일격필살","다재다능","책략가","Lv","공격!","냐무라이 이치히메, {0} 공격! {1} 피해를 입혔다!","냐무라이 이치히메, {0} 공격! 회심의 일격! {1} 피해를 입혔다!","냐무라이 이치히메, 오늘 더 이상 공격할 수 없다.","냐무라이 이치히메, 모든 적을 처치했다.","{0} 처치!","Lv1: 모든 피해량 5% 증가","Lv2: 모든 피해량 10% 증가","Lv3: 모든 피해량 15% 증가","Lv1: 9순 전 화료 시, 피해량 10% 증가","Lv2: 12순 전 화료 시, 피해량 20% 증가","Lv3: 15순 전 화료 시, 피해량 30% 증가","Lv1: 배만 이상으로 화료 시, 피해량 10% 증가","Lv2: 하네만 이상으로 화료 시, 피해량 20% 증가","Lv3: 만관 이상으로 화료 시, 피해량 30% 증가","Lv1: 6종 이상의 역으로 화료 시, 피해량 10% 증가","Lv2: 4종 이상의 역으로 화료 시, 피해량 20% 증가","Lv3: 2종 이상의 역으로 화료 시, 피해량 30% 증가","Lv1: 화료 시 텐파이 4면 이상, 피해량 10% 증가","Lv2: 화료 시 텐파이 3면 이상, 피해량 20% 증가","Lv3: 화료 시 텐파이 2면 이상, 피해량 30% 증가","스킬 포인트 x","미습득","Lv MAX","스킬 포인트 부족","레벨 업","8월 11일 06:00 오픈","8월 12일 06:00 오픈","8월 13일 06:00 오픈","8월 14일 06:00 오픈","8월 15일 06:00 오픈","8월 16일 06:00 오픈","8월 17일 06:00 오픈","8월 18일 06:00 오픈","8월 19일 06:00 오픈","8월 20일 06:00 오픈","8월 21일 06:00 오픈","8월 22일 06:00 오픈","8월 23일 06:00 오픈","8월 24일 06:00 오픈","8월 25일 06:00 오픈","8월 26일 06:00 오픈","8월 27일 06:00 오픈","8월 28일 06:00 오픈","8월 29일 06:00 오픈","8월 30일 06:00 오픈","8월 11일 \n06:00 오픈","8월 12일 \n06:00 오픈","8월 13일 \n06:00 오픈","8월 14일 \n06:00 오픈","8월 15일 \n06:00 오픈","히메카와 히비키 팬클럽","히비키를위해콰콰쾅쾅쾅","울려퍼져라 히메카와","Maj으악","히비키댓글주세요","히비키히비키히비키","히메카와히비키남바완","유포니움","바람처럼 자유롭게","국사무쌍만침","딸랑이94562","히메카와 히비키 채널 지박령","페이밍","칭난","제인","란세이","사탄","웬펑","키사라기 아야네","소승은돼지요","SAN치핀치","신상노출불가","토끼공주","애플젤리","천연기념퇴물","오버힐","메롱아닌멜론","일 년에 한 번만 찾아오는 이한시의 추석이 돌아왔다냥~ 다들 추석에 뭘 먹어야 하는지 알고 있냥?\n문케이크! 바로 다양한 맛의 문케이크다냥~\n팥, 코코넛, 견과류, 대추, 파인애플! 그 외에도 연꽃 노른자, 커스터드 크림, 장미 잼까지…… 앗! 까먹을 뻔했다냥. 혼천 신사가 아사바 고등학교랑 같이 출시한 매실 게장 맛도 있다냥~","순간, 누가 이긴 건지 헷갈렸습니다……","우스미는 이런 게 바로 윈윈이라고 했다냥~","부회장, 무슨 일 있는 것 같은데? 쫑긋.jpg","후지타, 올해는 콘서트가 많나 봅니다. 출석 일수가 아슬아슬하군요…… 아사바 추석 축제에 출연해 준다면 모른척해 줄 수 있습니다만.","T_T 방심했다……","고작 며칠 복수쌍전관에서 마작 좀 했을 뿐인데, 왜 갑자기 신사에 한정판 문케이크 같은 게 생긴 거지? 맛도 참 근본 없다멍……","지난주에 이시하라랑 이치히메가 마작으로 내기했었어. 진 쪽이 올해 혼천 신사의 추석 문케이크를 책임지기로 말이야~ 그런데 스안커 직전에 이치히메가 먼저 화료할 줄은 몰랐네? 후후~","멍! 지! 로! 지금. 당장. 오라냥! 아직 포장 못한 문케이크가 한가득이다냥! 당장 안 오면 견과류 맛만 먹을 줄 알아냥!","쳇…… 신성한 혼천 신사에 무슨 짓을…… 문케이크라니 그것도 한정판? 그래도 겁나 맛있어 보이긴 하네에에~~","다들 화가 많이 나있네…… 캣챗 점검을 오래 하긴 했지, 몇 개월을 한 거람, 다들 답답했을만해. 요새는 캣챗이 드라마보다 더 재밌다니까……","매실과 게장…… 그거 맞아?","냐? 매실도 맛있고, 게장도 맛있다냥~ 맛있는 거 2개가 만나면 맛도 2배 아니겠냥!","안 먹어봐놓고 말은……","제일 맛있는 문케이크는 추석까지 기다렸다가 주인이랑 같이 먹어야 하는거다냥~ 근데 주인도 늦고, 추석도 너무 늦다냥……","어째 이치히메의 캣챗은 올리는 것마다 메뉴판 같네. 하여간 이치히메가 음식 이름을 말할 때는 점수판 읽을 때만큼 열정적이라니까.","냥? 주인도 점심에 밥을 두 그릇 먹었거나, 낮에 대삼원을 했으면 이치히메한테 캣챗해도 된다냥~ 미키가 그러는데, 캣챗은 자기가 좋아하는 걸 올리는 거라고 했다냥. 이치히메는 주인도 음식도 다 좋아한다냥~","이제 곧 추석이고. 우짠지 요새 손님들이 갈수록 쭐어들더만, 전부 고향으로 가뿐 모양이네…\n차라리 우리도 잠깐 마작장 닫고, 어디든 가서 명절 좀 즐기는 건 어떻노? 나름대로 의미가 깊은 명절이기도 하다이가.","마, 그럼 미디에 찻집 2층으로 온나. 예가 이한시 달구경 최고 명당자리 아이가. 내 항상 니 자리는 냄겨둔다꼬.","니 벌써 몇 년짼데, 내가 또 속을 줄 아나??? 맨~날 차, 차, 차밖에 안 내주믄서! 달도 뜬 추석인데 술이 빠지면, 거 무슨 추석이고…","명절 때마다 살이 토실토실하게 오르니 조심해야 한다멍.","멍지로, 내 말이 그 말이다. 니 몸매야말로 참말로 조심해야 된데이.","얼마 전에 좋은 찻잎이 들어와서, 후지 씨를 모시고 명절을 보내고 싶었는데…","하하, 타이밍 억수로 좋네~ 사실 내도 어디서 좋은 술 몇 병 얻었다이가. 페이밍처럼 굴면 못 쓴다. 술 한 잔 안 걸치고 우째 장사를 할라 그라노? 내 내일 바로 가께.","복수쌍전관을 닫겠다구요? 그냥 열면 안 될까요? 사장님, 마작 하고 싶어요 T_T","오? {0}, 내랑 마작 하고 싶은 기가? 어디 보자, 니가 이런 말을 하는 건 흔치 않긴 한데. 니가 이번에 내를 이기면은, 내년 마작장 요금 30% 할인. 어떻노?","후지 씨는 추석을 좋아하시나 보네요? 특별한 일 없으면 저랑 같이 보내도 괜찮은데.","온 가족이 모이는 날인데, 싫어할 사람이 어디 있겠노. 추석은 옛날부터 말이지… 으음, 이거 설마 유도신문은 아니제? 뭐, 그래도 좋은 제안해 줬으니깐, 나중에 달 구경이라도 하믄서 니한테 추석의 역사나 좀 들려 주께.","냐~~~~~~!!!!!\n이치히메가 열심히 준비한 야옹이 발 모양 매실 게장 맛 문케이크가 토끼 머리 모양으로 변해 버렸다냥!\n누구 짓인 거냥!!!!!!!!!!","하아… 신사에 있는 문케이크도 그렇단 말이야? 모양만 바뀐 게 아니라 속도 말차랑 겨자를 섞은 걸로 바뀌었어.","설마 먹은 건 아니지?","디저트부 부원들이 새로 개발한 메뉴인 줄 알았지…","그럼 올해 한정판 문케이크는 결국 물 건너간 거 아니냥!","만약 내일까지 돌려놓을 수 없다면, 아마… 그렇게 될 것 같네. 하하하…","어떻게 이럴 수가 있는 거냥… 아직 주인도 못 먹어봤다냥…","천월 신사에서도 아침에 이런 문케이크를 받았는데… 감실 위에 올려져 있었어요.","마이는 범인을 보지 못했냥?","미안해요. 아침에 일어났을 때부터 있던 거라서… 조금만 더 일찍 일어났으면 좋았을 텐데.","이 모양은… 쿠쿠쿡. 불가능한 것을 빼고 남은 것은 어쩔 수 없이 진실일 수밖에 없지.","냥? 뭔 소리다냥?","내 생각에 범인은 곧 정체를 드러낼 거야. 걱정 말라구!","어디서 본 것 같은데……","주인은 설마 범인을 알고 있는 거냥!","이치히메. 이 문케이크 모양 말이야, 어디서 본 것 같지 않아?","냥? 이렇게 생긴 과자는 요즘 많이 먹긴 했는데냥… 어디 꺼 말하는거냥?","…………","단서가 없으면, 범인 찾는 데 시간 쓰지 말고 지금부터라도 다시 만들자. 이번엔 내가 도와줄게.","주인은 정말 착하다냥… 무슨 일이 있을 때마다 내 곁에 있어 줘서 참 좋다냥… 매실 게장 맛 말고도, 이치히메는 주인이 직접 만든 초콜릿, 커스터드 크림, 장미 잼맛도 맛보고 싶다냥~","추석 분위기에 맞춰서 따스하면서도 로맨틱한 네일 아트를 해 봤어. 하하, 어때? 해 보고 싶은 사람? 마침 네일용 큐빅이 한 세트 남는데~","우와, 평소에 하던 갸루 스타일이랑은 좀 달라 보이는데? 그런데 또 막상 어디가 다르냐고 물으면 뭔가 대답하기 어려운 그런 느낌.","아마 평소에는 이런 핑크빛 소녀소녀한 스타일로 꾸미질 않아서 그런 게 아닐까. 하하. 물론 유행을 잘 따르는 것이야말로 갸루의 본분이니, 핑크빛 소녀 스타일이라도 따지자면 \'순한 맛 갸루\'로 쳐 줄 수 있지 않을까?","갸루의 본분 같은 것에 대해선 잘 모르겠지만, 이해는 가. 후후, 그냥 하고 싶은 대로 하면 되는 거지!","빙고! 나나는 역시 갸루의 소질이 있어~","나, 나 할래! 원래 이런 분홍색은 완전 하얀 피부에만 어울린다고 생각했는데, 이제 보니 다 잘 어울리네~","OK~ 명절 끝나면 학교에 가져갈게~","키라라 디자인이 다 했네. 진작에 알았다면 데이트 전에 키라라한테 네일 아트를 해 달라고 하는 거였는데… 맞다, 학교에 이렇게나 반짝이는 네일 아트를 하고 갔다간 렌이 주의를 줄 수도 있을 테니 조심하렴~","후후, 제가 선생님께 네일 아트를 해 드릴 테니까, 대신 비밀을 지켜 주셔야 해요~ 맞다, 이번 데이트 상대는 누구예요?","비밀! 보건 지식과 관계없는 질문에는 묵비권을 행사할 거예요~","그거 하는 법 링크 좀… 아니, 나도 똑같은 네일 해 줘!","하하, {0}에게 해 줄 디자인은 내가 진작에 준비해 뒀지롱! 오늘 밤부터 시작할 \'추석 커플 네일 아트\'를 기대해 달라구~","역시 너는 너답게 명절을 보내는구나. 정말 딱 너다워!","그럼 너는? 넌 명절을 어떻게 보내? ……갑자기 궁금한 건데, 넌 전통적인 스타일이야? 아니면 유행을 좋아해?","범인들이여, 드디어 이날이 도래하였노라. 몸과 마음을 다해 정성껏 이 몸을 모시거라. 우히히히히~\n아 맞다. 이 몸이 이번에 그대들에게 준 추석 선물은 마음에 들었느냐?","냐! 역시 이 토끼가 그런 거다냥! 혼천 신사의 문케이크를 돌려내라냥!!!","우히히~ 꼬맹이, 혼천 신사의 문케이크는 이미 평생 걸려도 찾지 못할 곳에 이 몸이 잘 숨겨 두었도다~","아 그래. 이 몸이 그대에게 비밀을 하나 더 알려 주도록 하지. 이건 그저 이 몸이 혼천 신사를 차지하려는 계획의 첫걸음에 불과하니라. 우히히~","역시, 며칠 전에…","쉿, 그대가 무슨 말을 하려는 건지 이 몸은 잘 모르겠다만~","알겠습니다.","T_T 카구야히메 님이 개발한 겨자 말차야말로 올해 최고의 문케이크입니다! 감기 때문에 일주일 동안 코가 막혔었는데 그걸 먹는 순간 코가 뻥 뚫렸거든요. 카구야히메 님이야말로 진정한 신이십니다. 으헝헝…","카구야히메 님 대단하옵니다~~~!","추석에 너한테 소원을 빌면 들어 주는 거야?","범인이여, 이몸을 도발하는 건가? 좋다, 그대의 소원을 얘기해 보거라!","그럼…… 달 토끼 토끼야, 어디를 가느냐, 문케이크를 내놓지 않으면 구워서 먹으리…?","흥!","역시 너였군. 이제 혼천 신사에 손을 대려는 거야? 아, 잠깐… 그러고 보니 네가 혼천 신사를 차지하겠다고 말한 지는 벌써 한참 된 것 같은데.","우히히. 이게 바로 신님의 지혜라는 거다. 신사 하나를 차지하는 정도의 중대사는 당연히 길일을 골라서 해야만 하는 것 아니겠느냐~","범인이여, 이 몸을 얌전히 따르거라. 내년에 맞이할 오늘은 이 몸이 혼천 신사를 차지하는 일 주년 기념일이 될 테니까 말이지. 우히히히히~","천월 신사의 계수나무가 인연을 맺어 주는 나무로 불리고 있는 것 같아요… 뭐, 이렇게 특별한 날에는 분명 나무의 신께서도 모두가 행복하도록 보살펴 주시겠죠.","계수나무는 이쁘고 향도 좋지. 그저… 코에는 영 좋지 좋다는 게 문제지만 말이야. 젠장!","어쩐지, 요즘 신사에 물건을 가져다주시는 분이 바뀌었더라니, 그런 이유가 있었군요. 에인 씨, 부디 몸조심하세요.","혼천 신사의 복잡한 전통 의례에 비하면, 천월 신사는 꽤나 젊은 층이 좋아할 법한 느낌인데~","할아버지가 살아 계실 땐 천월 신사에서도 전통적인 의례를 치르고는 했죠… 하지만, 지금 같은 방식도 마이는 나쁘지 않은 것 같아요. 계수나무에 소원 카드를 걸어놓을 자리가 부족할 지경인걸요.","마이는? 마이도 행복을 찾고 싶어?","갑자기 그런 걸 물어보시면, 대답하기가 좀…","사실 마이도 소원 카드를 준비해 뒀어요… 주인님, 마이와 소원 카드를 걸러 계수나무에 같이 가지 않으실래요?","마이가 전통 복장을 입은 모습은 처음 보는걸~","주인님이 보기에는 어떤가요……? 마이에게는 별로 어울리지 않나요?","아니, 엄청 잘 어울려. 마이는 조금 더 자신감을 가져 봐. 넌 뭘 입어도 예쁘니까 말이야!","추석과 관련된 이야기들은 거의 \'다 함께 모이다\'라는 주제인 것 같아. 어쩌면 이게 둥근 보름달이 뜨는 날을 추석으로 정한 이유 중 하나이지 않을까 싶네.\n그런데 옛말에, 달은 음력 15일보다 16일이 더 둥글다고 하지. 그러니 달 구경을 가려면 아무래도 오늘이 더 낫지 않을까 싶은데~","우리 잡지사에서 편집장 일을 해 볼 생각은 정말 없는 거야? 네 경험과 재능으로 분명 여기서 대박을 칠 수 있을 텐데!","답답하게 늘어선 빌딩 안에 갇혀 있는 것보다는 자유로운 삶이 더 좋은지라.","사미르 씨께서 이렇게까지 박식하실 줄은 몰랐네요. 종교든 전통이든 모두 꿰고 계시다니. 하하, 보아하니 저도 아직 배울 점이 많은 것 같습니다.","그저 이곳저곳 돌아다니면서 주워들은 이야기들일 뿐이랍니다. 보고 들은 것이 많다 보니 경험도 자연스레 풍부해진 것이죠. 사탄 씨도 그렇지 않나요?","사미르라면 분명 내가 모르는 민간 전설들을 많이 알고 있겠지?","맞아. 하지만 하나씩 얘기하려면 시간이 꽤나 걸릴 텐데, 그래도 괜찮아? 어쩌면 밤을 새야 할 수도 있을 것 같은데.","사미르는 같이 명절을 보내고 싶은 사람이 있어? 이한시에서는 항상 혼자인 것 같던데.","외로워 보이고 싶진 않지만, 아쉽게도 난 다시 만날 가족이 없어… 하지만, 만일 네가 함께해 준다면 다음 추석부터는 나도 함께 명절을 보낼 사람이 생기겠지.","음…… 냥…… 요즘 이한시 분위기가 좀 이상한 것 같지 않냥?","분위기가 어떻게 이상하다는 건가요? 음산……하다는 건가요?","으냥…… 그런 분위기는 아닌 것 같다냥. 그런 거라면 마이가 가장 먼저 알아차렸을 거다냥~","전 그렇게 대단한 사람이 아닌걸요…… 가끔씩 실수도 하니까 말이에요……","이 몸이 요즘 너한테 총애를 베풀지 않아서 그런지도 모르지. 쓸쓸하지는 않았느냐? 꼬~ 맹~ 아~","또 너냥, 바보 토끼! 다른 사람이 곤란해할 땐 나타나지 마라냥!","우히히~ 하지만 이 몸이 나타나면 그 곤란함도 해결되지 않겠느냐~","그렇긴 하다멍. 좀 열받긴 하지만.","갑자기 생각났는데 있다이가, 분명 그날이 다가와서일꺼다~ 하마터면은 가게 이벤트 준비 까먹을 뻔했다.","무슨 이벤트…… 말이냥?","할로윈 말이다, 할로윈!","냥! 어쩐지 요즘 호박이랑 사탕을 구하기 어려워졌다 싶었다냥!","이치히메가 느꼈다는 이상한 분위기 말이야…… 그건 어떤 분위기를 말하는 거야?","냥?! 마치 이치히메가 이상하다는 뜻으로 들린다냥…… 후냥! 이치히메 뒷담화를 하면, 주인한테 독을 잔뜩 바른 발톱을 맛보여 주겠다냥. 헤헤헤……","요즘 들어 그런 거라면, 곧 할로윈이라서 그런 걸 거야. 다들 할로윈을 준비할 때잖아.","주인, 주인, 트릭 오어 트리트다냥~","응응, 진작 준비해 뒀어~","주인이 최고다냥!","역방향…… 할로윈이 가까워질 때면 생각지 못한 일이 생기기도 하죠. 불안한 일이 있다면 언제든지 절 찾아 주세요.","잡았다 이놈, 큐르! 교활한 점술사 같으니라고. 네 진짜 목적을 말하라는 거다!","파파야 우유는 효과가 있던가요? 참고로, 파파야 우유는 몸매를 가꾸는 데에 아무런 도움도 되지 않는답니다.","그렇게 도발해 봤자, 정의의 마녀는 아무렇지도 않은 거다! 유즈는 전혀 화나지 않았어! 1도 화가 안 나! 진짜라고!","카비 씨의 점은 주부들한테 인기가 많잖아요? 지금까지의 경험으로 보자면, 진짜일지도 몰라요~","큐르르…… 가끔 생각지 못한 일이 일어나는 건 정상 아니야? 할로윈까지도 아직 많이 남았다는 거다.","안 돼…… 이번 주엔 새 앨범을 낼 예정이었는데!","Lucky한 날로 바꿔 보는 건 어때?","그것도 괜찮겠네. 그럼 사장님 설득은 선배한테 부탁할게요.","평소에도 조셉한테 시키지 않았어?","쉿…… 공개적인 장소에서는 선배의 체면을 살려 줘야지! 스캔들도 조심해야 하고 말이야!","설마…… 카나 너, 새 앨범 출시 때문에……","온라인 점이라…… 결과는 어떻게 보는 거지?","사진으로 보여 드리죠. 동영상은 추가 비용이 있어요.","역방향? 무슨 카드길래?","어떤 카드인지는 중요하지 않아요. 중요한 건 결과랍니다.","오늘 주인님이랑 \'이머시브 시어터\'라는 곳에 가서 몰입형 게이미피케이션 연극을 봤는데, 코스프레를 하고 사진을 찍는 코너가 있을 줄은 몰랐어요…… 부끄럽지만 가게 홍보를 도와드리기로 해서 말인데…… 혹시 관심이 있다면 한번 가 보셔도 좋을 것 같아요…… 마이는 꽤 재미있는 곳이라고 생각해요.","으음! 리사리사가 너무너무너무 보고 싶어 했던, \'사무엘의 마음\' 테마네. 그 티켓을 구하다니, 역시 무녀님이야!","사실…… 주인님께서 구해 주신 티켓이랍니다. 저도 주인님 덕분에 볼 수 있었어요.","으으음…… 리사리사를 안 데리고 가다니, 너무해 {0}. 리사리사도 마이쨩 코스프레를 보고 싶었는데 말이야!","이머시브 시어터라…… 요즘 마작장에서 그 얘기 많이 들리던데, 진짜 재밌어?","네, 그런데 마이는 바보 같아서 NPC랑 제대로 말도 못했어요. 그래도 주인님이 계셔서 무사히 클리어할 수 있었답니다.","하하, 역시 {0}. 그런 게임도 잘 하는구나~","마이가 테마랑 잘 어울리더라고, 예뻤어. 다음엔 다른 스토리도 클리어해 보자.","네, 다음엔 마이도 같이 임무를 맡아 볼게요!","으음…… {0}, 다음에는 리사리사랑 뽀요용도 같이 데려가 줘!","사실 나도 잘 하는 편은 아냐. 마이랑 같이 해서 클리어할 수 있었던 거지.","마이한테 주인님은 이미 엄청난 사람인걸요. 저도…… 다음에는 주인님처럼 해내고 싶어요……","춤추거라, 나비들아.","유이유이도 이머시브 시어터에 간 거야?!","응, NPC 알바하러 왔어.","나 버리고 혼자 알바하러 간 거야?!","참고로 아케치 선배랑 시노미야 씨도 있어.","젠장, 왜 동아리에서 나만 왕따 당하는 느낌이지……","야기 씨, 수고했어요. 오늘 사람이 이렇게나 많이 올 줄은 상상도 못했네요, 하하. 연장 근무를 하긴 했지만 분위기가 너무 좋아서, 저도 즐거웠어요~","선배도 수고했어. 내 역할은 대사가 적어서 괜찮았어.","후후. 오빠는 집에 도착하자마자 쓰러져 버려서, 내가 대신 좋아요 눌렀어.","시노미야 씨 역할…… 확실히 대사가 엄청 많긴 했지.","이머시브 시어터에서 어디선가 본 것 같은 사람이 있더라니, 역시 너였구나!","나도 선배를 봤지만…… 이상하게 내가 맡은 스토리를 하러 온 사람들이 많아서…… 선배를 못 만났네, 아쉬워.","이건 어떤 역할의 의상이야? 딱 네 거 같네.","플로라야. 다음에 내가 맡은 스토리에 와 줄래……? 선배가 얼마나 잘 할지 기대돼.","이치히메 녀석, 할로윈 때 혼천 신사에도 할로윈 분위기를 내야겠다면서 시끄럽게 굴더니만, 이거냐멍?","하핫, 이건 며칠 전에 무녀님이랑 신사로 옮겼던 호박이네. 멍지로 주려고 그런 거였구나.","말하자면 복잡하다멍…… 안 그래도 요 며칠 거리가 너무 시끄러웠는데, 신사에서 수행이라도 한 셈 쳤다멍.","고양이 귀가 달린 무녀에 이어서, 고양이 귀가 달린 호박이라니……","하하, 꼬맹아. 혼천 신사에서는 뭐든지 가능하다는 걸 알거라멍.","그러고 보니, 이 호박에 달린 고양이 귀…… 조각된 게 아니라는 걸 방금 알았다멍……","우와…… 멍멍 씨의 허수아비 코스프레, 진짜 잘 어울려! 리사리사도 뽀요용 위에 앉아서 허수아비 코스프레 할 수 있는데~","뽀요용: 예의는 밥 말아 먹었나?","뽀요용을 얕보지 말라구. 사실 뽀요용은 힘이 엄청 세거든. 하나도 한번 해 볼래?","고맙지만, 난 지금 교실이고 부회장이 바로 밖에 있어서 말이야.","아래에 있는 고양이 얼굴 모양 잭오랜턴은 이치히메를 본뜬 거야?","역시 {0}, 바로 아네. 이치히메 녀석이 이 호박이 자기 대신 혼천 신사를 지킬 거라고 하던데, 이젠 뭐라고 하기도 귀찮다멍.","이 호박 엄청나게 튼튼하네.","흥, 나 때는 말이야, 호박은 고사하고 토마토 위에서도 한 발로 설 수 있었다멍!","내가 안다~ 멍지로는 그때 억수로 민첩하긴 했다. 그땐 그랬제.","오늘 저녁은 마스테마가 가만히 있질 않네…… 아마 동족의 기운을 느낀 거겠지…… \n이런 곳에선 평범한 인간은 진짜와 가짜를 구별할 수 없을 테니까, 섞여 들어가기엔 딱 좋은 시기야……","에에에엣? 그냥 오늘 할로윈 분위기 내려고 그러는 거지? 아니라면 엄청 소름인데!!","미안……","질문: 마스테마는 진짜 귀신과 가짜 귀신을 구별할 수 있습니까?","아마도…… 할 수 있어. 마스테마는 그런 게 특기니까……","그럼, 오늘 밤에 진짜 귀신들이 우리랑 섞여 있을 거라는 거야?","할로윈이니까 그럴 수도…… {0}, 내가 준 부적은 잘 가지고 다니는 거겠지?","아야코는 무슨 코스프레 한 거야?","마녀야…… 헤헤, 내년 할로윈에는 진짜로 멋진 마녀가 되어 있었으면 좋겠어.","코스프레가 아니라 진짜 마녀인 거다, 큐르! \n마녀의 규칙 하나(강조), 마녀를 우습게 보는 인간에겐 따끔한 맛을 보여 줄 것!","이상하네요. 제가 점술사인건 아무도 의심한 사람이 없었는데, 왜 그러는 거죠?","제길…… 시간문제일 뿐인 거다. 인간들에게 네가 하는 감언이설은 언젠간 안 통할 거다, 큐르!","진짜 마녀였다면, 할로윈 축제에 가려고 수업을 빼먹지는 않았겠죠.","할로윈 때문이 아니라구, 큐르……","수업을 빼먹은 건 인정한다는 건가요?","미, 미안, 부회장…… 큐르 ㅠ","유즈가 진짜 마녀인 건 내가 증명할 수 있어. 레서판다즈가 내 핸드폰을 찾아 준 덕분에 이렇게 캣챗을 하고 있는 거야. 우어어어……","그건 레서판다즈라면 마땅히 해야 할 일인 거다. 그래도 위험하니까, 다음부턴 절대 지하철에서 핸드폰을 들고 잠들지 말도록. 큐르르……","여기서 도움을 받을 수 있다고 들었는데요…… 위대한 마녀님께 질문이 있습니다. 제 전 남친의 마음을 돌릴 수 있는 방법이 있을까요?","큐르르? 스승한테 그런 마법 약이 있기는 한데, 유즈는 별로 추천 안 한다는 거다. 어차피 전 남친은…… 헤어질 때 이미 죽었잖아?","주, 죽어? 전 남친이요……?","네 마음속에서 \'사망\'했다는 뜻인 거다. 큐르…… 마녀는 함부로 사람을 죽이지 않아. 무서워할 건 없어~","여기서 정의로운 마녀에게 도움을 받을 수 있다고 들었는데, 맞나요?","중요: 그냥 도움이 아니라, \'정의\'로운 도움인 거다~ 큐르르. 유즈는 모든 사람을 돕지만, 절대로 나쁜 일은 하지 않지! 그건 {0}한테도 예외는 아니야~","유즈가 가진 마녀의 기질은, 복제할 수 없는 유일무이한 것임을 증명합니다!","큐르르~ {0}, 역시 혹독한 대가를 치른 인간답군. 마녀에 대한 기본 상식이 있는 것 같아, 정말 기쁘다는 거다~","할로윈…… 작년에 있었던 일이 떠오르네요. 지하철에서 어떤 사람이 저한테 무슨 코스프레를 한 거냐고 묻더라고요. 전 그냥 평소처럼 책을 읽고 있었을 뿐인데…… 귀신이 되어 버렸네요?","큐르르…… 유즈도 며칠 전에 마녀 코스프레를 했다고 오해받는 일이 있었다는 거다. 진짜와 가짜를 구분 못하게 만드는 할로윈은 어떻게 보면 좀 오싹한 것 같아.","당신…… 그거 코스프레 아니었나요?","큐르?","요즘 같은 시대에 종이책을 읽는다니, 무겁진 않나요?","그건 뭘 모르는 말씀이죠.","지하철에서 책을 보면…… 집중이 잘 안되지 않나요?","내려야 할 역을 지나칠 수도 있긴 해요.","내년엔 아예 코스프레를 하는 건 어때?","……프랑켄슈타인으로 할까요?","할로윈 저녁엔 지하철에 사람들이 미어터질 텐데, 용케 책을 보는구나……","평소에도 그래요.","이머시브 시어터에 다녀온 소감…… 이 아저씨는 지금 밖에 나온 지 30분이나 됐는데, 아직도 머리가 지끈지끈해. 젊은이들의 문화생활은 체력도 좋아야 하고, 이젠 머리까지 써야 되는구만.","역시 평소엔 약한 척한 거였구만. 옷만 갈아입었다고 해서 그런 눈빛이 나오긴 쉽지 않지. 하, 이제 나랑 결판을 내자!","이번 달에만…… 몇 번이나 결판을 냈는지 알아? 이 아저씨 좀 살려 줘……","아저씨는 멍지로랑 같이 간 거야?","아니.","미안미안, 뒤에 있는 게 멍지로인 줄 알았어.","멍?","크크큭, 우매하고 무지한 늑대인간 일족이여. 곧 만월이 도래할 것이다, 너희의 그 추한 모습을 맞이하거라!","시건방진 뱀파이어여, 만월이 도래하는 순간 널 죽여 주도록 하마…… 하하, 이 아저씨는 아직도 대사를 기억한다고.","아직도 연극에서 못 나왔어?","지금까지 늑대인간 플레이어 중에서 제일 잘했잖아~","코스프레 엄청 멋진데!","{0}한테 그렇게 보였다니, 30분 동안 힘들게 입은 보람이 있구만. 하하.","다음에는 츠키미 씨랑 같이 가 보고 싶네.","{0}, 함께해 준다니, 이 아저씨도 최선을 다해 널 보좌해야겠구만. 아, 그런데 다음엔 앉아서도 할 수 있는 테마를 골라도 될까?","하…… 할로윈이라고 멋대로 날 도발하는 인간들한테 되갚아 주지도 못했는데, 이런 끔찍한 날도 드디어 끝났군. 할로윈이란 건 섬에 있는 농민들이 축제를 벌이는 날인 줄 알았는데, 이한시 사람들도 이렇게나 좋아하는 날이었을 줄이야. 시끄러워 죽겠다……","후후. 제가 이곳에 처음 왔을 때도, 익숙한 분위기가 느껴져서 꽤나 놀랐답니다. 이한시는 정말 신기한 곳이에요.","그럴수록 빨리 이한시 사람들도 사냥을 좋아하게 만들어야겠어.","네…… 그런데 이한시에 사냥을 할 만한 곳은 없지 않나요? 동물원에서 사냥을 할 수도 없는 노릇이고……","혼천 신사에서 소원을 빌 수 있지 않았나? 혼천 신사에 가서 방법을 물어보자.","옳지, 옳지. 잭스 씨는 사실 착한 사람이라는 걸 리사리사는 알고 있어. 그렇게 꼬리를 만져대는 {0}한테도 화낸 적 없으니까, 에헤헤~","제길…… 그땐 그냥 방심했을 뿐이야. 받아줄 생각은 없었다고!","잭스 고향에서도 할로윈을 보내?","할로윈을 따로 보내지는 않아. 그건 옆 동네 섬사람들의 관습일 뿐. 귀신들이 날뛰는 모습은 정말 보기 흉하다고…… 하지만 비슷한 시기에 우리 일족 사람들은 큰 축제를 열지. 가을 수확철이니까 말이야. 내가 내년에 구경시켜 줄게.","할로윈이라고 사람들이 몰려와서 꼬리가 훌륭하니 어쩌니, 어디서 샀냐고 물어봤을 생각하니 웃기네.","제길, 뭐가 웃겨! 네가 허구한 날 내 꼬리를 만지작대지만 않았어도, 사람들이 날 만만하게 보지 않았을 거라고!","가을 선물이 겨울 선물이 돼 버렸어요.\n열심히 노력하면, 눈에 띄지 않던 낙엽도 사람들의 주목을 받는 존재가 될 수 있는 거군요.","니노미야가 예술에 소질이 있을 줄이야, 이 정도면 팔아도 될 수준이잖아. 올해 학생회 사무실에 놓을 크리스마스트리는 네가 맡아 줄래?","회장, 학생의 노동력을 너무 당당하게 착취하려고 들지 말아 주세요.","하하, 들켜 버렸네. 하지만 이런 느낌의 크리스마스트리가 더 의미 있을 것 같은데. 음…… 좋아! 그럼 렌한테 트리 만드는 걸 도와주라고 할게!","……회장. 생각해 봤는데, 저 혼자서 만들어도 충분히 완성할 수 있을 것 같아요. 크리스마스 전까진 완성해 둘 테니까 걱정하지 마세요!","저도 작품 완성이 기대되는군요. 부디 힘내시길.","ㅠㅠ","니노미야는 즐거워 보이네. 나도 똑같이 부회장이 낙엽 청소 시켰었는데, 흙먼지랑 땀, 상처만 얻었어…… 흑……","그건 당신이 나무 위에 열린 열매에만 신경써서 그런 거겠죠. 아니면 나무에 오르다가 팔꿈치가 다 까지는 일도 없었을 거라구요.","하지만 꽃이 궁금하지도 않아? 이런 계절에 탐스러운 과일이 열린다니, 식물의 생명력은 진짜 놀랍다고.","식물은 강한 생명력을 지니고 있죠. 내년에 저랑 같이 원예 동아리에서 직접 느껴 보시는 건 어떤가요.","으으으음, 트리 꼭대기에 있는 양털 별이 왠지 엄청 익숙한 느낌이 드는 것 같은데, 설마…… 뽀요옹!","그거까지 알아봤네요. 엘록 홈즈라고 불러야겠어요.","우와, 엄청 잘 만들었네! 만드는 법 좀 가르쳐 주라~","어차피 학생회에 더 큰 걸 만들어 줘야 하니까, 겸사겸사 같이 만들면서 알려드릴게요.","상처 하나 없는 크리스마스트리√, 이게 바로 원예 동아리의 실력인가!","저희 원예 동아리가 실력을 발휘하면 더 대단한 것도 만들 수 있답니다! 그리고 이 낙엽들은 여름 내내 햇빛을 막아 주었는데, 그대로 치워 버리려니 조금 아쉬운 느낌도 들었구요.","용사란 자고로 태어날 때부터 세계를 구할 책임을 떠안고 있지. 굶주림, 혹한, 노동…… 이 모든 고난을 홀로 이겨내며 길모퉁이에서 눈꽃 하나를 주우니, 이것이 올겨울의 유일한 수확이로구나.","하하. 다들, 내가 번역해 줄게. 이번 달 24일은 오빠의 생일이니 축하를 받았으면 좋겠다는 거야. 물론 선물이 있으면 더 좋고 말이야.","크크크, 하늘이 내려준 용사의 기프트를 어찌 단순한 선물로 형용할 수 있단 말이더냐~","그래그래, 하늘이 내려 준 기프트는 집안에 가져다 놨어. 생일날에는 알바 끝나면 바로 집으로 와야 돼. 선물은 엄마랑 같이 골랐어. 엄마는 오빠가 분명 좋아할 거라 했어.","생일 축하드려요!","소박한 축복 속에서, 한 줄기의 무성의함이 드러나는군. 심지어 오늘이 아니라는 걸 알아차리지도 못했어.","하하, 이런 건 그냥 겉치레잖아요? 사실 다들 모여서 서프라이즈 파티를 준비하고 있어요.","서프라이즈? 뭘 준비하고 있는데?","그걸 말하면 서프라이즈가 아니잖아요? 당연히 비밀이죠.","생일 축하해.","아…… 너 말이야, 부장처럼 느낌표라도 써서 축하의 마음을 좀 더 표현하는 보는 건 어때?","!","하하하, 댓글을 보니 많은 사람들이 네 생일을 축하해 주고 있네. 시끌시끌해~","그렇다고 제가 감동했다는 걸 인정하진 않을 거라구요. 참, LULLABY에 와서 한잔하실래요? 오늘은 아저씨가 좋아하는 한정 스페셜도 있다구요.","오늘 저녁은 마작이 땡기긴 하지만, 시노미야가 그렇게까지 말하니 안 갈 수가 없겠구만. 하하핫.","그럼, 나도 미리 생일 축하해 줄게!","고마워, 하지만 미리 축하해 주기보다는, 생일날 만나볼 수 있었으면 좋겠네. 어때, 나랑 같이 크리스마스이브를 보낼래?","크리스마스 준비를 하느라 이렇게 중요한 날을 잊어버리고 있었네. 우리 괴도 선생님께서는 무슨 선물을 좋아하려나?","선물이라…… 내가 직접적으로 얻기 힘든 물건이면 좋겠는데. 예를 들자면…… 누군가의 진심 같은 거 말이야.","리우가 직접 짠 크리스마스 양말을 걸어놨다구. 흐흥흥, 산타 할아버지한테 가득 채울 수 없는 양말도 있다는 걸 알려 주도록 하겠어!","가게에서 파는 크리스마스 양말은 너무 작죠. 치오리 아가씨께서는 세상에서 가장 아름다운 선물을 받을 자격이 있으십니다.","매년 그런 선물만 받는다면 엄~청 재미없을 거야. 차라리 리우의 크리스마스 양말이 더 좋지.","다 못 채울 정도라니…… 대체 얼마나 큰 양말인 거냥?","역시 사진으로는 크기가 잘 와닿지 않는 모양이네. 내 다리 두 개가 전부 들어갈 정도로 커.","내가 본 크리스마스 양말 중에 제일 큰 양말이야. 엄청나게 많은 선물을 받을 수 있겠어.","리우가 만든 양말이니까~ 그리고 올해도 열심히 노력하는 모습을 보니까, 너는 선물 하나 더 고르게 해줘도 될 거 같네.","아 참. 감사하단 인사는 필요 없어, 이미 귀가 닳도록 들었으니까. 할 거라면 좀 더 신선한 대사를 가지고 오도록 해. 흥.","엄청 귀여운 그림이네. 내가 산타였으면 양말을 가져갔을 거야.","치오리랑 양말 중에 양말을 고르겠다는 거야? 서민 주제에 용감한걸. 올해 크리스마스 선물은 없! 어!","흐흥~ 대길을 못 뽑아도 괜찮아! 하루나가 그리면 된다구. 어때? 대단하지?!\n새해엔 다들 대길을 가지고 있어야 해! 그러니까 하루나는 새해가 오기 전에 모두에게 대길을 전부 그려줄 거야!","신사에서 하는 운세 뽑기는, 그저 내년에도 운이 좋기를 바라는 의미에서 하는 것일 뿐이야. 새로운 한 해도 열심히 노력한다면 반드시 좋은 결과를 얻을 수 있을 거야.","그럼 하루나가 만든 대길도 분명 좋은 운이 깃들어 있겠네! 그렇지?","이론상으론 그렇네.","대길…… 마스테마에게 있어서 길일까 흉일까……","마스테마도…… 분명 기뻐할 거야! 선물을 받았으니까 당연히 기뻐하겠지?","마스테마가 일어나면 물어봐야겠어. 그리고…… 나도 선물을 받아서 기뻐.","신사의 존엄성이 엄청나게 시험을 받고 있는 듯한 느낌이다멍.","혼천 신사가 너무 쩨쩨해서 그런 거야. 엄마는 혼천 신사가 모두에게 행복을 가져다주는 곳이라고 말했는데, 그럼 죽통 안이 전부 대길로 가득 차 있어야 하는 거 아냐? 대흉도 있다니, 너무한 거 아니냐구?!","하루나, 붓글씨 솜씨가 훌륭하네.","그치, 그치? 대길 두 글자만큼은 하루 종일 연습했다구!","어젯밤엔 꿈에서까지 연습했지. 근데 금방 까먹을까 봐 무서워.","나도 대길 가지고 싶어!","{0}, 이 한 장은 널 위해서 준비한 거야! 감동했어? 헤헤, 들고양이 군단도 {0} 위치를 찾고 있다고. 그럼 하루나의 대길, 발사 준비합니다!","오래간만의 휴일이라서, 선배랑 같이 온천에 왔답니다. 헤헤~\n유카타를 입은 선배는 너무 이쁘지만, 이 모습은 저 혼자서만 간직하도록 할게요! 절대로 다른 사람한텐 보여 주지 않을 거예요!","사실 이번 온천 여행에서 카나 사진을 많이 찍었는데, 이걸 다른 사람한테 보여줄까~ 말까? 내 다리에 누워 침을 흘리면서 자고 있는 사진은 어때?","안 돼요…… 평소 이미지에 엄청 신경 쓰고 있단 말이에요. 오래간만에 선배랑 같이 놀러 나와서…… 조금 들떴나 봐요. 그 사진은 절대로 올리시면 안 돼요! ㅠㅠㅠ","역시 옛날처럼 잘 속는구나. 농담이었어, 후후.","선배 최고!","내가 일찍 온 건가? 첫 번째 댓글은 카나네 팬클럽 사람이 썼을 줄 알았는데?","개인적인 메시지는 카나가 가장 소중하게 여기는 사람들만 볼 수 있다구~","하하, 선배가 널 괜히 챙겨 주는 게 아닌 모양이네. 근데 사장님 댓글은 안 보는 것 같아서 정말 아쉽구만~ Anyway, 사장님을 차단하는 건 회사에 착취 당하는 직원이라면 당연히 해야 할 일이긴 하지만.","일리 있군.","온천이라, 나도 가고 싶네.","선배님이 추천해 준 숨겨진 온천이야. {0}, 너라면 카나가 위치 공유해 줄 수도 있으니까, 꼭 봐야 해.","아 참, 매니저한테 새해 라이브 콘서트 티켓을 보내라고 했어. 카나의 새해 콘서트니까 늦으면 안 돼! 그 자리, 카나의 윙크를 받을 수 있는 자리니까 말이야.","새해 복 많이 받아!\n지난 한 해 동안 나와 함께해 준 딸랑이들을 위해서, 캣챗 추첨 이벤트를 열기로 했어. 자, 규칙을 공지할게.\n추첨 규칙:\n히메카와 히비키의 채널을 팔로우한 뒤 이 메세지를 리트윗+새해 소원을 적어 주면 참가 완료고, 방송에서 그중 행운의 딸랑이 스무 명을 뽑을 거야. 방송에서는 새해 소원이 이루어질 수 있게 도와주고, 세뱃돈이랑 같이 히메카와 히비키의 사인이 적힌 사진을 보내 줄게!\n이벤트 기간:\n2022년 12월 31일 23:59까지","이번 이벤트는 히메카와 히비키 팬클럽에서 선정된 대표들이 전 과정을 감시 및 감독할 예정입니다. 형평성과 개인정보가 보장되오니, 딸랑이들은 안심하고 참가해 주세요!","전남친이 10년 동안 솔로였으면 좋겠어요! 그리고 히비키의 사인 세트 가지고 싶어요!","전여친이 20년 동안 솔로였으면 좋겠어요! 그리고 히비키의 사인 세트 가지고 싶어요!","전여친이 30년 동안 솔로였으면 좋겠어요! 그리고 히비키의 사인 세트 가지고 싶어요!","전여친이 평생 솔로였으면 좋겠어요! 그리고 히비키의 사인 세트 가지고 싶어요!","난…… 잠만, 아니 왜 전부 애인이 있었던 거야? 제길, 그럼 난 지금 커플인 녀석들 전부 배드 엔딩을 맞이했으면 좋겠어! 그리고 저도 히비키의 사인 세트 가지고 싶어요!","와, 여기서 니가 제일 독한 듯. 내가 졌다.","오늘은 안 좋은 일들이 생겨서 하루 종일 우울했었어요. 히비키의 캣챗만이 유일하게 좋은 소식이네요…… 제가 당첨될지는 모르겠지만, 충분히 행복해졌어요.","이제 두 번째 좋은 소식이 생겼네.","우와아…… 정말로…… 저 죽을 것 같아요……","이상한 소원이 섞이지 않게 팬클럽에서 잘 정리해 줬으면 좋겠어요. 히비키는 분명히 이번 이벤트를 여느라 돈을 엄청 썼겠죠…… 생각하면 할수록 걱정되네요. 오늘 저녁엔 더 많이 후원해 드려야겠어요!","내 새해 소원은…… 라이브로 귀여운 모습을 보는 거야!","왠지 전에 했던 얘기 같은데…… 만약 진짜로 네가 뽑히면 해 줄게.","나도 손! 나도 보고 싶어!","내 최애 방송인 두 명이 같이 얘기하고 있다니! 눈나 나 죽어!!","진짜 어떤 소원이든 다 들어 주는 거야? 그럼 사양 안 할게. 음흉한 미소.jpg","불법이거나, 패작 빼고 전부 OK야.","하하, 역시! 히비키한테 화료보다 중요한 건 없지~","이 사람도 확실히 빡겜충인듯!","세상 하나뿐인 카나","일번 추종자","카나 쫓아 삼만리","질투는 날 바꿔","자나 깨나 카나 사랑","히메카와 히비키 후원회","히메카와 히비키 천하제일","힐리","쿠츠지","다 같이 큰 소리로 외쳐 주세요: 돌아온 Éternité 여름 할인 이벤트 시작~! 한! 층! 더! 업그레이드된 여름 특별 음료! 유니폼 준비 완료! 세 명의 새로운 미소녀 직원 대기 중! 이래도 안 올 거야???","후, 정말로 이 카피를 사용했네요.","그야 이 카피가 귀여우니까요. catchat에 무슨 말을 쓸지 몰라서 그런 건 절대아니라구요(?).","공유가 많이 되고 있는 걸로 봐선, 효과가 아주 좋네요. 한 수 배워갑니다……","니노미야 씨가 도우러 와 주셔서 정말 기뻐요, 이번 여름 잘 부탁드려요.","그래! 청춘의 에너지가 넘치는 종업원들(물론 나도 포함)이랑 같이 아름다운 여름을 맞이하자!","난 벌써 이벤트에 참여할 준비가 돼 있다고!","어머머, {name} 씨의 사심이 여기까지 느껴지네. 전 종업원, 철벽 방어 준비 완료! 헤헤","무슨 말인진 알겠다만, 근데 그 대단히 자유로워 보이는 문구들은 뭐야……?","앗, {name} 씨한테 들켜 버렸네. 헤헤, 이건 새로 합류한 종업원들이 친필로 쓴 문구랍니다~ 여름이니만큼, 다들 홍보 문구에 활기가 느껴졌으면 좋겠다고 해서 말이야.","이 홍보 문구, {name} 씨가 보기엔 어때?","오픈 첫날 영업은 대.성.공! 흐트러진 머리랑 손에 들린 청소 도구는 무시하고, 이 코스튬만 보면 그래도 90점 정도는 되지 않을까?","나나 씨의 아름다움은 90점 정도로는 모자라죠! 점장으로서 100점 드릴게요!","카메라를 향해 자신 있게 브이를 날리시다니…… 너무 눈부셔서 괜히 제가 다 부끄럽네요……","뭐가 부끄럽다고~ 오히려 하나야말로 너무 굳어 있달까.","스마일! 좋았어, 내일은 널 모델로 눈부시게 아름다운 사진을 찍어 주겠어!","점장님… 저 내일은 쉴게요. 톡 보고 계시죠?","소매가 너무 넓어서 불편하진 않나요? 수선이 필요하면 언제든 저한테 말해 주세요.","헤에~ 고마워! 그래도 아직은 괜찮을 것 같아!","상태가 너무 멀쩡해서 막 출근하고 찍은 사진인 줄 알았네, 어떻게 이럴 수 있지!?","흐흥, 이런 게 바로 타고난 거 아닐까나! 후배 군, 내가 부러워? 그럼 내일부터 나랑 같이 연습하자구. 금방 나처럼 될 수 있을 거야!","보통 이벤트 첫날이 가장 바쁘지, 수고했어.","음~ 그래도 생각보다는 괜찮았어. 그치만 후배 군이 그렇게까지 얘기하니까 찬스를 좀 써야겠는걸. 그럼 내일은 후배 군이 우리 사진을 찍어 주는 걸로 하자, 모처럼 다들 예쁜 유니폼을 입었으니까 말이야!","일할 때: 내가 생각한 내 모습 VS 실제 내 모습.\n더 노력해야겠네요……","그래도 오늘은 정말 잘했는걸! 원예부 사람이 이렇게나 체력이 좋을 줄은 몰랐어, 다시 봤다니까.","음, 오늘 스페셜 오더가 엄청 많았어요. 저도 쓰러질 뻔.","손님분들께 들은 얘기론, 온라인에서 보고 주문하러 온 사람이 많았던 모양이에요. 으음…… 내일은 재료를 더 많이 준비해 둬야겠네요.","자기 사진을 이렇게나 클로즈업시키다니, 장난 아닌걸. 아, 그게 아니라 고화질로 보고 싶다고.","원본 사진은 치마가 너무 헝클어져 있어서…… 한번 생각해 볼게요…… 아, 쉬는 시간이 끝났네. 일단 손님부터 받고 다시 얘기해요.","하하, 그래도 이 코스튬 정말 잘 어울리는걸, 예쁘네.","역시 이 코스튬은 {name} 씨도 인정하시는군요, 오늘 유독 저를 바라보는 시선이 많았던 이유도 설명됐습니다. {name} 씨의 안목은 믿을 수 있으니까요.","빛의 뒤에 숨어있는 어둠이여, 이몸이 그대가 즉시 나의 운명의 의복으로 변할 것을 명한다. 치명적인 힘의 해방이 필요 없는 평일의 오후에도 영원한 고독 속에서 세계의 질서를 지켜야 하는 법.","?","전체 답변: 어떤 중2병 걸린 고양이가 쓰고 갔어요. 못 본 걸로 해 주시길…~!","……컨셉이 확실한 고양이네.","원래는 두 얼굴을 가진 고양이야.","진짜야? 못 믿겠는데.","움…후유미가 어떻게 해야 믿어줄꺼야, {name}?","끝없는 인간세계의 굴레 속에서, 동생과 나는 결국 다른 길을 택했다. 제군들의 선택은 어떠한가?","시노미야 씨가 어제 협찬해 주신 칵테일향 특제 콜드브루, 인기가 대단했어요. 시간 있으시면 언제든 놀러 오세요.","다들 좋아했다니 다행이네. 맞다, 전부 무알콜 음료니까 학생들도 마음껏 즐겨 주시길.","시노미야 씨가 어디 갔나 했더니, Éternité에 있었구나. 그건 저번에 벌써 업그레이드해 뒀으니까, 이번엔 분명 만족할 수 있을 거야!","……고맙군, 수고 많았어. 지금부터는 내 매니저와 연락하도록 해.","???","매니저가 어디 있어?","@{name}","아? 오빠, 오늘 가게에 왔었구나.","오후에 와 봤는데 네가 바빠 보이길래 안 불렀지. 일이 좀 있어서 먼저 나왔는데, 너 퇴근할 때 다시 데리러 갈게.","낮에는 커피, 밤에는 술. 어린애들한테는 선택지가 하나 뿐이겠군.","{name}, 너한테 이런 모습이 있을 줄은 몰랐는걸? 오늘 밤은 특별한 맛으로 네 선택을 받아내야겠어.","글쓴이를 생각해서…… 이 문제, 난 2번을 선택할게.","대답이 뭔가 찜찜한데? 그래도 걱정하지 말라고, 진정한 남자는 이럴 때 바보인 척 모른 체 해 준 다음, 선택받는 기쁨을 만끽하는 법이지.","누가 내 잠을 훔쳐가기라고 한건가~? 아, 낮에 꽃꽂이 연습하면서 잠을 쫓으려고 커피를 여러 잔 마셔서 그런가 보다.","어머, 벌써 시간이 이렇게 됐네…… 나나 씨, 내일은 늦어도 괜찮으니까 조금 더 자고 와요. 급여는 안 깎을게요.","땡큐 사장님!!! 근데 정말 걱정 안 해도 돼, 난 괜찮으니까!","인간이 버틸 수 있는 카페인 양에는 한계가 있다고. 다음엔 절대 그러지 말고, 차라리 따뜻한 우유라도 마셔.","집에 따뜻한 우유가 없는데, 혹시 요거트도 괜찮지 않을까. 근데 후배 군은 왜 안 자고 있어?","후배 군? 저기요?","설마 대답도 안 하고 잠든 건가! 쳇…… 조용한 밤은 고독하구나.","잠이 안 오면, 기분 전환을 해 보는 건 어떨까? 예를 들면, 남풍국 한 판?","후배 군, 그거 진짜로 기분 전환되는 거 맞아?","선포합니다! 카나는 지금부터 이 스페셜 오디 커피의 비공식 홍보 모델이 되겠어요!","우오오오오오오오 어디 커피숍이냐! 내가 간다 우리 딸래미!!!","catchat에 문제가 있나…… 시력 보호 모드를 켜 놨는데, 카나가 여전히 빛나고 있잖아!","지금 100평짜리 침대에 누워 있는데, 방문 밖에 500명쯤 되는 잘생긴 남자 집사들이 \"주인님, 주인님의 최애이신 카나님이 catchat을 올렸어요! 역시 카나님은 오늘도 굉장히 아름답군요, 분명 주인님을 미치게 만들 거예요!\"라고 외치고 있어.","@나나미 레이나 스페셜 오디 주문이 폭발한 원인 발견.","찾았다, 스페셜 오디를 못 사먹게 만든 \"원흉\"!","그건 {name} 씨가 늦게 와서 그런 거지, 이렇게 맛있는 음료를 마시려면 줄을 서야 하는 게 상식이라구!","여러분들 여기에요! 또 그 사람이 나타났어요! 매번 카나의 댓글에 나타나서 주목받는 신비한 인물!","여기 줄 서면 카나님의 눈길을 받을 수 있는 건가욥ㅇ_ㅇ","당연하죠!","헐헐헐헐 뭐라고 해야 할지 모르겠다. 으아아아아 아무튼 가문의 영광!!!","카나, 오늘도 Éternité에 간 거야? 못 봐서 아쉽네.","만약 그랬으면 스페셜 오디 커피의 비공식 홍보 모델이 한 명 추가됐을걸? {name} 씨도 무조건, 꼭 먹어 봐!","#내 Éternité커피를 가져다준 사람의 정체는?# ……이런 식으로 실시간 검색에 오르다니, 이상하네요.","실시간 검색 순위를 보고 찾아오는 사람들이 또 늘어난 모양이네요.","어떻게 보면 좋은 일…이겠죠.","이번에 글을 쓴 친구들은 기억력이 너무 나쁜데? 마작이었으면 엄청 손해 봤을 거야!","그러고 보니 요즘엔 정말 시간이 없었네요, 오늘 끝나고 체력이 남으면 같이 마작 한판 해요.","혹시 고급 인술을 사용해서 모습을 감춘 것인가!","죄송합니다만, 아마 아닐 거예요.","음…… 아마 너랑 마작을 안 해봐서 그런 거 아닐까?","그럼 끝나고 같이 마작하실래요? 아무래도 인지도를 높이기 위해서 더 노력해야겠어요.","#내 Éternité커피를 가져다준 사람의 정체는? 이걸 질문이라고 하는 건가? 당연히 세계 최고의 귀염둥이, 니노미야 하나지!","일이 흘러가는 게 뭔가…… 어쩌면 제 기대가 커지는 거일지도 모르겠네요. 아무래도 저에 대한 당신의 관심이 커져서, 도시괴담 비슷한 게 되어 버린 느낌이에요.","말이야 그렇게 하지만, 뭔가 좀 잘못된 것 같다……?","\"어이, 나이도 어리면서 벌써 자는 거야?\"","변신 냥이! 빨리 변신해 봐! 왜 변신 안 하는 거야!","하하, 진정하시고, 고양이한테 좀 잘해 줘요!","저녁에 가게 일 마무리하고 마작만 할 수 있었으면 좋겠네요.","그건…… 아하하, 당분간은 무리일 것 같네요.","귀엽다, 가게에서 키우는 고양이야?","레이나 씨 말로는 근처에 자주 출몰하는 두목 고양이라고 하던데, 기분에 따라 집사를 고르는 거 같아. 요새는 계속 이 가게에 머물고 있네. {name}, 한번 쓰다듬어 볼래?","나도 후유미랑 점심에 같이 벤치에서 햇빛 쐬고 싶어.","나도야, 점심시간이 길면 더 좋을 텐데. 그럼 케이크도 같이 나눠 먹을 수 있잖아.","사진부터 보고 말씀하시길.","오늘 마작도 물 건너갔네요.","원망이 느껴지는걸…… 걱정마! 얼른 다녀올게, 조금만 기다려 줘!","벌써 주문이 이렇게나 많이?","후훗, 우리가 있는데 이 정도는 당연한 거 아냐?","엄청나다냥! 이 손님은 이치히메와 완전히 똑같은 걸 주문했다냥!","꼬마 고양이! 너 혹시…… 설마……","놀랄 뻔했는데 누군가의 댓글을 보고 괜찮아졌어.","역시 주인님.","올해 이벤트 업무량이 장난 아닌 것 같네.","점장이 작년에 후배 군이 도와줬을 땐 훨씬 나았다고 하던데, 그러니까, 저기, 가능하다면 말이지만, 혹시……","마시고 싶은 음료가 있는데 이건 두잔 사면 한 잔은 반값이래요. 선생님이 하는 말 무슨 뜻인지 이해했나요? @{name}","괜찮아 보이네.","하지만 며칠 안 남았는걸, 여행에선 언제 돌아오는 거야?","이해했습니다!","그럼 꼭 나와야 해!","이해했다고 말하고 싶지만, 마작관에 발이 묶여서요. 이번 판은 꽤 늘어지네요……","세상에, 이 선생님이 {name}의 마음속에서 마작한테 져 버리다니……","누님 한정 스페셜! 이러면, 누님이 작은 토끼 라이언을 한 모금 한 모금 마실 수 있을 거예요!","생각보다 괜찮네. 이렇게 된 거, 다음에 공연 보러 온 관객들한테도 해 주면 어떨까?","안 돼요, 라떼 아트는 특별한 마술이랑 같은 거라구요. 누님한테만 해줄 거에요.","이렇게 귀여운 토끼를 어떻게 마셔.","토끼 왈: \"정말로 누님의 음료가 되고 싶어요! 그러니 저를 마음껏 마셔 주세요! 왜냐면 대 마술사 라이언이 앞으로도 누님이 좋아하는 토끼를 엄청 많이 만들어 낼 거니까요.\"","이 라떼를 마시고 나니까, 라이언의 마술이 보고 싶어졌어.","아아, 탐욕에 찌든 어른이여. 하지만 누님의 모든 탐욕은 결국 또 하나의 애정 표현에 지나지 않죠. 그래서, 라이언이 누님을 위해 깜짝 마술을 준비했어요. 카운트 다운 10분!","다 됐습니다! 누님, 이제 문을 열고 귀여운 토끼 라이언을 맞이해주세요.","어떤 직원이 관두는 바람에 일이 너무 많아졌어.\n에구…… 너무 바빠서 털이 다 빠질 정도야…… 이렇게 된 이상, 일단 열심히 해 보는 수밖에!","꺄아아아 복슬복슬 보호 협회는 여러분께 복슬이들을 아껴 줄 것을 선언합니다. 에인의 털이 빠지다니, 리사리사는 받아들일 수 없다구욧!","……난 또 무슨 좋은 사냥터라도 발견했다는 건 줄 알았네, 살기 위해서 그런 일까지 할 정도로 추락해 버린 거냐! 터, 털이 빠질 정도라니……","이게 바로 어른의 세계 아니겠나, 직장이란 곧 잔혹한 사냥터와 같다.","어이! 갑자기 그런 말 하지 말라고, 토 나오니까.","으아아~ 얼른 꼬리 보여 줘, 잘 달려 있지?","응?? 그것보다 먼저 내 건강과 마음을 걱정해 줘야 하는 거 아냐?","열심히 하고 있는 모습을 보니 마음이 놓이네. 그러니까, 그때 가면 메이드 복장이랑 거기에 맞는 말투까지 다 준비되어 있을 거란 말이지?","@잭스","그런 걸 어떻게 입어! 죽을래?!","좀 진정해 봐, 이건 {name}의 댓글이라고. 너 때문에 놀랐잖아.","내가 잭스한테 줬던 선물은 버려진 건가?","그, 그거랑 이건 다르지! 너희 둘 다 시끄러우니까, 이제 아무 말도 하지마!","모처럼 자주 가던 단골 카페에 커피를 사러 갔는데 마침 이벤트 중이라 줄이 엄청 길었다. 보자마자 이거 렉 걸린 거 아니냐는 말이 저절로 나왔음……","오오오 히비키님께서 외출하셨다니! 딸랑이들도 즉시 환복하고 히비키님을 영접하러 가겠습니다!","나한테는 히비키의 방송이 카페인 그 자체!","어디가 잘못된 건지 모르겠네.","우리 같은 이모티콘 쓰는듯.","방금 널 본 것 같은데, 가게 쪽 내리막길?","이거 지금 나까지 끌어들이려고 하는 거 맞지?!","그저 그렇네. 작년에 리우가 만들어 준 핸드드립에 비하면 많이 뒤떨어지긴 하지만, 이벤트가 이틀밖에 안 남았으니까 굳이 따지지는 않겠어.","바로 바꿔 드릴까요?","괜찮아, 우린 지금 손님으로 왔으니까 핸드폰은 내려놓자.","아까 보니까, 올해는 종업원들끼리 모여서 기념사진도 찍고 그러던데, 갑자기 작년에 우리 사진을 많이 못 찍은 게 아쉬워지는걸.","그냥 일일 뿐이니까 아쉬울 건 없지만…… 혹시 원한다면, 지금 치오리를 만나러 커피숍까지 오는 것도 안 될 건 없다…랄까나?","올해 유니폼은 정말 귀엽네요.","모모가 이 유니폼을 입은 모습을 상상해 보니, 엄청 귀여울 것 같아. 혹시 내년에도 가게에서 같이 일해 보는 건 어떨까나?","나한텐 치오리가 작년에 술 게임을 열심히 연습하던 사진이 있지.","아악! 내 흑역사! 지금, 당장, 바로, 삭제해!","저…… 저희 한번 깊은 얘기를 나눠 보죠.","그치만, 작년에 치오리도 굉장히 아쉬워했던 게 기억나는걸.","그럴 리가. 분명 한 살 더 늙은 {name}의 기억력이 퇴화한 거겠지!","후다닥 일어나서 옷을 다 갈아입고 나서야 오늘 출근하지 않아도 된다는 사실이 생각났어. 나만 이런 거 아니지? 아니라고 해줘…!","ㄹㅈㄷ ㅋㅋ","ㄹㅈㄷ ㅋㅋ","ㄹㅈㄷ ㅋㅋ","ㄹㅈㄷ ㅋㅋ","이런, 나까지 너희들한테 물들어 버렸잖아!","고생했네, 얼른 다시 자러 가.","이미 잠 다 깼어. 후배 군, 지금 어디야? 같이 놀자.","머머리아닙니다","푸른옷깃","쿠키","무덤파기장인","킹콩은콩이아니야","아이스레몬","유치원갱스터","콜라조아","나홀로남풍국","자유를위해","끝까지버텨","미치히토","이한 연예 잡지","새턴","레아","미야","아카네","[tag]#뒹굴뒹굴 파자마 파티 #[/tag]와! 이벤트 참가자 추첨에다가, 베개 싸움까지 한다니! 신비한 별똥별 님, 제발 하루나가 당첨되게 해 주세요! 그걸 위해서라면 하루나는 별님께 오늘 먹을 아이스크림을 다 바칠 수도 있어요!","저 별 모양 펜던트…… 왠지 익숙해.","이건 예전에 하루나가 잔 아저씨한테 아이스크림을 나눠줬을 때, 아저씨가 보답으로 하루나한테 저 펜던트를 준 건데…… 잠깐, 혹시 잔 아저씨가 모두에게 저 펜던트를 준 건 아니겠지?!","별똥별 따위에 소원을 빌 바엔, 혼천 신사에 소원을 비는 게 훨씬 효과가 좋을 거다냥!","그…… 소원이 이뤄진다는 게 반드시 좋기만 한 건 아니더라고.","뭔가 있나 보네, 썰 좀 풀어 줘.","뭔가 있나 보네, 썰 좀 풀어 줘.","썰이라기 보다는 쓰라린 교훈이었지…… 다들 올해 고교 연합 예선 시작된 거 알지? 며칠 전에 옆 도시의 \"무패신화 드림팀\"이랑 우리 옆 학교랑 시합을 했는데, 무패신화 드림팀의 리더가 시합 전날에 혼천 신사에 가서 소원을 하나 빌었대. 그리고는 다음 날 바로 졌다지?","옆 학교 팀이라면 올해의 다크호스라고 소문이 자자했던 팀인데…… 대체 어떤 소원을 빌었길래?","\"내일 있을 경기에서 한 번도 해 보지 못한 경험을 하고 싶다.\"","……전형적인 승자의 대사였네. 그래도 그 팀이 진 게, 꼭 소원을 빌었기 때문만은 아니지 않을까?","그건 모를 일이지, 어쨌든 이 일 때문에 나는 요즘 팀원들이 혼천 신사에 못 가게 막고 있어.","그럼 난 하루나의 잠옷 입은 모습을 직접 보고 싶다고 소원을 빌 거야, 분명 엄청 귀여울 거야!","흥, 그럼 하루나도 {name}의 잠옷 입은 모습을 보게 해 달라고 빌 거지롱, 그럼 같이 베개 싸움이다!","그보다도, 이제 와서 소원 빌기엔 좀 늦은 거 아냐? 어차피 이벤트 당첨자는 벌써 나왔을 텐데?!","와아아앗, 당첨자 공지가…… 진짜네! 하루나가 이렇게 중요한 걸 빠뜨리다니!!! 우우, 하루나는 정말로 베개 싸움이 하고 싶단 말야! {name}, 하루나랑 같이 베개 싸움 해 주면 안돼?","[tag]#뒹굴뒹굴 파자마 파티 #[/tag]불면증 타파 뒹굴뒹굴 파자마 파티 스타트!\n얼마 전 발표된 <이한시 수면 연구 보고서>에 따르면 이한시 인구의 21%에 달하는 시민들이 크고 작은 불면증을 겪고 있다고 합니다. 따라서 낮에 마작에 제대로 집중하지 못하여 이에 대한 보상 심리로 늦은 밤까지 반장전 서입 대국을 벌이는 현상 또한 심해지고 있으며, 이러한 악순환의 고리는 시민들의 신체적, 정신적 건강에 심각한 악영향을 미친다고 합니다. 따라서 샘 그룹에서는 이한시 주민들의 한층 편안한 생활 분위기 형성을 위해 \'뒹굴뒹굴 파자마 파티\'이벤트를 주최하기로 결정했으며, 현재 캣챗 뽑기로 당첨된 20명의 참여자를 발표했다고 합니다. 해당 이벤트에서는 잠자리 낭독회, 베개 싸움 등의 프로그램으로 시민들의 스트레스를 낮춰, \'수면 즐기기\'를 장려할 계획입니다. 또한 이벤트를 통해 시민들의 교류의 장을 마련하여 마음이 맞는 마작 친구를 사귈 수도 있어, 단언컨대 최근 이한시에서 진행된 이벤트 중 가장 가치 있는 이벤트라고 할 수 있습니다. 본 잡지사는 해당 이벤트를 지속적으로 보도할 예정이니, 꼭 [tag]@이한 연예 잡지[/tag]를 구독해 주세요!","아무래도 제목 짓는 건 더 연습할 필요가 있겠어.","아직도 모니터링 중이야? 이런 일 중독자 같으니ㅋㅋ! 방금 나데시코한테 저녁에 같이 LULLABY에서 술 마시면서 3인전 몇 판 하자고 연락왔는데, 너 시간 괜찮아?","오늘은 힘들 것 같은데, 내일 가자.","편집장님, 저……휴가 좀 쓰게 해 주세요……ㅠ_ㅠ","?","아, 아닙니다. 편집장님 전 아무 말도 하지 않았습니다.","한밤중에 남풍국을 한다니 보통 일이 아닌데, 아무래도 불면증 문제가 심각하긴 한가봐요.","아마 날씨가 너무 더운 것도 한몫하는 것 같아요. 요즘 식물들도 맥을 못 추고 있다니까요.","<충격! 보기만 해도 공중제비를 돌게 하는 파자마 파티 명장면 10선!>","훌륭한 제목인걸? 너한테 딱 맞는 직책을 생각해 놨으니까, 내일 보도국에 한번 들르라고. 후훗, 이런 게 진짜 재능이지! 후배 군도 이런 재능이 탐나지 않아? 내일부터 나랑 같이 훈련하면 너도 금방 이런 재능을 가질 수 있을 거야!","내 직감이 이번 파자마 파티에서 엄청난 뉴스거리가 나올 것 같다고 말해 주고 있어.","네가 가는 곳마다 큰 사건이 터지던데, 대체 왜 그런 건지 한번 진지하게 생각해 본 적 없어?","[tag]#뒹굴뒹굴 파자마 파티 #[/tag]이벤트 시작까지 이틀 남은 시점, 같은 전업주부 친구한테 듣기론 결정 장애가 올 때 캣챗 친구들한테 대신 선택해 달라고 부탁하면 좋다고 하더라고요. 지금 한번 시험해 볼까요? \'뒹굴뒹굴 파자마 파티\'에 갈 때는 어떤 옷을 가져가면 좋을까요?","빨간색은 재물운을 불러온다고 하고, 보라색은 건강운을 좋게 한대.","어머, 카비 언니 좋은 정보 고마워요. 두 선택지 다 마음에 들어서 더 결정하기 힘들어졌어요.","두 색깔 모두 키타미 씨한테 엄청 잘 어울리는데…… 마이는 결정을 못 하겠어요. 죄송해요……","나한테 좋은 생각이 있어. 투표를 만들어서 어떤 옷이 좋을지 정하자!","어머, 그럼 투표는 제 마음속에서 백만 표 이상의 영향력을 행사하고 있는 {name} 씨한테 맡길게요.","그래서…… 이렇게 인터넷 친구한테 도움을 요청하는 방법이 효과는 있었어?","어머, 제 생각엔 아주 효과적이었던 것 같아요. {name} 씨도 이렇게 흥미를 느끼고 도와주러 왔으니까요.","[tag]#뒹굴뒹굴 파자마 파티 #[/tag]갈수록 풍성해지는 이벤트, 그리고 점점 목적을 달성해가는 악당들! 정의의 마녀로서 이런 자리엔 절! 대! 빠질 수 없지!\n그치만…… 아직 레서판다즈 잠옷을 못 구했는데, 큐르르…… 레서판다즈를 유즈의 잠옷 치마 속에 숨겨서 가면 안 들키지 않을까?","음 음, 리사리사도 이한시에 있는 가게들엔 뽀요용한테 어울리는 스타일이 없어서 무지무지 곤란한 참인데…… 아예 직접 만들어 버릴까?","큐르, 그럼…… 한번 직접 만들어 보자.","한 번에 닌자 반려 동물을 셋이나 다룰 수 있으시다니, 소생께도 유즈 공의 비결을 전수해 주실 수 있으신지요?","닌, 닌자 반려 동물? 큐르르…… 또 무슨 이상한 설정을, 친해지려는 진심만 있어도 레서판다즈랑 소통할 순 있을걸?","우와아아아! 나도 파자마 파티에 당첨됐어! 레서판다즈도 꼭 \'잠입\'시켜서 데려와 줘, 꼭 한번 쓰담쓰담해 보고 싶단 말이야!","레서판다즈를 가까이서 볼 수 있다니……후하후하 당장! 당장 데려와! 당자아앙!!!","큐르, 레, 레서판다즈에게 위협이 되는 행동은 하지 말아 주세요!","만화 속 마녀들은 항상 길쭉하고 볼륨 있는 모습을 하고 있던 것 같던데, 솔직히 말하면…… 유즈 씨는 마녀보다는 이한시의 신출귀몰한 점술가 쪽이 더 어울릴 것 같네.","닉값 잘 하시네요.","이렇게 또 한 사람이 가는구나.","뭐라고 댓글을 달아야 할지… 멀리 안나갑니다…","마녀의 법칙 제25조: 악행을 저지르지 않은 시민에게는 손을 쓰지 않는다. 큐르르…… 너, 유즈가 지켜볼 거야, 나쁜 짓 하다가 유즈한테 걸리기만 해!","유즈, 혹시 네 치마 안에 나도 숨겨줄 수 있어?","큐르르…… {name}, 유즈의 치마를 대체 뭐라고 생각하는 거야? 그런 무시무시한 상상력은 정말 위험해, 사악한 기운이 자라나는 자양분이 될 수 있다구!","저기, 은신 마법을 쓰면 손쉽게 레서판다즈를 \'잠입\' 시킬 수 있는 거 아냐?","마녀의 법칙 제25조: 마녀는 마법을 사용해 위법 행위를 저질러서는 안 된다.","위에 댓글 보니까 25조는 분명 \"악행을 저지르지 않은 시민에게는 손을 쓰지 않는다.\" 였을 텐데.","큐, 큐르! 그, 그건 26조였어!","[tag]#뒹굴뒹굴 파자마 파티#[/tag]진짜 당첨될 줄 몰랐음, 요즘 Éternité도 한가한 편이니까 레이나도 가 볼 생각이에요. 음…… 이번에 복슬복슬한 곰인형 하나를 새로 들여놨는데, 이 곰인형이 제게 같이 베개 싸움에 참가할 멋진 팀원을 데려다주지 않을까요? 레이나도 열심히 해서, 다른 사람의 걸림돌이 되지는 않을 거예요.","카페는 저한테 맡겨 두시고, 점장님은 맘 편히 \'참전\'하고 오세요.","그럼 카페는 히나타 언니한테 맡길게요. 음, 요샌 삼촌이 카페에 상주하고 계시니까, 무슨 일 있으면 삼촌을 불러서 해결하시면 될 거예요.","똑똑, 혹시 Éternité의 점장님이신가요? 한 가지 여쭤보고 싶은 게 있는데, 전에 그 가게에서 일했던 은발에 까무잡잡한 피부를 가진 잘생긴 분은 어디로 가셨나요?","A 씨를 말씀하시는 걸까요? 죄송해요, 저도 그분의 행방을 잘 몰라서 대답해 드릴 수가 없네요. A 씨가 가게에 빨리 돌아와 주시면 좋을 텐데, 그분은 Éternité의 유일한 7성급 직원이거든요.","티, 팀? 베개 싸움이 팀전이었어?","치오리 씨의 팀원이라면 당연히…… 아니지, 꼭 저랑 팀 하죠.","아하하…… 우리 치오리는 베개 싸움 이벤트 참전 규정을 제대로 이해하지 못했나 보네.","그, 그런 건 평소엔 리우가 읽어 주기도 하고, 또 리우가 없더라도 {name}(이)가 읽어 주니까 치오리가 모르는 게 당연한 거 아냐? 저, 절대 독해력 문제가 아니야.","아무래도 치오리를 팀원으로 삼겠다는 꿈은 물거품이 되어 버린 것 같네.","난 레이나가 Éternité의 점장으로서 절대 걸림돌이 되지 않을 거라 믿고 있어.","아무렴, {name}의 기대를 저버리지 않기 위해서라도 더욱 분발해야지.","그리고 앞에 댓글 다신 분께서 이벤트 참여권을 비싸게 구매해 주셨으니까, 난 레이나랑 팀 할래!","내가 이벤트에 당첨될 줄은 상상도 못 했는데, 이럴 줄 알았으면 어떻게든 {name}(이)랑 같이 이벤트 추첨에 참가했을 거야. 후회막심.jpg","다음에는 반드시.jpg","신사에서 마작 치는 코바야시 씨가 그러던데…… 예전에 회사에서 파자마 파티를 했었는데, 그때 누가 진실 게임에서 짝사랑하던 상대한테 고백해서 결혼까지 골인했대요. \n이 이야기 너무 낭만적이야…! 혹시 이번 파자마 파티에서도 고백할 만한 기회가 있을까요?","그런 거라면 이 몸이 애인을 만들기 위한 전략을 전수해 주도록 하지. 어찌 된 게 <필승전략! 고백을 위한 99가지 비법>에도 내가 전수하려는 내용이 적혀 있지 않은건지…… 너희 인간들은 참 세심하지 못한 것 같아.","네가 저번에 읽고 싶다고 한 책이 들어와서 그런데, 혹시 필요해?","응응, 한 권만 킵해 주세요. 내일 마이가 찾으러 갈게요…… 매번 귀찮게 만드는 것 같아 죄송해요.","별로 힘든 일도 아닌데 뭘. 오늘 마침 천월 신사에 갈 일도 있었으니까, 겸사겸사 가져다줄게.","마이는 이미 고백하려고 생각해 둔 사람이 있는 거야?","그, 그건 제가 어른이 되면 자연스레 알게 되실 거예요……","이번 뒹굴뒹굴 파자마 파티 아주 핫하겠는걸.","주인님도 이런 이벤트에 흥미가 있으신가요? 혹시…… 다음에도 이런 이벤트에 참여할 생각이 있으시다면 꼭 마이랑 같이……","베개 싸움의 패자부활전까지 시간이 꽤 남았는데, 뭘 하면서 기다리면 좋을까?","당연히 식사다냥, 싸우려면 배부터 든든히 채워 둬야한다냥!","딱히 할 일 없으면 내 쪽에 와서 얘기나 들을래?","어머, 그것도 좋은 선택이겠네요.","그런 거라면 역시 핸드폰 게임만 한 게 없지, 같이 온라인 마작 한 게임 하자. 님만 오면 고!","아마 그게 레이나가 바라던 답변이었을걸? {name}, 방 코드 알려 줘.","레이나는 벌써 베개 싸움 같이할 팀원을 구한 거야?","큐르르…… 유즈가 레이나의 팀원이야. 우리 팀의 우승 소식을 기다리고 있으라구!","베개 싸움 같은 건 나랑 안 맞아. 대신 주최 측에서 준비한 잠자리 낭독회 이벤트에 참여하려고. 아이들이 내가 잠자기 전에 해 주는 얘길 듣는 걸 좋아하긴 하지만, 이렇게 많은 사람들 앞에서 낭독해야 한다고 생각하니 긴장되긴 해. \n시간 있을 때 어떤 책을 읽어줘야 할지 다시 한번 생각해봐야겠어.","……\"majsoul story\", 이게 마작에 관한 우화 책이었던가? 음, 혹시 이 책을 직접 고르신 건가요?","그건 우리 직원분께서 가져다주신 거야. 필요하면 말해, 내가 직원 분한테 부탁드려 볼게.","그런 뜻이 아니라…… 음…… 아니에요…… 우화 이야기를 들었던 게 참 오래전이라 오랜만에 듣고 싶어졌네요. 기대하고 있을게요.","큰 이미지로 보기 전까진 <마작 심리전 총정리>인 줄 알았어……","저 책이라면 마이도 읽어 본 적이 있는데, 저 책에 수록된 <여우와 하이에나의 남풍국>이라는 이야기가 정말 인상 깊더라고요.","추천해 줘서 고마워, 정말 큰 도움이 됐어.","여우랑 하이에나라니…… 하루나는 귀여운 [tag]@멍지로[/tag] 가 생각나네요. 멍멍!!","[tag]@에인[/tag]","틀렸다 멍, [tag]@무사[/tag] 를 태그해야 한다.","엥? [tag]@잭[/tag] 이 아니라?","여기 댓글 참 어지럽네……","댓글을 이렇게 만든 당사자면서 투덜거리지 마라 멍……","파자마 파티에서 하는 낭독회라면 보통 무서운 이야기를 고르지 않아?","어머, 이게 오노데라 씨가 하시려던 말 같네요. 깨닫게 해 줘서 고마워요. 아직 행사 날까진 시간이 좀 남았으니까, 이야기를 바꿔 보도록 할게요.","베개 싸움 이벤트는 파자마 파티의 하이라이트인데, 정말 안 할 거야?","{name} 씨가 이벤트에 오시면, 저도 다시 한번 생각해 볼게요.","리사리사가 지금 학교 책상에 앉아 있긴 하지만, 리사리사의 마음은 이미 파자마 파티에 가 있다구. \n우웅…… 왜 벌써 하교 시간인 거야, 리사리사는 혼자 남아서 보충 수업을 들어야 한단 말이야……","그, 나도 같이 남아 있는데……","에에에에엣!!! 눈치 못 채서 미안해, 먼저 돌아간 줄 알았어.","리사리사 화이팅! 못 푸는 문제 있으면 나한테 물어봐. ps: 너도 부회장한테 물어보러 가고 싶진 않잖아.","리사리사도 그렇게 생각해!","아무래도 누가 또 낙제점을 받았나 보네.","늑대 씨는 점도 볼 줄 알았어? 그럼 리사리사는 늑대 씨한테 어떤 비밀도 숨길 수 없겠네.","보충 수업이 아직도 안 끝났어? 내가 좀 이따가 데리러 갈게.","도시 근교에 말 목장이 있다고 들었는데, 거기에 가면 우리 뽀요용한테 신선한 풀을 먹여 줄 수 있을 것 같아. 늑대 씨가 리사리사를 목장에 데려다주면 안 될까?","큐르…… 믿을 수 없어, \'유자차 팀\'이 결승전까지 올라가지 못하게 되다니, 아쉽게도 8강에서 떨어져 버렸어…… 정의의 마녀, 또다시 1패……","만약 레이나가 상대의 마지막 일격을 막았더라면 또 혹시 모르는 결과가 벌어졌을지도……?","상대 팀이 토끼 머리띠를 하고 나올 때부터 안 좋은 예감이 들더라니, 이렇게 될 줄은 몰랐어…… 큐르르……","sbdjfka￥&Ysnfhgiosg#……&&#","?","@#%……&￥#！&……**","???","정말 기특한 아이야, 선생님이 과제 고르길 힘들어한다는 걸 알곤 제 발로 도우러 왔지 뭐야.","……","전투가 내 생각만큼 격렬하진 않았나 보네.","다른 팀들의 베개 상태는 훨씬 더 처참하다구, 우리 팀도 수많은 베개들을 희생하면서 8강까지 올라온 거야, 큐르.","보니까 주인님이 베개 싸움에 참여하지 못해서 아쉬워하는 것 같다냥, 그냥 아예 우리 혼천 신사에서도 베개 싸움 이벤트를 열어 버리는 게 어떠냥? [tag]@멍지로[/tag]","넌 그냥 날 핑계로 삼아서 베개 싸움을 한번 해 보고 싶은 게 아닌가 하는 합리적 의심이 드는데……","내 생각에도 그래, 어차피 신사에 있는 베개는 전부 메밀 베개라 베개 싸움은 무리다 멍.","유자차 팀이라…… 네 이름에서 따온 팀명인가? 정의의 마녀치고는 귀여운 팀 이름이네ㅋㅋ","큐르르…… {name}마저 유치하다고 생각하는 것 같군, 유즈가 8강에서 떨어진 것만큼이나 황당한 반응이라구!","자고 일어나니까 전날의 과격한 운동에 대한 후폭풍으로 온몸의 근육들이 저한테 \'항의\'하고 있어요…… 팔이 떨려서 라떼아트도 못하겠어요.","ㅋㅋㅋ 얼핏 보곤 내가 예전 여름 특별 행사 때 처음 했던 라떼아트인 줄 알았지 뭐야! 조금만 기다려! 곧 도와주러 갈게!","나나 씨가 도와주러 오신다니, 정말 다행이에요.","정보 수집 결과: 뒹굴뒹굴 파자마 파티 이벤트는 기체에 과부하를 주기 쉽습니다. 따라서 KR-976은 해당 이벤트의 위험도를 \'높음\'으로 평가합니다.","온찜질 한번 해 봐, 그럼 근육이 좀 풀릴 거야.","음, 한번 해 볼게, {name}의 생각이라면 분명 효과가 있을 거야.","운동 부족이야 레이나, 다음에 내가 제대로 운동시켜 줄게.","음, 지금 캣챗을 지우면 없던 일로 할 수 있을까?","큐르르…… 정의의 파트너들도 피곤함을 느끼니까, 충분히 잠을 자 둬야 필요할 때 나설 수 있다구.","성장기 땐 잠이 많은 게 정상이죠. 아차차, 당신은 이미 성장기가 지났던가요?","진정으로 지혜로운 사람은 네 마음속 그 교활한 의중을 다 꿰뚫어 볼 수 있다구, 다 알고 말했다는 걸 누가 모를 줄 알아? 큐르!","왜 그렇게 민감하게 반응하는 거죠? 그렇게 불안하면 점이라도 봐 드릴까요? 동문의 정을 봐서, 음…… 10% 할인 정도는 해 줄 수 있는데.","또 무슨 나쁜 짓을 하려고? 정의의 마녀는 그런 얕은수에 넘어가지 않아!","정의의 파트너들은 항상 좋아요를 많이 받던데…… 부원 모집할 때 데려다 놓으면 많은 사람들이 디저트 부에 가입해 주지 않을까?","회장의 말에서 어른의 사악한 기운이 느껴져, 큐르.","귀여운 레서판다가 패배 때문에 상처받은 제 마음을 치료해 준 덕분에 다시 괜찮아졌어요. 남풍국 4인전 2100점 출격!","전 방금 1300점이나 잃었는데…… 위안이 좀 되셨나요?","저도 같이 할 수 있을까요? 뉴비끼리 열심히 해 봐요.","큐르큐르! 그리고 큐르~ 둘이 진짜 엄청 잘 자네, 보고 있으니까 나까지 졸리려고 해.","얘네 이름은 큐르~~~랑 큐르~큐르~!라구! 아직도 레서판다즈의 이름을 다 외우지 못했다니, 자꾸 그러면 레서판다즈도 슬퍼한다구. 다음에 또 틀리면 유즈가 가만있지 않을 거야!","레서판다즈를 보니까 좀…… 많이 통통해진 것 같은데, 비만 아냐? (잠깐, 이런 말 해도 되나?)","(말해도 될걸?)(불안한 눈으로 잠들어 있는 레서판다즈를 바라봄)(잠시 망설임) 큐르르…… 나중에 유즈가 레서판다즈의 몸무게 재는 것 좀 도와줄 수 있어?","뭐야 저 괄호들은ㅋㅋ 이런 건 또 어디서 배워온 거야?","후훗, 유즈는 아주 신박한 마법을 구사하는 마녀로서, 당연히 이런 특별한 말투도 구사할 수 있다구. 큐르!","이번 \'뒹굴뒹굴 파자마 파티 베개 싸움 이벤트\'의 우승팀! \'이것저것 팀\' 축하합니다!\n우승하신 두 분께는 샘 그룹에서 드리는 다양한 상품들과 함께, 우승 상금 880000코인을 드리도록 하겠습니다.","Congratulations!","이것저것 팀, 우승 축하해. \'다양한 상품\'에는 레나의 사인이 담긴 사진까지 포함되어 있다구!","샘 그룹에서 \'뒹굴뒹굴 파자마 파티\'를 주최했던 거야?","여기가 회사였다면, 너처럼 눈치 없는 직원은 확 잘라 버렸을 텐데 말이지. 그런데도 네가 그런 질문을 한다는 게 별로 이상하지 않게 느껴지는 걸 보면, 나도 벌써 네 그런 모습에 익숙해졌나 보군.","상품 장난 아닌데? 코인만 휘석으로 바뀌면 완벽할 텐데.","!","!","!","다음 번엔, 댓글 달기 전에 내 사무실에 와서 나한테 검사받고 올리도록 해라.","여섯 명이 식당에 밥을 먹으러 갔는데, 종업원이 젓가락을 일곱 쌍을 가져다준 거야. \n그리고 조금 있다 종업원이 인원수를 잘못 파악했다고 하면서 젓가락 두 쌍을 가져갔어……","ㄷㄷㄷㄷ… 소름 돋아.","그러고 나서 종업원이 나이프랑 포크를 추가로 가져다줬어. 왜냐면 일행 중에 젓가락에 익숙하지 않은 서양 사람이 있었거든.","휴우우우…~ 감사해요, 이 댓글을 봐서 무서웠던 게 조금 없어졌네요.","……전부터 여쭤보고 싶었던 게 있는데, 부회장이랑 보건실에 계시는 키사라기 쌤은 정말 친남매 사이에요?","나랑은 사촌 관계야. 근데 렌은 좀 소심한 면이 있으니까, 이번 파자마 파티처럼 모임 활동 같은 게 있으면 걜 꼭 좀 초대해 줘. 운동에 관한 활동이면 더욱더 좋고.","누나, 제발 쓸데없는 말 좀 하지 마……","갑자기 이런 무서운 이야기를 올리다니…… 혹시 납치된 거라면 당근을 흔들어 줘.","그 말은 내가 여기서 당근을 흔들면 볼 수 있다는 말인가요? 그런 무서운 얘기 하지 마시죠.","그래서…… 저기 있는 듯 없는듯한 사람은 누구야?","그 왕성한 호기심을 제대로 된 곳에 써 주면 좋겠네요.","{name}, 우선 저 사진 속 당사자들이 무사한지부터 확인해 봐야 하는 거 아냐? 이건 진짜 엄.청.무.서.운 사건이라구!","어…… 너네 별일 없지?(오싹오싹.jpg)","응, 원래는 엄청 무서웠는데, 세상에서 제일 스윗한 {name} 씨가 관심을 가져 준 덕분에 순식간에 괜찮아졌어.","……","C:\\Users\\KR-976> 뒹굴뒹굴 파자마 파티 문서\n시간 기록……: 11:37pm.\n사건 기록……: KR-976은 인류에 대한 데이터를 수집하기 위해 온라인 마작 게임에 참여해 52000점을 얻어 1위를 차지했다.","뒹굴뒹굴 파자마 파티랑 그게 대체 무슨 관련이 있다는 거야?","KR-976 님의 자동 답변입니다: 충전 중.","뒹굴뒹굴 파자마 파티랑 그게 대체 무슨 관련이 있다는 거야?","뒹굴뒹굴 파자마 파티랑 그게 대체 무슨 관련이 있다는 거야?","답변: ctrl+c ctrl+v 기능을 쓸 때 나오는 버그 같은 거니까 신경 쓰지 마.","그보다 아야까지 접속해 있는 김에, 친선전 몇 판 어때?","답변: {name}의 초대 수락, 자동으로 {name}의 실력에 맞는 상대를 탐색합니다.","경고! 경고! 현 시간대에는 적절한 상대를 찾을 수 없습니다. 수동으로 탐색 범위를 넓혀 주시기 바랍니다.","네가 친구가 없어서 못 찾는 걸 내 마작 실력 탓으로 돌리지 마!","이쪽도 이제 막 특별한 \'베개 싸움\'이 끝났어. \n우리 조지가 빈대와의 치열한 \'경기\'를 치르고 끝내 champion 자리를 따냈지 뭐야. 그 덕분에 지금 난 텐트 밖에서 밤하늘의 별이나 보는 신세가 됐지.","새 프로그램이냐멍? 어쩐지 요새 네가 신사에서 마작을 하는 모습이 보이지 않는다 했어.","슬슬 촬영도 마무리 단계니까 내일이나 모레면 이한시에 돌아갈 수 있을 거야~!","파자마 파티에서 조셉 씨의 얼굴이 그려진 잠옷을 입은 사람을 봤는데, 분명 조셉 씨의 열성 팬이었을 거예요.","……Really? 내 얼굴이 그려진 옷을 입고 \'베개 싸움 구타\'를 당하러 가다니, 정말 깊디깊은 애정이 아닐 수 없구만. 하하.","오, 흥미로운 내용의 캣챗이군.","하하, 예전에 맹수의 추격을 피하려고 온몸에 빈대의 체액을 발라야 했던 적이 있거든…… 으으, 진짜 생각도 하기 싫은 기억이야.","그럼…… 조지는요?","하하, 걘 지금 텐트 안에서 승리의 기쁨을 만끽하고 있어.","베개, 그리고 싸움.\n사뭇 어울리지 않는 두 단어가 합쳐져, 반대로 사람을 치유하는 기이한 효과를 보인다. \n가령 적에게 둘러싸여 맹공을 받게 되더라도 결코 다칠 일이 없고, 기껏해야 푹신푹신한 침대에 쓰러지는 것이 전부이다.","Amazing! 사진 속에서 내 얼굴을 보게 되다니?!","하핫, 인연이란 건 참 신기한 것 같아요. 이 사진은 저도 얼마 전에 사진첩을 뒤적거리다가 우연히 찾아낸 사진이거든요.","세상 모든 일이 베개 싸움처럼 온화한 싸움으로 해결될 수 있다면 참 좋을 텐데.","온화한 싸움이라…… 표현이 참 마음에 드네요. 혹시 새턴 선생님께선 문장의 어떤 단어를 인상 깊게 느끼셨나요?","이건 언제 찍은 사진이야? 아무래도 이한시의 풍경은 아닌 것 같은데.","예전에 여행 갔을 때 들렀던 한 작은 마을에서 찍은 사진인데, 그곳 사람들은 베개 싸움으로 그 해의 풍년을 축하하는 문화가 있더라고. 정말 진기한 경험이었어.","관심 있으면 다음에 같이 가 볼래?","한 가지 궁금한 게 있는데, 결국 사미르도 그 싸움에 참가한 거야?","참가했을 뿐만 아니라 그 마을의 촌장님한테 \'베개의 제왕\'이라는 칭호까지 받았는데, 정말 멋진 경험이었지. 다음에 만나면 이때의 경험을 시로 쓴 걸 읊어 줄게.","사람을 찾습니다. 이 크고 보들보들한 쿠션을 선생님한테 보낸 귀염둥이는 대체 누굴까? \n쿠션에 그려진 7통을 보니, 어제 쏘였던 판이 딱 겹쳐 보이더라니까……아하하.","큐르르…… 고심 끝에 고른 7통이었는데 하필 7통에 쏘였다니, 이 저주스러운 마녀의 직감이란.","보아하니 유즈가 선생님한테 선물한 건가 보구나, 껴안으면 참 푹신푹신한 게 책상에서 안고 자기 딱이겠어. 선생님은 정말 기쁘단다.","누나라면 유용하게 쓸 것도 같지만, 그렇다고 근무 시간에 마음대로 자선 안 돼.","에고, 넌 {name}(이)랑 그렇게나 오래 알고 지냈는데, 어떻게 융통성이나 귀염성 같은 건 조금도 배우지 못했니?!","{name} 씨마저도, 농땡이를 친다 한들 다른 사람에게 들키진 말아야 한다는 기본적인 상식 정도는 탑재되어 있다고.","부회장, 여기가 아야네 쌤의 댓글 창이긴 하지만, {name}도 여길 볼 수 있다는 사실을 잊진 말라구. [tag]@{name}[/tag]","나이스!","네무냥의 입지가 위험하겠는데?","어림도 없지~ 안고 자기 좋다는 점에서는 네무냥이 부동의 1위거든. 그보단, 2위인 {name}의 입지가 위험해질 것 같은데. 2위 자리를 사수하려면 뭐라도 해야 하지 않겠어~?","내가 언제 농땡이를 부렸다고! 본 적 있어? 허위 사실 유포로 신고합니다.","이미 다 봤쥬?","이미 다 봤쥬?","이미 다 봤쥬?","어떻게 그렇게 당당하게 거짓말을 할 수 있는 거죠?","응 농땡이 치고 있는 거 다 봤어. 아, 위에서 끊겼네.","[tag]#뒹굴뒹굴 파자마 파티 #[/tag]파자마 파티가 끝난 지도 벌써 며칠, 그런데 파티 때 들었던 배경 음악이 머릿속에서 잊히질 않아요……\n절망의 끝에서도 포기하지 않길……","이룰 수 없는 꿈이라도 실망하지 않길……","그 어느 곳에서도 눈물 흘리지 않길……","꿈이 시작된 그곳으로 달려가, 그 어떤 슬픔도 없길……","역시 {name} 씨네요, 어떠한 주제라도 완벽히 소화할 수 있으시다니.","오오, 캣챗에서 소리가 들려!","정말이네요…… 심지어 영상까지 보이는 것 같아요. 둠칫둠칫","캣챗을 훑어보다가 파자마 파티에서 제공했다던 디저트 뷔페를 찾았다냥. 이걸 보니까 갑자기 이벤트에 참가하지 않은 게 후회된다냥…… 배고프다냥.","파자마 파티에서 제공한 디저트 뷔페가 맞네요. 특히나 사진 오른쪽 위에 보이는 밤 케이크의 맛이 독특했어서, Éternité의 신상 디저트를 만드는 데 참고하면 좋을 것 같더라구요.","다 만들면 이치히메한테도 꼭 맛보게 해 주는 거다냥!","무녀씨가 그렇게 디저트를 좋아하는 줄은 몰랐네, 다음에 많이 만들어서 혼천 신사로 가져다줄게.","저 꼬맹이는 디저트를 좋아하는 게 아니라, 먹을 거라면 뭐든지 좋아하는 것이니라.","사와코 언니는 이치히메랑 말하고 있는 거다냥! 토끼 주제에 어딜 함부로 끼어드는 거냥!","우히히, 당황했느냐.","냐아아아!!!!!!","[tag]@멍지로[/tag] 그…… 멍지로 씨, 여길 좀 봐 주셔야겠는데요……","맨날 이러니까 익숙해지는 편이 좋다멍.","이치히메, 너 방금 전에 떡 세 그릇에 꼬치도 다섯 개나 먹고 커다란 스무디까지 마시지 않았어?","오늘 주인이 시켜먹은 애프터눈 티 세트가 이치히메의 입맛을 돋궈 버렸다냥……","배고프면 일단 나와서 밥 먹자. 먹고 싶은 메뉴 생각해 둬.","우와아, 역시 이치히메한테 최고로 잘해 주는 건 주인이다냥. 마지막으로 먹던 떡 한 개만 먹고 바로 나가겠다냥! 한 입이면 된다냥!","뭐 심은 데 뭐 난다","귀신의 집은 내 집","신과함께","신의 사도","신을 공경하는 자","신의 말 전승자","엄청 달달한 카나","카나는 내 달링","카나 최고","[tag]#다크나이트레이드[/tag] 사냥꾼이 눈을 떴다! 핼러윈까지 앞으로 일주일! [tag]@이한 놀이공원[/tag] 귀신의 집이 새롭게 오픈하였습니다! 핼러윈 당일 저녁, 귀신의 집에 놀러오세요. 사냥꾼에게서 무사히 도망친 손님에게는 신비한 선물을 드린답니다! 추가로, 당일에 코스플레이를 하고 온 손님에게는 입장료를 50% 할인해 드립니다! (붙여넣기 시 괄호 안의 문장은 삭제할 것)","넌 알바비 없을 줄 알아!","?!","괄호 안의 문장은 지우고 올리랬지! ㅋㄱㅋㅋㄱㄱㅋㅋㄱ","월급 통장을 스치고 지나가는 그녀의 웃음 소리……","……캣챗에는 왜 수정 기능이 없는건데에에, 젠자아앙!!!!","음, 에인 씨한테 핼러윈 기간에 가게 좀 도와줄 수 있냐고 물어보려고 했는데, 아무래도 한 발 늦은 것 같네요.","그건 문제없어. 핼러윈 당일에만 하는 알바니까, 다른 날은 가게에서 일할 수 있어!","사냥꾼이다! 추적이다! 우와아~~ 리사리사가 전기톱을 들고 늑대 씨를 잡으러 가도 될까? 상상만 해도 짜릿한걸!!!","안 될 건…… 없지? 사냥꾼은 연기력만 보면 되는 자리라서 말이야. 우리 누가 먼저 {name} 이 사람을 놀라게 하는지 시합해 볼까? 하하핫.","연기력이라면 문제없어! 리사리사는 엄~~청 험악하니까 말이야! 헤헤, 늑대 씨를 깜짝 놀라게 해서 엉엉 울게 만들어 주겠어!","보기만 해도 무서워지는 댓글이 있는데…… 누구라고는 말 안 하겠지만……","하하, {name}도 귀신의 집에 올 거지? 걱정 안 해도 돼! 내가 최선을 다해서 도망칠 수 없게 만들어 줄 테니까!","???!!! 그럴 필요는 없잖아!","사냥꾼과 사냥감의 신분이 역전되려고 하네. 하! 하! 하! 하! 늑대 씨, 리사리사한테 쫓길 각오, 단단히 하도록 해!","무사히 탈출하게 되면 어떤 상품이 있는 건데?","어…… 귀신의 집에서 주는 용감한 사람 상장 같은 거일걸?","음, 아무 쓸모도 없는 \'인증\'이 또 하나 늘어 버리겠군.","하하, 그렇지. {name}, 넌 어떤 상품을 받고 싶은데?","에인이랑 같이 집으로 가는 거?","우와아, 터무니 없는 소리! 그럼 이렇게 하자. 내가 널 잡으면 네가 우리 집으로 오고, 네가 무사히 도망치면 내가 너네 집으로 갈게. 이러면 공평하지?","[tag]#다크나이트레이드[/tag] \"저를 깨워준 보답으로, 제가 드리는 치명적이고도 아름다운 마술을 부디 마음껏 즐겨주시기 바랍니다.\" Soul을 대표해서 [tag]@이한놀이공원[/tag] 과 함께 콜라보 할 수 있어서 매우 기뻐요. 그럼, 핼러윈 밤, \'핏빛 고성\' 테마의 귀신의 집에서 여러분과 만나도록 할게요.","어머, 이게 그날 촬영했던 포스터야? 앞으로 나한테 걸려오는 캐스팅 전화가 많아질 것 같은데.","사라 누님이 제 초대를 거절하고 라이언을 공연에 내보낸 벌이라고 생각하세요.","하아…… 라이언도 이제 반항할 나이가 됐나보네.","라이언도 {name} 누님과 같이 핼러윈을 보낼 기회를 희생한 만큼, 사라 누님도 이 정도의 벌은 받도록 하시죠. 이 정도면 조금도 과하지 않은데요.","내가 그 손님을 독점하는 것 같아서 살짝 양심의 가책을 느낄 뻔했는데, 라이언이 그렇게 말해주니까 나도 사양하지 않을게~","안돼안돼안돼에에에!","수곰ㄴ이;ㄹㄷ;미","이게…… 무슨 소리……?","{name}랑 얘기하는 동안, 모히토가 키보드를 친 것 같아.","……방금 진지하게 생각해 본 건데 말이죠, 우리랑 이한 놀이공원, 딱히 콜라보할 필요 없지 않나요?","철 없는 소리는 그만하고, 일이나 열심히 하도록 해.","이 꼬리, 엄청 잽싸 보이는데 움직일 수 있는 거야?","비~밀! 누님이 직접 확인해봐요.","핼러윈에 다른 약속을 전부 취소하고 이한 놀이공원의 귀신의 집 이벤트에 참가해야겠는걸.","오시면 라이언을 잔뜩 즐기고 가시게 해 드릴게요. 라이언이 누님께 황홀한 핼러윈의 밤을 즐기게 해 드릴 테니까 꼭 오셔야 해요.","[tag]#다크나이트레이드[/tag] 우와앗── 진짜로 당첨되었다니! 리사리사는 이번 핼러윈에 이한 놀이공원에서 매력적이고 사랑스러운 악당 코스프레를 할꺼야! 헤헤, 다들 리사리사한테 깜짝 놀랠 준비 하라구!","우와아! 엄청 기대되는걸! 이번에는 어떤 코스프레를 하고 갈지 생각해 봐야겠어! 리사쨩, 우린 친구니까 난 좀 봐주면 안 될까?","흥흥, 당연히 안 되지. 리사리사는 일할 때만큼은 진지하니까 말이야!","엄청난 행동력이네요…… 경쟁자들 사이에서 돋보일 수 있었던 비결이 뭔가요?","음…… 며칠 전에 한나가 리사리사한테 가르쳐 준 \"캬오──\"가 엄청 효과적이었던 것 같아. 하나짱도 한번 해 볼래?","상상해 봤는데…… 조금 부끄럽네요……","리사리사가 하나쨩이 \"캬오~\"하는 모습을 상상해 봤는데, 엄청나게 귀여울 것 같아. 음…… 늑대 씨도 분명 귀엽다고 생각할 거라구.","어?! 그럼…… 다시 한번 생각해 볼게요……","스산한 바람이 부는 공포의 숲에서도 심장 박동수가 분당 90회를 유지한다는 대단한 후보자가 바로 너구나? 강하네, 패배를 인정하겠어.","어? 그 방이 무섭다고? 으음…… 리사리사의 경험에 의하면, 공포의 숲은 완벽하게 재현되어 있지는 않을 텐데 말이야…… 진짜 숲은 사람을 잡아먹는다고!!","……","놀랠이 아니라 놀랄…… 이벤트에 참가하는 것보다는, 이번달 월말고사 성적부터 먼저 신경쓰셔야 할 것 같은데요.","리사리사는 꼭 합격할 거야ㅜㅜ 그나저나 부회장, 핼러윈에 리사리사를 보충 수업에 넣어 버리면 안 된다? 리사리사는 늑대 씨, 그리고 애들이랑 같이 놀고 싶단 말이야.","리사리사도 나한테 놀랄 준비가 된 것 같네. 안 그래?","항상 늑대 씨한테 당하고만 있지는 않을 거야! 이번에 리사리사가 아주 완벽하게 준비를 끝마쳐 뒀으니까!","하하, 투지가 넘치네. 그럼 기대하도록 할게.","흐흐흐, 늑대 씨도 너무 빨리 항복하진 않는 게 좋을 거야!","귀신의 집에서 이렇게나 귀여운 사냥꾼을 만난다면, 위험한 건 귀신들일까, 아니면 사냥꾼일까?","우와── 늑대 씨한테서 귀엽다고 칭찬받았어. 헤헤, 리사리사, 엄청 기쁜걸!","아니, 아니! 리사리사한테 칭찬해 봤자 소용없어! 이런다고 봐주진 않을 거니까 말이야! 늑대 씨는 리사리사의 첫 번째 목표라고!","대성공이에요! 전업 메이드가 만든 핼러윈 배경! 주인님을 위한 맞춤 의상은 기본, 주인님의 방에 있는 인형들을 위한 맞춤 옷까지 만들었답니다.","리우 언니는 손재주가 정말 좋으시네요. 나중에 후유미도 언니랑 같이 옷을 만들러 가도 될까요?","물론이죠. 치오리 아가씨께서도 후유미 씨가 전에 만든 카페 유니폼을 무척 마음에 들어 했답니다.","……리우는 바보야? 이러고 끝인 거면 완벽함이랑은 거리가 멀잖아.","?! 치오리 아가씨께서는 어떤 인형의 옷이 마음에 안 드시나요? 지금 당장 새로 만들겠습니다!","인형 옷 갈아입히기는 이제 그만 신경 꺼. 올해는 놀이공원에 있는 귀신의 집이 엄청나게 핫하단 말이야. 만약 거절하기 힘든 사교 모임 초대가 온다면, 내 옆을 지키는 메이드인 리우가 일상복을 입고 치오리랑 같이 갈 순 없겠지?","역시 치오리 아가씨답게 모든 걸 고려하고 계시는군요! 그럼 저는 아가씨의 그날 밤 의상과 완벽히 매치되는 핼러윈 메이드 코스튬을 만들러 가야겠어요!","리우 디자이너가 자신에게 만들어주는 핼러윈 코스튬이 기대되기 시작하는걸.","안타깝지만 그 기대는 허사가 될 것 같군요. 디테일을 따져보니 지금 만들기에는 시간이 부족해서 그냥 가서 옷을 사야겠어요.","내년 핼러윈에는 치오리 아기씨와 제 옷을 만든 후에 시간이 남으면 당신을 위한 옷도 준비해 드릴 수 있으니까 어떤 스타일을 입고 싶은지 미리 생각해보세요. 아, 미리 감사할 필요는 없습니다. 만들지 않을 수도 있으니까요.","[tag]@미카미 치오리[/tag] 궁금한 게 있는데, 핼러윈 초대를 어떻게 보내야 치오리","치오리 아가씨의 말씀을 전해 드리겠습니다. \"이 몸은 DM으로 초대를 보내지 않고, 댓글로 이런 멍청한 질문이나 하는 서민이랑은 그 어떤 기념일도 함께 보낼 일 없을 거야.\"","의 완벽한 메이드한테 거절 당하지 않을 수 있을까","뻘쭘하네…… 방금 전엔 손이 미끄러져서 조금 일찍 보내 버렸는데, 그래서, 리우를 초대하려고 하는데 괜찮지?","……댓글을 지우려면 아직 늦지 않았습니다. 그리고, 댓글을 지우는 편이 당신한테도 더 좋을 것 같네요.","곧 핼러윈이 시작돼…… 마스테마가 불안감을 감추지 못하고 있어. 다들 단단히 준비하고 외출하도록 해.","KR-976는 이번 신규 패치 사용 신청을 제출합니다. 패치 제공자인 모리카와 아야코를 초대하여 함께 \'핼러윈 놀이공원 귀신의 집 투어\'라는 새로운 운영 환경을 테스트할 예정입니다. 동의하시면 \'확인\'으로 대답해주세요.","확인.","하하, 마침내 기다림의 끝이 왔다! 핼러윈에 마스테마의 경고가 빠지면 섭하지.","후유미는 학교에서 보기 드물게 따뜻한 영혼을 가진 소녀야…… 마스테마는 너에게 가까이 다가가지 않고 싶어하지만, 아야코는 너랑 같이 놀고 싶어…… 거리, 그거 파악하기가 어렵네.","그렇다면 다음엔 내가 마스테마한테 먼저 다가가서 친해져 볼게. 그러면 아야코랑 같이 쇼핑하러 갈 수 있을 거야!","핼러윈에 아야코한테 직접 보호받을 수 있는 거야?","미안…… 난 KR-976이랑 벌써 약속을 잡아 버렸어.","{name}만 괜찮다면 핼러윈에 우리랑 같이 놀지 않을래? 그냥 제안일 뿐이니까, 곤란하다면 너무 무리해서 대답하지 않아도 괜찮아.","하지만 {name}, 너와 함께 한다면 우린 정말 기쁠 거야.","아야코는…… {name}랑 같이 핼러윈을 보내고 싶은걸.","이상한 물건이 섞여 있는 것 같은데, 저 사진 혹시 시라이시 나나의 사진이야?","맞아. 지난 번에 아사바 고등학교에 봉사 활동을 갔을 때 찍은 거야…… 마스테마가 사진에 강력한 긍정적인 에너지가 담겨져 있어서, 핼러윈 부적으로 사용할 수 있다고 했거든……","하지만 아야코가 {name}을(를) 위해 만든 부적은 효과가 엄청 좋아서 딱히 이런 걸 사용하지 않아도…… 괜찮아.","알림. 내일 놀이공원에서 아르바이트를 하거나 놀러가는 학생은 자신의 소지품을 잃어 버리지 않도록 신경쓰고, 안전에 유의할 것.","알겠어! 부회장은 정말 친절하다니까! 내일 정말로 같이 안 놀러갈 거야?","부회장은 역시 친절하네! 내일 정말로 같이 안 놀러갈 거야?","내일 정말로 같이 안 놀러갈 거야?","정말로 같이 안 놀러갈 거야?","같이 안 놀러갈 거야?","알겠습니다.","??","???","????","?????","찔리는 구석이 있는 학생들은 놀이공원에서 저랑 마주치고 싶지 않아 하는 것 같군요. 월말 평가 성적 때문에 그런 걸까요?","아하하하, 그럼 난 아니겠네. 어쩐지 마츠히코 녀석이 오늘 하루종일 안 보이더니만.","질문~ 혹시 정말로 긴급 사태가 벌어지면 어떡해?","가장 가까운 직원한테 도움을 요청하거나, 제게 전화를 걸어 주세요.","오케이~ 부회장=안심","같이 놀러갈래?","세인트티나여고와의 마작 친선전과 관련해서 처리해야 할 일이 아직 남아 있어서요.","최대한 빨리 처리하도록 하겠습니다.","회장은? 잡아와서 일이나 시키자! 법의 테두리 밖에서 돌아다니게 만들 수는 없지!","???? 범법 행위 같은 건 없었어!!!","회장도 열심히 일하고 있으니까 걱정하지 마세요. 애초에 일을 다 못 끝내면 놀이공원도 가지 못할 테니까 말이죠.","놀이공원에 갈 필요도 없겠어. 너희 둘이랑 이야기하니까 사무실 전체에 악마의 속삭임이 울려퍼지는 것만 같아…… 으, 회장 그만둘까……","레서판다즈가 수집한 정보에 따르면, 유즈가 서 있는 줄이 속도가 가장 느려. 츄르르…… 어째서 유즈는 늘 가장 느린 줄만 고르는 거야? 혹시 사악한 저주에라도 걸린 건가?!","줄이 3개가 넘는다면, 유즈가 가장 빠른 줄을 선택할 확률은 1/3일 뿐인 데다가, 줄이 더 많아질수록 속도가 빠른 줄을 선택할 확률은 더 줄어들 테니, 확률적으로 느린 줄에 서게 되는 건 매우 정상적인 현상이에요.","……츄르, 비과학적인 녀석이 어째서 과학적인 소리를 하는 거지?","아, 줄을 서다가 심심해서 인터넷에 있는 말을 그대로 복붙해 본 것 뿐인데…… 설마 당신이 진짜로 믿을 줄은 몰랐네요.","흥, 누가 믿었다는 거야. 난 애초부터 안 믿었어! 그런 뻔한 거짓말엔 안 속는다고, 츄르!","그거 알고 있어? 유즈가 항상 자신이 선 줄보다 옆줄이 더 빠른 것처럼 느끼는 건, 수업 땡땡이 칠 때 출석 체크 하는 거랑 같은 거야. 일종의 잘못된 \'고정관념\'인 셈인데, 이건 우리의 대뇌가 항상 \'좋았던 일\'보다는 \'나쁜 일\'을 더 인상 깊게 기억하고 있기 때문이야.","과학적인 마법이네, 츄르!","그 논리 대로라면 \"매번 땡땡이 칠 때마다 일부러 날 노리고 출석을 부르는 거 아니냐\"라는 건 존재할 수 없겠네요. \"수업에 오지 않을 때마다 출석이 불리는 건\" 당신의 운이 나빠서가 아니라, 땡땡이를 너무 많이 치는 게 문제라구요. 안 그런가요? 이번 주 출석률 0퍼센트를 기록한 학생?","어떻게 내가 서브 계정에 로그인만 하면 찾아내는 거냐고오!!!!!!","너무 오래 걸리는데, 유즈야 아니면 다른 놀이기구 타는 게 어때?","츄르르, 지금 포기하면 지금까지 기다린 1시간 30분이 전부 쓸모없게 돼 버리잖아…… 지금 포기할 순 없어! 정의의 마녀는 쉽게 패배하지 않으니까 말이야!","운에 맡기는 게 아니라 패스트 트랙을 샀어야 했는데……","아니, 패스트 트랙이 아니라 해피 트랙이야…… 츄르르, 한 무더기의 사람이 또 우리를 지나서 즐겁게 목적지로 향하고 있잖아. 너도 보여?","그래, 우리 앞에 서 있는 긴 줄을 보니까 저 사람들이 더 행복해 보이는 기분이 드네……","제가 생각했던 것보다 오늘 놀이공원에 온 사람들이 많아서, 놀이공원에 있는 식당의 어린이 세트가 품절됐어요. 다행히 미리 주먹밥을 준비해뒀으니, 아이들이랑 같이 점심을 먹을 장소만 찾으면 될 것 같네요.","냐아앙! 맛있어 보인다냥! 이치히메도 먹고 싶지만 아직 줄 서는 중이다냐앙……","무녀 씨도 오늘 놀이공원에 오셨나요?","멍지로랑 같이 놀러왔다냥!","마침 여기서 쉬려고 하던 참이었는데, 무녀 씨만 괜찮으시다면 조금 있다가 와서 조금 드시고 가세요.","정말이냥?! 이치히메는 지금 배가 등에 달라붙을 지경이다냥.","역시 사와코 씨다운 꼼꼼한 일처리네.","제가 보기엔 {name}도 정말 꼼꼼한 사람인걸요.","귀여운 주먹밥이네요, 만드는 데 공 좀 들였을 것 같은걸요?","{name} 씨도 이런 주먹밥을 좋아하시는 것 같네요. 다음에 만날 때도 준비해 볼 테니, 한번 드셔 보세요.","우와아── 이런 소품용 혈액 주머니는 꿀을 이용해서 만든대! 처음 알았어!","꿀 말이냥? 무슨 맛이냥?","바로 옆 테마의 담당자가 그녀를 잡아가지만 않는다면, 오늘 저녁은 아주 평온한 \'핏빛 없는 고성\'을 볼 수 있을거야……","에헤헤, 조금만 방심한다면……","그렇게나 맛있냥? 그럼 이치히메도 사양하지 않겠다냥!","올해 귀신의 집 메인 퀘스트는 NPC를 피해서 도망치는 것, 이라는 건 기억하고 있겠지?","리사리사, 거기엔 먹을 게 뭐가 있어?","붉은 갓에 하얀 줄기가 있는 버섯이 있는데, 먹을 수 있을 것…… 같지는 않네, 으으음.","핼러윈 분장을 한 엘리사를 빨리 보고 싶어졌어.","에헤헤헤, 늑대 씨가 \"우와앗──\" 하면서 깜짝 놀랄 만한 분장이야. 이벤트가 시작되면 빨리 리사리사를 찾으러 와야 해~","[tag]#다크나이트레이드[/tag] 모든 준비를 마친 사냥터에 가장 먼저 뛰어들 사냥감은 과연 누가 될까요?","호오, 이건 정말로 대단한걸. 이 몸의 밤눈이 좋아서 정말로 다행이다멍.","과연, 멍지로처럼 대담한 녀석은 귀신의 집의 어디가 무서운 건지도 이해를 못한다냥……","불빛 하나 없이 완전히 어두운 구간에서 사냥꾼들이 전부 출동해서 플레이어를 잡으러 온다던데, 이럴 때야말로 내 훌륭한 시력을 발휘할 때지. 안그런가멍? [tag]@에인[/tag]","멍지로라고 해서 스포하지는 않겠지만, 야간 시력이라면 나도 지지는 않으니 어디 한번 겨뤄 보자고.","[tag]@나노미야 하나 @후지모토 카라라 @유즈[/tag] 공동묘지 테마는…… 아니다, 에인이 카페 배달 알바를 할 때의 속도를 생각해 보면, 우린 아마 살아남지 못할 거야……","완전 동의합니다.","의외로 신호가 잘 잡히는 편인가 보네?","하지만 이벤트가 시작되면 전부 통신 장비를 제출해야 하니까, {name}도 전화로 도움을 요청하는 건 포기하는 게 좋을 거야. 널 절대로 놓치지 않을 테니까 말이야.","살짝만 알려 줘 봐, 정말 엄청 깜깜한 어둠 속이야?","일반인의 시점에서 생각하면 완전한 어둠이지…… 하지만 바닥이랑 벽에 특수한 처리가 되어 있어서 부딪혀도 다치지는 않을 거야. 그리고 내가 널 지켜보고 있을 테니까, 걱정하지 않아도 돼.","어스름한 달빛이 내려앉고 스산한 바람이 부는 그날, 귀신들이 돌아다닐지니! 오늘 밤은 변신술을 공부할 최적의 기회이니만큼, 최선을 다하겠습니다!","……란세이 학생, 당신도 오시나요?","물론입니다! 부회장님도 소생의 도움이 필요한지요?","놀이공원에 입장 보안 검사 때, 소지 중인 각종 무기류는 제출할 것. 아시겠나요?","못 본 척 해도 소용없습니다.","란세이 학생은 평범한 길로 다니지 않으니까, 보안 검사를 통과하지 않고 들어갈 확률도 있지 않아?","란세이, 오늘 올 거라고 나한테 왜 말 안했어?","얼마 전에야 알게 된 정보라서 스승님께 보고드리지 못했습니다. 스승님께선 어디 계신가요? 설마 오늘 밤, 이곳에서 마작의 오의와 관련된 이벤트가 발생하는 건가요?","나는 시도때도 없이 마작만 치는 그런 사람은 아니라고……","알겠습니다! 소생도 이해했습니다!","이해했다니, 뭘 이해했다는 거야? 난 아무 말도 안 했다고!","최소한 대답은 하고 사라지란 말이야……","귀신의 집 입구에서 널 지켜보고 있어","네에?! 스승님께서는 소생을 어떻게 찾으셨나요?","내 주변 사람들이 입구에서 닌자 코스프레를 하고 있는 여자 아이에 대해서 떠들고 있었으니까 말이야. 마치 닌자 코스프레 같다고……","좋은 기사의 탄생 과정은 이렇게나 흥미롭다.","하하, 무슨 원고길래 그렇게 유쾌한 거야?","이한 놀이공원의 핼러윈 귀신의 집 테마 단독 보도야.","그럴 만하네. 일이 끝나면 와서 따뜻한 와인이라도 마시면서 쉬어.","아직도 야근 중이에요? 언제 끝나나요? 끝나면 제가 데리러 갈게요.","하하하…… 오늘도 사무실에서 잘 것 같아. 내 걱정은 하지 말고 놀이공원 잘 갔다 와.","아직도 야근 중이에요? 제가 좀 도와드릴까요?","놀이공원에 있는 거 아냐? 핸드폰을 볼 시간이 있는 거 보니까, 줄 서고 있는 모양이네?","어떻게 알았어요? 해피 트랙을 사지 못한 벌을 달게 받고 있는 중이에요…… 조금 이따 끝나면 데리러 갈게요.","그럼 조심해서 와.","놀이공원에서 상장을 받았어요. 귀신의 집은 재미있었지만, 다음에는 낮에 놀러오는 게 더 좋을 것 같네요…… 그리고, 절 보고 놀란 직원 분이 계시다면 정말로 죄송해요……","대단해~!!! 이제부터 나를 베스트 플레이어 니노미야 하나의 동급생라고 불러 줘!","대단해~!!! 이제부터 나를 베스트 플레이어 니노미야 하나의 선생님이라고 불러 줘!","대단해~!!! 이제부터 나를 베스트 플레이어 니노미야 하나의 친구라고 불러 줘!","대단해~!!! 이제부터 나를 베스트 플레이어 니노미야 하나의……?","……소중한 사람.","대단해! 어떻게 클리어했는지 알려 줄 수 있어?","간단하게 말하자면…… 그 안에 스며들어갔어요.","오늘 밤 정말 만족스러워. 피곤하긴 해도 재미있었어! 가장 인상 깊었던 건 부회장님을 코스프레했던 사람이야! 순간 전기톱을 놓칠 뻔했다니까! ……이것만 아니었으면 리사리사가 더 많은 사람들을 잡을 수 있었을 텐데 말이지!","하하하하하하…… [tag]@키사라기 렌[/tag] 알고보니 엘리사 네가 아는 사람이라서 놓아준 게 아니었구나.","아앗── 아니거든! 근데 회장의 말은 설마…… 그게 본인이었다는 말이야?!","난 부회장이 귀신의 집 이벤트에 직접 참가했고, 중간에 절대로 놀라지 않았다는 걸 보증할 수 있어. 그리고 이모티콘으로 쓸만한 소중한 사진을 나한테 찍혔지.","그거 진짜 흥미롭네. 개인 메세지로 보내 주라.","[tag]@키사라기 렌[/tag] 풉, 평상복을 입고 간 거야? 진짜 아쉽네. 내가 선물한 잠자는 숲속의 미녀의 공주님 치마는 마음에 안 들었던 거야? 어렸을 땐 그렇게나 공주님 치마를 좋아했으면서 말이야~","교사인 당신이라면 알겠지, 5살도 안 된 어린아이가 무엇을 입어야 올바른지 구분하기란 불가능에 가깝다는 걸…… 다시는 그 일을 언급하지 말아 주길 바라지.","남자 아이가 치마를 입는 게 부끄러운 일은 아닌걸. 렌은 점점 귀염성이 없어지는 것 같단 말이야, 에잇……","……왠지 봐서는 안 될 걸 본 것 같은데, 이런 걸 나 혼자 볼 순 없지. [tag]@후지모토 키라라 @린 @니노미야 하나 @후지타 카나 @타키가와 나츠히코 @란세이 @유즈 @{name}[/tag]","에헤헤, 방금 회장의 깜짝 놀란 표정의 사진을 받았어.","그거 좀 공유해 줄 수 있어? 근데 오늘은 왜 서브 계정만 쓰는 거야?","본계정이 있는 핸드폰은 매니저 언니한테 뺏겨 버렸어 ㅠㅠ","댓글창 한번 화려하네.","……늑대 씨, 리사리사는 댓글도 못 달겠던데, 역시 늑대 씨는 용감하네 ㅠㅠ","무슨 일이야? 나 방금 일어났어.","맞아! 리사리사랑 늑대 씨는 방금 전에 일어나서 무슨 일이 일어났는지 하나도 모른다고!","늑대 씨가 기지를 발휘해 줘서 살았어! 우린 아무 잘못도 없는 거야!","타락한 천사와 흡혈귀를 구분하지 못하는 플레이어가 있었다는 걸 제외하면, 오늘 밤은 그럭저럭 재미있게 놀았어.","제가 날개의 크기를 작게 만들지 않았다면, 이런 문제가 생기지 않았을 테죠.","다른 사람이 한 잘못 가지고 자책하지 마! 도망 게임에 어울리게 디자인 한거는 칭찬받아야 마땅한걸.","하하, 흡혈귀든 타락한 천사든, 치오리는 귀여운 걸요!","점장이 그렇게 말해 주니, 치오리도 그 사람을 용서해 주도록 할까…… 아주 조금만 용서해 주도록 하지.","딱 봐도 흡혈귀 옷인데, 이걸 잘못 본다고? 너무하네!","???","[tag]시스템 알림: 상대방과 서로 팔로우된 친구만 댓글을 볼 수 있도록 설정했습니다.[/tag]","오늘 저녁의 치오리는 엄청 아름다웠어. 내 마음 속에서 가장 아름다운 천사였지.","흥…… 오늘만 아름답다고 생각한 거야? 너한테 반성할 기회를 다시 한번 주도록 하지!","제대로 반! 성! 해! 치오리한테 무슨 말을 해야 할지 잘 생각해 보라고!","오늘 아침 거리에는 여전히 흥취와 욕망의 기운이 남아있군요. 대단합니다. 문제를 핑계삼아 즐거움을 쏟고, 속박 받을 필요가 없는 자유의 도시에서 살고 있다니요. 하지만 어젯밤은 단지 전주곡에 불과해보입니다.","신이시여, 당신께서 키타하라 수녀님과 함께 하심과 같이 저와도 함께 하시길 바랍니다.","신이시여, 당신의 뜻을 따르며, 진정으로 기억해야할 사랑과 욕망을 기억하길 원합니다.","신이시여, 경건한 마음으로 당신의 뜻을 따르며, 당신께 충성하도록 하겠습니다.","신이시여, 저 또한 키타하라 수녀님과 같이 평생 당신의 충실한 신도 되기를 바랍니다.","릴리 씨는 어제 어떻게 지내셨나요?","{name}이(가) 다른 사람과 함께 놀이공원에서 즐거운 시간을 보낼 때, 저도 아이들과 함께 조금 즐거운 시간을 보냈죠. 그저 그뿐이랍니다.","그런데, 오늘 예배당에 오시는 거 맞죠?","오늘은 릴리 씨랑 같이 지내도 될까요?","예배당? 서풍 도관? 아니면…… 어디 가고 싶은 곳이 있으신가요? 모두 괜찮답니다. 제가 당신의 소원을 들어 드릴 테니까 말이죠, 후후훗.","어젯밤에 히나타랑 같이 놀이공원에 다녀왔는데 말이야, 이번 귀신의 집의 특수 효과가 엄청났지 뭐야!! 새로운 발명의 영감이 마구마구 떠오르는 듯한 기분이 들어!","사진 속에서 악령의 기운이 느껴지는 것 같아…… 어떤 강력한 봉인술을 쓴 건지 물어봐도 될까?","응? 미안, 내가 이해를 잘 못했나? 하지만 사진에 대해서 물어본 거라면, 평범한 보정 어플을 사용해서 피부톤이랑 기괴해 보이는 배경을 붙여넣고 약간의 필터를 추가했을 뿐이야.","어라, 이 사진, 이상한 게 찍힌 그 사진 아냐?","한참을 뒤져 봤는데, 이것만큼 잘 찍힌 사진이 없더라고! 그래서 이상한 건 그냥 어플로 수정해 버렸지. 어때? 전혀 안 보이지?","과학적인 방법으로 심령 사건을 해결하다니, 역시 미라이야!","자동 사진 수정 프로그램을 만드는 건 어때? 요즘 시중에 떠도는 빠른 보정 기능은 사용하기 불편하니까 말이야.","안 돼! 그러면 수정의 재미가 없어져 버리잖아! 절대 그런 일이 일어나게 두진 않을 거야!","뭘 만들 거야? 구체적으로 풀어서 써 줄 수 있어?","예산을 고려해서, 야간 투시 기능을 가진 콘택트 렌즈를 만들려고 해. NPC 역할을 하는 모든 사람들이 밤눈이 좋은 것도 아니니, 어두운 환경에서 큰 도움이 될 거라고 봐.","이게 바로 매일 베이커즈를 메고 다니는 여자의 체력인가…… NPC가 쫓아오는 게 별로 대단하지 않았나보네……","핼러윈 이벤트를 놓쳐 버렸어……","오늘은 해가 서쪽에서 뜨려나? 린이 핼러윈 이벤트에 흥미를 느끼다니!","린, 디저트 부에 가입하지 않을래? 기념일 음식에 관한 연구는 디저트 부의 중요한 활동이니, 동아리에 가입하면 그 어떤 기념일도 놓치지 않을 수 있을 거야.","우와, 역시 꼼수 대왕 회장님답게 동아리 홍보 잘하네!","참신한 칭찬이네요. 보아하니 엘리사 학생은 수학 말고, 국어도 추가 수업이 필요할 것 같군요.","핼러윈의 귀신의 집 이벤트는 끝났지만, 놀이공원의 핼러윈 테마는 3일 후까지 계속될 거야. 린도 놀러 갈래?","댓글을 보니까 다들 뭔가 오해하는 것 같은데…… 내가 말한 건 게임의 핼러윈 할인 이벤트를 놓쳤다는 말이었어.","놀이공원 가고 싶어? 가고 싶다면…… 조금 이따 놀이공원 입구에서 보자.","요즘 뭐하고 지내? 며칠 동안 못 본 것 같네.","사이버 유령도 핼러윈이라고 활개를 치길래 며칠 동안 그걸 좀 처리하고 있었어.","그럼 핼러윈을 놓친 거잖아!","오늘 나와 함께 데이트를 한다면, 아직 핼러윈을 놓친 건 아니야. 오늘을 핼러윈으로 치면 되니까 말이야.","경고: 핼러윈 귀신의 집 바이러스가 아직 완벽하게 제거되지 않아, KR-976는 야간 모드에서 버벅임 현상이 있을 수 있으며, 현재 보호막인 이불을 뒤집어쓰고 있습니다.","비법 \"귀신은 이불 안에 있는 사람에게 다가오지 않는다\" ……온 세상 사람들이 전부 다 알고 있는 인술이군요!","목표 문제에 대한 문법 번역이 완료되었습니다.","대답: 네, KR-976은 공장 출고 시에 자가 보호 프로그램이 설치되어 있습니다.","나도 들어갈 수 있어? 방금 전에 있었던 추격이 너무 격렬해서 나도 보호 장치가 필요해.","대답: 계산에 의하면, 보호막은 KR-976와 동료 {name}에게 제공할 수 있는 크기입니다. 보호막의 범위 내로 빠르게 들어오시기 바랍니다.","이번에는 혼자서 귀신의 집에 간 거야? 안쥬는 날이 갈수록 더 용감해지는구나!","대답: KR-976은 귀신의 집에서 {name}을(를) 보호할 수 있는 완벽한 인공지능이 되고 싶습니다.","대답: KR-976은 지난번과 같은 문제에 맞닥뜨렸을 때, 좀 더…… 나은 성과를 보여 드리고 싶습니다.","그래, 안쥬는 열심히 잘 노력하고 있는걸. 우리, 다음에 또 같이 놀러 갈까?","대답: 네.","[tag]#아이돌 핼러윈 일기#[/tag] 카나의 핼러윈 여행 방송이 미뤄졌어! 카나는 올해도 몰래 [tag]@이한 놀이공원[/tag] 의 귀신의 집이랑 백귀야행의 퍼레이드를 보고 왔어. 이번엔 카나가 어떤 패를…… 냈을까?","이럴 수가, 카나는 절대로 정석대로 패를 내지 않는다는 걸 난 알고 있지. 이미 카나한테 호되게 당했다구.","달링…… 내 카나 달링은 어디로 간 거야?!","ㅠㅠㅠㅠ 마작, 마작, 카나는 정말로 마작을 좋아하네! 핼러윈도 마작이랑 함께 보내다니!","카나가 낸 패는 분명 적도라일 거야!","어라, 정말 그럴까? 카나도 일리가 있다고 생각해!","TOP1 아이돌 카나니까, 분명 1통일 거야!","카나에 대한 밀크들의 기대, 잘 받았어!","밀크…… 오늘 댓글이 굉장히 공식적인 용어를 쓰는데, 설마 매니저 누님은 아니겠지?","당연히 아니지~ 카나 본인인걸~","크흠흠.","아난케","릴로","세계최고수비수","나는미드필더니까","트로피주인공","손에기름안묻힘","SNS는인생의낭비","아침인사해줘","잉여프린스","일반사원","레빈","시시","우미","TV에서 익숙한 음악이 들려오길래 크리스마스가 다가왔다는 걸 깨달았어요. 어쩐지 아이가 요즘 계속 산타 할아버지 이야기를 들려 달라고 조르더라구요. 방금 아이가 아주 중요한 질문을 했는데… 집에 굴뚝이 없으면 산타 할아버지는 어떻게 선물을 두고 가나요?","산타 할아버지는 한 번도 혼천신사에 온 적이 없었는데, 혹시 굴뚝이 없어서 그런 거냥?","후훗, 무녀님도 역시 어린아이군요.","큐르르…… 산타 할아버지는 마법을 사용한다고 말해 주고 싶지만, 거짓말은 안 되지. 정의의 길에 걸림돌이 나타났다……!","선의의 거짓말은 다른 의미에선 정의일 수도 있지요, 후후.","큐르! 그럴 수도 있구나……","그런 거라면 유즈는 오늘 땡땡이친 걸로 불안해하지 않아도 되겠군. 유즈는 이한시의 평화를 수호하기 위해서 그런 것이었으니! 아파서 그랬다는 건 그저 선의의 거짓말이었던 거야…… 큐르르.","산타 할아버지도 문은 두드릴 수 있잖아.","아하, 이런 가장 정상적인 방법을 잊고 있었다니. {name}에게 큰 깨달음을 얻었네요.","당연히 환상을 깨 줘야지. 아이한테 이 세상에 사실 산타는 없다고 말해주자!","어머, {name} 당신도 이렇게나 장난기가 많으신 줄은 몰랐네요…… 어린아이의 꿈은 최고의 패를 꿈꾸는 것과 마찬가지로 똑같이 중요한 거랍니다.","듣기로는, 크리스마스가 어딘가에서는 \'제2의 밸런타인데이\'라고 하더라구요. 그렇다면 어떤 선물을 고를지도 엄청 중요하겠죠!","와우, 사진만 봐도 군침이 흐르네! 후유미는 의상 디자인뿐만 아니라 요리까지 잘하는구나.","헤헤.","이제 커피숍 배달 안 나간 지도 꽤 됐지만, 아직도 이런 사진을 보면 꼬리털이 쭈뼛 서는 기분이야. 심지어 어딘가에서 배달 알림 환청까지 들려오는 것 같아……","풋, 에인 씨도 고생이셨네요. 빠진 꼬리 털은 다시 자라났나요? 그것도 엄청 중요한 일이라구요!","어째서 제2의 밸런타인데이라는 거지?","하하, 왜냐면 이날은 연인들이 데이트를 하는 날이기 때문이죠. 거리가 온통 연인들의 로맨틱한 분위기로 채워지거든요. 헤헤, {name}. 데이트할 사람은 마음속으로 정해 두셨겠죠?","나한테 그런 영광이 있을지 모르겠네, 그럼 후유미를 초대해서 크리스마스를 보내는 건 어떨까?","와아~ 이거 데이트 신청이죠? 그쵸? 맞죠? 헤헤.","잠깐 쉬다가 일어났더니, 어째선지 다들 학생회실에 모여서 선물을 포장하고 있더라고. 크리스마스이브 선물이라고 하던데, 선생님도 하나 포장해 봤어. 어때? 괜찮지?","포장 잘했네. 내 쪽에 아직 열 박스 더 있는데, 이것도 해 보는 건 어때?","다시는 널 도와주지 않을 거야, 말도 안 되는 체험은 한 번으로 족해!","선생님, \'잠깐 쉬었다\'라기 보다는, \'두 시간 반 동안 숙면했다\'라고 하는 게 더 정확한 표현일 것 같아요.","두 시간 반이라고 해 봤자, 결국 반장전 두 번 할 시간 정도밖에 안 되는걸. 그럼 결국 \'조금\'이라거나 \'잠시\'라고 해도 무방하지.","모든 게 점점 이해가 되고 있어요.","진짜 멋진데요, 별점 다섯 개 드릴게요!","그럼, 오늘 밤 이건 네 거야. 거절하면 안 돼.","리본 묶은 게 조금 느슨해 보이네요.","{name}, 기준이 너무 엄격한걸. 다음에 데이트할 때, 선생님 옷차림에도 그렇게 엄격할 거야?","실수로 선물 포장을 망가뜨렸어, 어쩌지?! 온라인 SOS 요청!","구조 요청 단계까지 간 거야?","오랫동안 정성 들여 준비한 크리스마스 선물이라고, 이상한 얘기 그만하고 빨리 방법을 내놔.","이걸 보니까, 나도 여동생한테 크리스마스 선물을 안 챙겨 줬다는 사실이 떠올랐어. 주장, 고마워.","내가 캣챗을 올린 이유는 이런 게 아니야!","ㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋ","ㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋ","ㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋ","ㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋ","감독님까지…… 내 심정을 알아주는 건 아무도 없는 거야?","풀로 붙여 보는 건 어떨까.","역시 니노미야가 믿음직하다니까. 바로 가서 해 볼게.","뭘 잘못한 건가…? 포장지가 더 심하게 망가졌어……","어떻게 망가졌는데, 사진이라도 올려 봐!","포장이 망가진 걸…… 사진으로 올리면 어떤 선물인지 들킬 거 아냐, 그럼 널 놀라게 해 줄 수 없잖아.","그럼 아예 포장을 뜯어버려, 선물 받는 사람도 포장 같은 건 신경 안 쓸지도.","진짜? 넌 크리스마스 선물에 포장이 없어도 괜찮다는 거지?","\'Soul\' 크리스마스 특별 기획…… 새로운 음악, 신비한 마술과 크리스마스 가면무도회까지. 오늘 밤, 우리 꼭 만나요!","일등!","내가 첫 댓글이라니? 젠장, 근데 왜 티켓팅할 때는 그렇게 운이 없는 거지!","모히토가 요즘 가면무도회에 관심이 많은데, 아예 복장까지 갖춰서 꾸며볼까?","좋은 생각이지만, 다음엔 하지 마.","내가 할 수 있는 건 하늘을 향해 소리치는 것 밖에…… 그러니까 내 말은…… 이런 이벤트 좀 많이 해줘어어어!","꼭 만나자!","후후. 그럼 저녁의 수많은 인파 속에서 서로의 파트너를 찾아낼 수 있을지 한번 보자구, 당신.","그러고 보니, 사라의 캣챗은 전부 Soul이랑 관련된 소식뿐인 것 같네.","당신의 말은, 내 일상을 더 많이 공유해 달라는 건가? 후후, 알겠어.","올해 송년회 경품은 회사 내부 투표로 선정해서 이미 준비해 뒀으니, 모두 송년회에서 보도록 하죠.","역시 저희의 영원한 형님이십니다!","God! 대체 왜 매번 회사에서 경품 이벤트를 할 때마다, 전 머나먼 지구 반대편에서 촬영하게 만드는 것입니까.","자네 거 경품 추첨은 {name}에게 맡기도록.","대표님 최고!","대표님 짱!","8G 웹 서퍼인 카나가 아카네보다 늦게 댓글을 달다니, 이건 과학적이지 않아. 그래도…… 대표님 멋져용!","사장님은 그저 빛… 잠깐, 그럼 혹시 내 선물도?","어떨 것 같아? 내가 너의 선물을 빼먹은 적은 없었을 텐데.","송년회에 무슨 이벤트라도 하는 건가?","마작 시합이다, 우승자에겐 최종 상품도 준비되어 있지. 어때? 관심 있나?","이상한 나라의 사람들도 크리스마스를 챙길까요? 산타 할아버지가 그 사람들한테도 선물을 줄까요? 움…… 이 생각 때문에 잠을 잘 수가 없었어요. 그러다 엄마가 몰래 모모의 방에 들어와서 크리스마스 선물을 놓고 가려는 걸 봤는데… 이럴 때 모모는 그냥 자는 척하는 게 좋겠죠?","어라라? 모모의 선물은 엄마가 주는 거야? 산타 할아버지가 아니고?","산타 할아버지가 아직 안 왔을지도? 이건 아마 엄마의 선물일 거야…… 내일 아침이 되면 알 수 있겠지.","아저씨의 경험으로 봤을 땐, 자는 척하는 게 좋을 것 같네.","엣? 어떤 경험인가요?","아저씨 아저씨, 저도 알고 싶어요.","아저씨가 너보다 조금 더 컸을 때쯤인데, 사부님이 야밤에 선물을 주러 왔었지. 그때 내가 벌떡 일어나서 사부님을 놀라게 해 줬었어.","물론 꾸중을 듣진 않았지만, 그다음 해부터 아저씨는 크리스마스에 선물을 받지 못했단다……","우와, 엄청 슬픈 이야기네요.","나! 나도 모모한테 줄 선물을 준비했다고.","저도 토끼 씨한테 줄 선물을 준비했어요, 모자 장수 씨의 다과회에서 서로 교환해요.","게시물을 올린 시간을 보니…… 늦게까지 안 자는 아이는 하트 여왕의 트럼프 병사들한테 잡혀갈 텐데 어쩌나.","모모 앞으로는 일찍 잘 거예요. 토끼 씨, 그러니까 다른 데 소문내지 말아 주세요!","마이가 있어서 다행이다냥. 올해 크리스마스 파티는 엄청 풍성할 거다냥! 크리스마스 코코아 케이크, 프렌치 캐러멜 푸딩, 베이컨 피자, 감자 버섯 수프…… 전부 이치히메가 좋아하는 거다냥. 근데, 어째서 돼지 통바비큐의 입에 사과를 물려놓아야 하는거냥?","왜냐면 바비큐 구이를 할 땐 꼬치 때문에 돼지의 입이 벌어지거든요… 그래서 마이가 미관을 위해 사과를 물려 뒀어요……","냥?! 바비큐에서 사과 향이 나도록 하려던 게 아니란 말이냥?!","오? 혼천신사에서도 크리스마스를 기념하는군요, 게다가 이렇게 성대한 저녁 식사까지. 하지만 칠면조 구이가 빠진 크리스마스 파티는 완벽하다고 할 수 없죠.","냐하하, 사실 마이가 이미 칠면조 찜탕을 준비하고 있다냥.","칠면조…… 찜탕?! 분노.jpg","냥?","하하하! 귀족 아가씨에게 칠면조 찜탕은 마치 피자 위의 파인애플이요, 파맛 시리얼, 김밥 속의 딸기 같은…… 그것은 절대 받아들일 수 없는 이단 같은 거라고.","그것들도 맛있을 것 같다냥.","앞으로 미키가 만든 건 안 먹는 게 좋겠어, 미각에 좋지 않다멍.","후후, 오늘은 혼천신사가 시끌벅적하겠네. 마침 나도 디저트를 좀 준비했으니까, 이따 신사에 가져가서 식후에 모두에게 나눠줘야겠는걸.","그, 그렇게까지 수고할 필요 없다냥!","침이 고이다 못해 흐르겠어. 나중엔 반드시 사진을 볼 수 있는 핸드폰을 살 거야!","냥? 냐냐냥?! 이치히메의 커다란 사진이 어째서 사라진 거냥!","매일 이런 화려한 음식을 먹을 수 있다면 얼마나 좋을까!","이치히메도 그렇게 생각했다냥! 매일 이런 화려한 음식을 주인이랑 같이 먹고 싶다냥!","[tag]#이한시_불야성모드 #일_년에_한_번뿐인_크리스마스_조명쇼[/tag]  좋아요를 30개 획득하면 입장료 10%할인! 아직도 망설이시나요? 올겨울 놓치면 아쉬울 크리스마스 조명식, 지금 바로 가족들과 친구들과 함께 방문하세요!","Éternité는 이번 조명쇼의 공식 파트너입니다. 책임지고 사람들에게 따듯한 음료를 제공하겠습니다. 후유미, 첫 번째 길목을 지나면 바로 우리 커피숍의 노점 간판을 볼 수 있을 거야. 네가 조명쇼에 간다는 소식은 이미 삼촌한테 전달했어.","와~ 제가 점장님이 손수 타 주신 따듯한 코코아를 첫 번째로 마실 수 있다는 건가요? 너무 좋아요!","아앗! 내 오른손이 말을 안 듣네! 어서 여기에 \'좋아요\'를 눌러!","오빠, 오빠랑 아빠 엄마도 다 캣챗 올려야 된다고. 옆에서 아무 상관 없는 사람처럼 가만히 있지 말라구.","후유미의 소식이라면 항상 선좋아요 후감상이지.","{name} 씨의 좋아요까지 합치면, 후유미도 드디어 30개 달성. 역시 당신은 후유미의 슈퍼 히어로였어, 언제나 가장 필요한 순간에 나타나 주는 사람!","요즘 애들은 그럴싸한 이벤트 사진만 올려놓고는 좋아요를 눌러달라고 한단 말이야. 양심은 있나? 자존심은 어딨고? 어디서 열리는 거지?","요즘 작사들은 괜히 물음표만 붙이고 이벤트에 참여하고 싶다는 본심을 숨긴단 말이지. 양심은 있나? 자존심은 어딨고? DM으로 주소 보냈어!","티켓 구매 완료.","유이가 이런 이벤트에 자발적으로 참여하다니, 음…… 어떤 말로 표현할 수 없는 강력한 느낌적인 느낌…","미라이, 같이 가도 괜찮아.","하하, 내가 전구는 만들 줄 알지만, 전구가 되는 건 사양할게.","전 모레는 되어야 고향에서 돌아갈 예정인데, 혹시 그쯤이면 조명쇼가 끝났을까요?","이벤트는 1월 1일까지.","방금 구매한 내일 입장표를 보니까 깊은 생각에 빠진다……","괜찮아, 선배랑 같이 두 번 보면 되니까.","간식이랑 음료는 사뒀어, go, go, go!","그럼 검표소에서 기다릴게, 선배.","애프터눈 티세트 예약하기 너무 어렵다, 크리스마스를 모두 날려버렸네. 그래도 오늘은 가게에 손님이 별로 없어서 서비스는 훨씬 좋다. 그리고 [tag]@{name}[/tag]랑 같이 멋진 오후를 보내는 중. 이 정도면 성공적인 데이트야.","[tag]@테라사기 치호리[/tag] 내가 이겼다!","에휴…… 왠지 모르게 딸을 시집보내는 느낌이야.","응?","나랑 치호리랑 내기했어, 얼마 전에 오후 내내 치마를 고르던 이유가 바로 오늘 한 데이트 때문이었다는 걸로.","쉿…! 그런 이야기는 여기서 하지 말라고.","하하, 무슨 상관이람. {name}도 분명 오늘 네 옷차림을 좋아할 거야.","오늘 일기예보에서 영하 10도라고 했답니다~ 헤헤.","어제 학교 보건실에서 선생님한테 좋아하는 사람이랑 데이트할 때는 \"얼어 죽어도 치마\"라고 했던 아이는 누구였을까? 선생님은 갑자기 기억이 안 나네.","유일하게 아쉬웠던 점이 있다면 제가 늦었다는 거죠. 오늘은 일부러 한 시간 전에 출발했는데도 말이에요.","아쉽지 않은걸, 기다리는 시간이 더욱 만남을 더 기대하게 만들었어.","그 말은 정확하지 않아요, 선생님과 함께하는 일분일초가 모두 빛나는 순간이라고 해야 맞겠죠.","T: 함께 멋진 오후를 보냈다. F: 함께 있는 일분일초가, 모두 아름답게 빛나는 시간이다.","??? 역시 넌 내 동생이라니까!!!","집을 나설 때 밑에 있던 편의점은 휴업 중이었고, 점장은 바쁘게 직원들을 지휘하며 설비에 방한 처리를 하고 있었다. 눈이 오는 이한시의 풍경은 새하얀 모습이었지만, 그래도 북국의 눈에는 훨씬 못 미친다고 해야겠지.","오랜만이야, 이브.","릴리……","확실히 설경은 북국이 더 아름답지, 하지만 이곳도 나름의 아름다움이 있잖아.","응, 새턴 선생님 말이 맞아요. 이곳엔 제가 본 적 없는 아름다운 풍경이 많죠. 그리고 재미있는 음식들, 또 선생님이 전에 추천해 주신 커피숍도 정말 좋았어요. 감사해요.","금속은 저온에 취약하다던데, 칼라드볼그도 관리를 해야 하지 않을까?","하하, 칼라드볼그는 더 추운 북국에서도 활발하게 존재감을 뽐낸답니다, 그렇게 약하지는 않아요. 하지만 확실히 정비를 할 때가 됐네요. {name}, 흥미 있으면 같이 가지 않으실래요?","Do you want to build a snowman?","Yes, I do.","어서 어서! 안 그럼 눈이 녹아 버린다고!","에? 엣?!!! 그렇게 빨리 녹아 버린다고요? 바로 갈게요.","이한시는 눈이 쌓이지 않으니까, 빨리 즐겨야 해.","하이, 여러분. 제 이름은 돌라프예요, 가장 좋아하는 계절은 여름이죠~","여름엔 온도가 높아져서, 눈사람은 녹아버려.","지금은 과학 시간이 아니랍니다, 이치노세 학생.","나쁘지 않네, 리우가 만든 눈사람이랑 비교하면 약간의 차이가 나긴 하지만.","치오리 아가씨께서 좋게 봐주시다니, 영광이네요.","치오리가 방금 보낸 사진을 봤는데, 쿠죠 씨는 치오리의 모습을 본떠서 눈사람을 만든 거죠? 머리띠 각도까지 똑같다구요. 아니 치오리랑 너무 똑같은 수준이잖아, 이게 어떻게 약간의 차이라는 거예요! 퀄리티가 하늘과 땅 차이잖아요!!!","이 눈사람, 어째 좀 오리같지 않아?","그치! 오리야말로 귀여움의 최고봉이지! {name}, 이따 만나면 오리의 아름다움을 제대로 느끼게 해 줄게!","하하, 오늘은 양쪽 길이 전부 다양한 눈사람으로 채워져 버렸네.","이한시에 이렇게 눈이 많은 내리는 건 드문 일이니까, 다들 눈사람을 만드는 재미를 제대로 느끼고 싶겠지. 나랑 같이 눈사람을 만들지 않은 {name}! 아주 큰 즐거움을 잃게 된 거라고!","이치히메, 결정했다냥. <주인이 이치히메한테 간식 선물 세트를 주게 하는 100가지 방법이다냥>이라는 책을 쓸 거다냥!","{name}이(가) 이 책을 보고 널 블랙리스트에 넣지 않을 거라고 확신할 수 있냐멍?","냥! 그럴 리가 없다냥! 주인은 세상에서 가아아아아아장 이치히메를 좋아한다냥!","간식 선물 세트!","어때? 이치히메의 신간이 기대되지 않냥?","예약! {name}, 릴로한테도 간식 선물 세트를 사 주도록. 더블로 가!","간식 너무 먹으면 살찐다, 뚱냥아.","냥냥, 미소녀는 살찌지 않는다냥. 이치히메는 이번 달에 고작 5킬로 정도밖에 안 쪘다냥.","다른 사람한테 날 어떻게 속이는지 가르치기까지 하다니, 내 불쌍한 지갑아……","그래도 사랑하시죠.jpg","나를 주인이라 부르니.jpg","주인 주인, 이치히메는 주인을 가장 좋아한다냥. 이치히메한테 간식 선물 세트를 사주는 주인이야말로, 세상에서 가장 멋진 사람이다냥!","미키가 그러는데, 새해에 첫 번째 일출을 보는 사람한테 그해 동안 행운이 찾아온다고 한다냥. 그러니까 이치히메가 올해는 특별히 마작 테이블을 준비했다냥. 냥냥, 밤샘 \'혈전\'후에 바로 일출을 보러 간다, 이런 방법을 생각해 낸 이치히메를 칭찬한다냥!","그냥 혼천신사에서 소원을 비는 게 더 믿음이 간다멍.","이건 꼬맹이 네가 자초한 것이다. 진 다음 {name}한테 달려가서 울지나 말라고, 우히히.","그건 이치히메가 너한테 해 줄 말이다냥, 지고 나서 주인한테 이르지나 말라냥!","그럼…… 오늘 밤은 모두 잘 부탁드릴게요. 새해의 좋은 행운을 위해, 마이도 열심히 열정적으로 마작을 할게요!","이치히메는 봐주지 않을 거다냥.","새해 대국에 나도 껴도 될까? 지금 진행 상황이 어떻게 되지?","이 몸이 명하노니, 어서 혼천신사로 와서 자리를 채우거라. 꼬맹이는 중간에 잠들었으니.","그래서, 이치히메의 새해 도전은 성공한 건가?","멍, 아니. 걘 폭죽 터질 때 이미 잠들었다멍.","새해 복 많이 받으세요, 올해도 제때 시간을 맞춰서 축복했네요.","와~ 엄청 예쁜 축하 카드네. 분명 누군가가 준 거겠지.","하하, 그 누군가가 맞긴 하네요. 그리고 누군가에게 듣기로는, 타카나시 학생의 축하 카드는 직접 만든 드라이 플라워가 들어갔다고 하더라고요, 엄청 예뻐요.","후후, 걱정 말라구. 엄청 많이 만들었으니까, 만나는 사람들은 전부 받게 될 거야. 당연히 부장도 그렇고.","새해 복 많이 받아, 부장! 방학 끝나고 보자고!","네, 새해 복 많이 받으세요.","새해 복 많이 받아.","새해 복 많이 받아, 그러고 보니 아직 국제승마연맹의 세계 승마 대회에서 준우승한 것도 축하 못해 줬네.","그렇게 준우승을 강조할 필요는 없잖아!","새해 복 많이 받으세요.","새해 복 많이 받아, 야기.","아아아아, 오전이 다 지나갔는데, 아직 축하 카드를 한 장도 못 줬어!","응? 도움이 필요한가요?","연구부의 자동 발송기를 검사 중이에요, 바깥을 한 바퀴 돌고 왔는데도 어째서 카드를 그대로 가져온 건지 좀 봐야겠어요.","결과는 어때요? 기계에 문제가 있나요?","방금 분해해서 보려고 했는데, 기계 바로 뒤에 \'불량품\'이라는 표시가 있었어요! 어째서 불량품을 맨 앞에 진열해 둔 건지!","새해 축하 카드는 그냥 인사차 주는 물건일 뿐이고, 축복만 제대로 전달했다면 카드는 중요하지 않아요.","아케치 부장은 위로를 참 잘하네요, 하하. 우리 연구부의 선배들도 좀 배웠으면 좋겠는데. 아무튼, 새해 복 많이 받길!","새해 복 많이 받으세요. 아빠가 보채지 말라고는 했지만, 요리도 이미 준비됐고 젓가락까지 전부 놓아뒀으니까 얼른 내려와서 같이 먹어요.","내가 다들 기다리게 해 버렸네, 바로 갈게.","새해 복 많이 받아!","하하, 새해 복 많이 받으세요. {name} 씨, 새해에도 건강하고, 원하는 바도 이루고, 국사무쌍도 하시길 바라요.","자기가 보낸 축복이 제때 전달된 걸 확인한 누군가가 지금 꽤 안심한 모양인걸.","하하. 그럼, 그 누군가는 제가 보낸 선물을 받았을까요? 거기에 제 모든 마음이 담겨 있는데 말이죠.","또다시 새로운 해가 찾아왔습니다! 신년을 맞이해 복수쌍전관을 방문할 모든 손님 여러분들께서는 입장료 20% 할인 혜택을 받으실 수 있습니다! 이곳에 오시는 손님들 모두 새해 복 많이 받으시고, 항상 집안에 평안과 행복이 가득하시길 바라고, 모쪼록 건강한 한 해가 되시길 기원하며, 만사형통하시길 소망합니다!","아까 마작장 이름만 다르고 완전히 똑같은 광고를 봤는데 말이야, 설마 그냥 복붙한 다음에 이름만 수정한 거 아니지멍?","그런 것보다는 20% 할인이 젤 중요한 거 아이가?","후지 님, 새해 복 많이 받으시길.","새해 복 많이 받으래이. 그라고 보니까, 미아가 된 삼족오는 언제 데꼬갈낀데? 임마 이거 삐리한 상태로 여서 며칠째 묵고 마시고 있다 아이가.","삼족오가 후지 님께 갔었군요, 며칠간 폐를 끼치게 되어 죄송할 따름입니다. 잠시 뒤에 데리러 가도록 하지요.","마작장 입장료 20% 할인이라니, 작년이랑 똑같은 이벤트로는 경쟁력이 안 생긴다니까요. 다른 혜택은 없어요?","20% 깎아 준 걸로는 부족한 기가? 주판 팅구는 게 여까지 들리네!","왠지 날 가스라이팅하는 게 아닌가 의심되는데, 증거가 없네.","뭐, 니가 오늘 돈을 억수로 마이 써 주믄, 우리야 뭐 생각 몬할 것도 없지.","축복이라곤 하지만 사실상 광고잖아요. 제가 후지 씨를 얼마나 많이 봐 왔는데, 이런 것도 못 알아차릴 것 같아요?","이 쫌 억울하네, 우린 언제나 진심으로 손님들을 축복한다 아이가. 정 몬 믿겠으믄 퍼뜩 우리 마작장으로 와봐라, 그라믄 내가 그대로 읊어 주께.","친척 집에 들렀다가, 어른들한테 세뱃돈을 강제로 받게 되었군……","어른들 눈에 부회장은 여전히 어린애인가 보네, 푸훕……","웃는 소리는 굳이 글자로 안 쳐도 괜찮지 않습니까……","세뱃돈을 받는 건 사람과의 관계에서 유일하게 좋은 일 아냐?","친척집에 놀러갔다고 세뱃돈을 받는 건 초등학생들 뿐이잖아……","우리 부모님한테 은근슬쩍 이 캣챗 보여 줄 방법 없나?!","세뱃돈! 세뱃돈이잖아! 매해 세뱃돈을 받을 수 있다면 난 영원히 17살이고 싶어!","당신의 그 소원…… 정말로 한결같으시군요…… 뭐, 그렇게나 좋아하신다면 제 몫은 당신이 가지셔도 됩니다.","렌은 미성년자니까 세뱃돈을 받는 건 아주 정상적인 일이지. 위로.jpg","평소의 모습으로 보자면, 당신의 정신 연령은 저보다 많이 낮으니까 말이죠. 아무래도 당신에게 줄 세뱃돈을 준비해 둬야 할 것 같네요.","방학 마지막 날이 되어서야 선생님이 내준 깜지 숙제가 생각나서, 하루나는 지금 미친 듯이 숙제를 하고 있어. 그런데…… 하루나가 하루종일 안 보인다면 길고양이들이 걱정할텐데… 몰래 나가서 보고 오고 싶은데, 지금 가도 괜찮을까?","토끼 씨한테 도와달라고 하는 건 어때?","{name}은(는) 깜지 잘 써?","음…… 모모는 잘 모르겠어. 하지만 모모는 토끼 씨가 마작을 잘 치니까, 분명 다른 일도 잘할 거라고 생각해.","방금 우리 엄마가 콜네 엄마랑 통화했는데, 콜은 첫 주에 숙제를 전부 끝냈대.","우아아앗, 그럼 설마 하루나만 숙제하고 있는 거야?","아직 안 늦었을걸?","{name}, 그럼 나랑 같이 갈래? 길고양이들도 널 보고 싶어 하고, 하루나도 방금 엄마가 만들어 준 간식을 가지고 갈 테니까 말이야.","길고양이 군단은 나한테 맡기고, 하루나는 빨리 숙제나 끝내도록 해.","우와, 역시 {name}은(는) 믿음직스러워!","복귀 첫날, 명절 증후군이 시작되어 버렸다.","It is difficult to believe, 오늘 휴가가 끝났다고?","뭐야? 오늘 휴가 끝났다고?","새해 당일엔 인터뷰하고, 다음날엔 원고 작성하고, 그다음 날엔 인쇄까지…… 이게 진짜로 휴일이 맞는 건가……","휴일에 일하는 건 최악이야. 빨리 악덕 사장한테서 떠나도록 해.","에휴, 요즘 착한 사장이 어디 있다고.","오, 선배도 힘들다고 느끼는 일이 있기는 하군요.","하하, 카나는 날 너무 만능으로 생각한다니까.","인생은 짧고 평일은 길다…… 엄청 공감되는걸.","그럼 오늘 퇴근하고 재미있는 일 좀 찾아서 해 볼까? 저녁에 데리러 갈게.","[tag]#공유: [명절 증후군 극복법은??][/tag]","우리 아빠가 보낸 메시지인 줄 알았네. 내가 생각한 것보다 더…… 다양한 범위의 글들을 보는걸.","새해 복 많이 받으시고, 모든 일이 잘 풀리기를 빕니다.","아침부터 절구 방망이를 휘둘렀더니 축구 경기 뛴 것만큼 힘들어졌어.","하하, 고생하네. 다음엔 축구 동아리 멤버를 몇 명 데려와서 도와주도록 할게.","이걸 또 한다고?","큐르! 이렇게나 건실한 내용을 보내다니. 회장, 오늘 뭐 잘못 먹기라도 했어?","???","어제 \'입막음 비용\'은 엄청 맛있었어, 그 일은 리사리사가 반드시 비밀로 할게!","쉬잇…………!!!!","끝이야?","???","역시 진지한 내용에는 진지한 답변밖에 안 달리는 건가…… 아, 역시 난 네 긴 답장이 훨씬 더 좋아.","참고할 만한 새해 인사 문구를 올려 주도록 할게. 새로운 한 해, 언제나 행복하시기를 기원하며, 원하는 바를 이루고, 사업도 꼭 번창하시길 바랍니다! 새해 복 많이 받으시고, 올해도 건강하시고, 모든 일이 원하는 대로 풀리시길 소망하며, 가정에서도 행복하셨으면 좋겠습니다! 삶이 더욱 아름답게 빛나고 언제나 웃을 수 있길 바랍니다. 모쪼록 밝은 새해를 맞이하길!","아하하하, 웃겨 죽을 뻔했네. 복사해서 꼭 참고용으로 써먹을게.","어라? 날짜를 보니까 구정은 이미 지났고, 신정은 아직 안 온 거 아냐?","맞아. 하지만 예약 투고 시기를 잘못 설정했다고 인정하는 것보단, 오늘을 새로운 명절로 정하는 게 더 좋지 않겠어? 우리 둘만 축하하는 거라고 해도 상관없어.","만약 정의의 마녀가 무심코 실수를 저질렀다면, 위대한 정의의 신이 직접 유즈를 마법으로 벌해 주시길…… 물론 치통이 아니라 다른 방법으로……","테이블 위에 떨어진 음식은 3초 내에 주우면 다시 먹을 수 있다고 들었는데 말이다냥……","사, 삼 초? 큐르르, 유즈는 3초룰은 추천하지 않는걸.","병원에 안 가 봐도 되겠어? 선생님이랑 부회장한테는 내가 쉰다고 말해 둘게.","큐르르…… 병원은 필요 없어. 그렇게 심한 것도 아니고……","따뜻한 소금물로 입을 헹구면 치통에 도움이 돼요.","방금 해 봤는데, 확실히 조금 나아졌네.","큐르르, 정의의 마녀는 은혜와 복수의 관계가 분명하지. 그러니까, 고마워.","후후, 전 그저 병에 걸린 레서 판다의 반항은 별로 멋지지 않을 것 같아서 그런 것뿐이랍니다. 그러니 빨리 낫도록 하세요, 스승님께서 저한테 자꾸 약한 사람을 괴롭힌다고 쓴소리하시기 전에 말이죠.","큐르르르…… 화가 나니까 또 이가 아프기 시작했어!!! 역시 토끼 귀에 큰 가슴은 전부 악이야! 이 유즈가 정의를 대표해서 반드시 너한테 심판을 내리고 말겠어, 큐르!!!","내가 알기론, 유즈가 스스로 너무 많이 먹을까 봐 걱정돼서 떡을 전부 치워놨다고 들었다만?","큐르르…… 그건 {name}한테 새해 선물로 주려고 했던 거야.","나는 떡보다는 이 가게의 쇼트 케이크를 추천해. 하지만…… 내 \'얕은\' 지식으로 보자면, 선물을 주는 게 치통을 유발할 것 같지는 않은데?","유즈는 {name}이(가) 마음에 들어 할지 안 할지 몰라서 먼저 맛보려던 거다, 큐르!","치통 때문에 죽지는 않겠지, 죽을 만큼 아프긴 하겠지만. 그러니까 빨리 치료하는 편이 좋아, 시간 내서 같이 병원에 가자.","큐르! 전에 캣챗에서 신경 치료 관련 영상을 봤는데, 큐르르…… 동영상 생각만 했는데도 아픔이 없어진 것 같은 느낌이 들어. 응, 이제 괜찮아졌다고. 안 아픈걸.","\'기도춘\' 근처를 지나다가 \'가출\'한 미미랑 마주쳤다만, 도대체 무엇 때문에 여기로 이끌린 건지 모르겠군.","\'기도춘\'? 음…… 리사리사가 모르는 곳인가? 아마 안에 맛있는 고양이 통조림이 놓여져 있지 않았을까? 뽀요용은 신선한 먹이를 보면 그냥 지나치지 않으니까 말이야.","뽀요용한테 새로운 맛의 고양이 통조림을 사 줘야 하는 것 아닌가.","키사라기 씨…… 죄송하지만 좀 도와주실 수 있나요? 혹시 푸린도 거기에 있나요…… 손님힌테 인사하러 가는 동안, 정원에서 푸린이 사라졌어요……","천월신사의 그 고양이 말입니까? 알겠습니다, 혹시라도 보게 되면 무녀 씨한테 연락하죠.","네가 가출해서 \'기도춘\'으로 갔다고?","……아하, 미미구나. 내가 잘못 봤네.","미미랑 푸린이 동시에 \'가출\'했다고? 오호라, 나 지금 엄청난 비밀을 알게 된 것 같은 기분이 들어.","일단 미미랑 푸린은 둘 다 수컷이라는 사실을 알려드리죠. 정말이지, 매일같이 머릿속에서 무슨 이상한 상상을 하고 있는 겁니까?","아사바 고등학교랑 집은 완전히 반대 방향이잖아. 근데 왜 \'기도춘\'으로 간 거야?","……이쪽에 있는 카페의 케이크가 맛있다고 했던 건 당신이었잖습니까?","이한시의 올겨울이 작년보다 더 추운 것 같은 건 리사리사의 착각이 아니겠지? 으음…… 뽀요용이랑 같이 외투를 꼭 껴입어도, 영하의 날씨에 몸을 떨게 되어 버려.","어려움을 극복하는 것이야말로 사냥터 수련의 핵심이라곤 하지만, 영하의 기온에 아르바이트를 하러 나가는 건 정말 별로야.","에인은 장갑 있어? 올해 뽀요용의 털이 장갑 한 쌍은 만들 수 있을 정도로 많이 빠졌거든.","털이 빠졌다라…… 추운 겨울에 그 소리를 들으니 더 추워지는걸.","그건 착각이 아닐걸……","니노미야, 감기는 좀 괜찮아? 리사리사는 걱정되는걸.","열은 내렸어. 친구들한테 전염시키면 안되니까 좀 지켜보다가 다시 학교에 갈 거야.","엄청 춥지. 여기 벌벌 떠는 사람 한 명 추가요.","늑대 씨도 추워하면 분명 엄청나게 추운 거겠지. 리사리사의 새 외투는 늑대 씨가 들어와도 될 만큼 엄청 커.","추워? 아직은 괜찮은 것 같은데.","으으음, 늑대 씨 말이 맞아. 역시 추위를 느끼는 건 모두 상대적인 거니까. 그래도 늑대 씨의 품은 분명 따뜻하겠지. 늑대 씨를 안아서 따뜻함을 느끼고 싶은데, 괜찮을까?","짜잔~ 옷장에서 3년 전에 산 가방을 꺼내 봤는데, 의외로 지금도 괜찮아 보이는 디자인이더라고. 돈도 아꼈으니까, 새로운 헤어 액세서리를 사러 갈 수 있겠어.","이 가방…… 3년 전에 유행할 때 선생님도 샀던 걸로 기억하는데, 집에 가지고 돌아간 이후로 다시는 본 적 없는 그 가방인걸.","항상 뭔가 찾으려면 꼭 안 보이다가, 나중에 이상한 곳에서 튀어나오기 마련이더라구요. 선생님도 나중에 한 번 시도해 보세요.","음…… 선생님이 해석해 줄게, 못 찾으면 못 찾는 대로 살지 뭐. 라는데.","선배, 어제 촬영은 잘 끝났나요?","물론, 아주 잘 끝났지. 다음에도 이런 쉽고, 페이 좋고, 사진사분이 까탈스럽지도 않은 건이 있으면 나한테 꼭 연락해 줘야 해.","다들 가방에만 집중하는데, 나는 달라. 난 어디로 가야 너와 만날 수 있을지가 더 궁금한걸.","DM 봐봐, 위치는 진작에 공유했었는걸.","내 옷장을 보니까, 아무래도 코디네이터가 필요할 것 같네. 밝고 쾌활하고, 화장도 잘하고, 무엇보다 옷을 사도 3년은 먹힐 것 같은 옷을 사는 사람이 필요해.","Fine, 그냥 내 이름을 직접 말하는 게 어때? 거절하지는 않을 테니까 말이야.","0부터 시작해서 혼천 오르기!","친구 (트롤) 대국, 학살이다!","오늘은 진지하게. (마이크 off, 대화는 화료 속도만 늦출 뿐)","사람이라면, 꿈이 있어야지! (역만의 밤, 무대를 뒤집어 놓으셨다.)","이벤트 게임, 4등 할 때마다 딸랑이 한 명한테 용돈 쏜다.","월말 랭크 업 도전 실패하면, \"링 피트니스\" 매일 세시간 씩 일주일 라이브!","1등 하면 자야지……","일단 마작하고 다시 노래로.","딸랑이 친구들 이제 8강전 해설. 죽음과 눈 맞춤.","피곤해, 이제 영상 보는 타임. 팝콘이랑 음료는 각자 준비.","일 있어서 잠깐 자리 비움. 자기 전에 올 거임.","추억 회상 타임. 옛날 게임 빠르게 도전.","후로 없이 도전, 할 말 있음 해봐 내가 상대해 줄게.","토너먼트 Replay. 우리가, 바로, 챔피언!","냐?! 냐냥?! 이 후원 버튼은 확인 팝업창도 안 뜨는 거냥!!","이치히메의 코인…… 난 후원을 하고 싶었던 게 아닌데… 진짜 별로다냥!","머머멍?! 이게 된다고멍?!","이 몸은 오늘도 눈을 뜬 셈이다멍.","대단한 난장판이 대단히 화려하노라. 이 몸이 좋아는 것이노라. 우히히.","와…… 이 몸은 난쟁이 똥자루에게도 이렇게 악독한 말은 못 하겠노라.","점장이 우리헌티 언어 예술을 배우라 하는디, 도대체 뭣을 배워야 한다냐... 한나는 이해가 안 가는디요……","잘은 모르겄는디, 엄청 대단한 모양이여!","ㅋㅋㅋㅋㅋ 아 엄청 웃기네. 역시 너다.","큰 거 온다! 고고고고, 멈추지마!","오래 기다렸네, 나의 숙적이여. 오늘 밤도 통쾌한 한판이 될거라 믿어!","어떻게 한정 굿즈를 또 봐버린 거지?! 너, 너 도대체 어떻게 찾은 거야……","하하! 여기 진짜 지루할 틈이 없구나!","ohmygrandpa，내가 뭘 본거지?","멍청한 토끼가 맨날 이치히메를 쪼잔하다고 하는데, 이치히메는 쪼잔하지 않다냥!","탕야오는 정의라냥!","진정해라멍, 젊은이는 그렇게 크게 화내면 안된다멍.","우정 후원으로 탁자 사라멍","우히히, 진짜 보기 좋은 장면이었노라.","이건 네가 나를 기쁘게 한 보상이노라, 감사한 마음으로 받도록.","교육비여!","HIBI파이팅! 나쁜 말 하는 사람한테 굴복하지말어!","고마워, 아 덕분에 또 웃었네.","너 진짜… 나 울겠어.","받아라! 내 존경하는 적수여!","시간도 돈도 너무 많이 들어!","Bravo！","CoooooooooooooooooL","리사리사","굳이 끊어내기","일반인","붉은 바람","976net","정의의 마녀","일 없으면 와서 들어","오색찬란한 블랙","소설보는 키위","라떼라떼","HIBI의 테이블","깊은 흑심은 깊은 사랑","귤먹고싶다","닉네임이중복","메이드의 전쟁","게스트 (진짜)","어떻게 바람을 맞혀","밤길걷기","최고 자선가","마음 속 총자루","앞쪽 공격 온다","너무 좋은 패, 재미없네","이해 안 돼","ㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋ","당황하지 마 기술적인 조정이야","으악 눈부셔! 눈멀겠다","이번 달 테이블 주문했음?","만족스럽게 퇴장","패 들어온 거, 신기하네","너 뭔데, 이렇게 하면 안 되지!!","고민은 네 방총 속도만 방해할 뿐이야.","방법이 없네, 계속 고고!","?","????!","굳!","이런, 속아 넘어갔다니.","꿈이 없다면 죽은 거나 다름없지.","탐나.","진짜 너무 따뜻한 사람이야. 난 곧 울듯.","너무 평범하네.","사람이라면 현실을 마주할 줄도 알아야지.","주인공 마성의 매력이 있네.","무뚝뚝하긴, 계속해","대.위.기","온다 온다","너무 세다…","이게 강자의 여유인가…","마작의 신: 돈 더 내.","욕하지 마, 욕하지 마.","더 세게 욕해봐!","영웅은 전쟁터에서 물러날 수 없지!","HIBI, 내 초능력자.","계속 말해라, 다 적고 있으니까.","내가 얕봤어","실례","상가 제대로 조사해 봐","다음 판도 계속해, 내일은 더 좋을 거야.","누가 너한테 용기를 줬어?","전쟁의 신 같아","악플러 말은 그냥 듣고 흘려버려.","멍지로","라면 가게 영업 전략","멍지로가 라면 가게를 열고 싶어하는데, 가격을 정하는 데 어려움이 있는 것 같다. 그의 파트너로서 그에게 의견을 준다면 매우 큰 도움이 될 것이다.","가격 경쟁력","멍지로는 가게에 \"라면 가격 할인\"이라고 적힌 현수막을 내걸었다. 비록 판매량은 많았지만 너무 저렴했던 탓에 본전을 찾지 못했다……","멍지로의 라면은 맛도 가격도 착하다. 아사바 고등학교 입구까지 줄이 길에 늘어섰고, 질서를 위해 학생회에서는 얼른 인원을 동원해야할 것 같다. 멍지로는 짭짤한 수익을 얻었다.","고급화 전략","미식가들은 맛있는 라면 위에 굳이 이상한 맛이 나는 풀을 장식으로 올렸다고 생각했다. 맛도 별로고 가격도 비싸니 이 라면가게에 와서 손해보지 말라는 이야기가 돌았다.","맛있는 라면 위에 귀여운 고양이 발바닥 장식이 올라가있다. 한 입 먹어보니, 어랏! 망고스틴이잖아! 신선한 망고스틴의 달콤함이 라면의 맛과 합쳐지면서 색다른 맛을 만들어냈다. 순식간에 입소문을 타며, 가게 안은 손님으로 가득찼다.","쿠죠 리우","카페 마케팅 전략","쿠죠 리우는 축제 기간동안 카페를 열고 싶어한다. 하지만 음식을 판매하는 가게들과의 경쟁이 너무나 치열하다. 어떤 컨셉으로 카페를 열어야 손님을 끌어들일 수 있을까?","고양이 카페","커피를 마시며 고양이와 함께 노는 건 행복한 일이라는 생각이 들었고, 쿠죠 리우는 이 생각에 강력히 동의했다. 모든 준비는 완료 되었는데… 고양이는 어디서 구하지? 이치히메를 떠올릴 수 밖에 없었으나, 자신은 고양이 귀를 가진 인간이라고 강하게 주장하며 거절을 했다.","쿠죠 리우는 Éternité에서 임시로 순하고, 사람을 좋아하고, 심지어 재주도 부릴 줄 아는 고양이들을 빌려 오기로 했다. 고양이 카페는 고양이를 좋아하는 사람들에게 폭발적인 인기를 끌었고, 놀랄만한 수익을 얻을 수 있었다.","메이드 카페","메이드 카페의 직원들이 너무 귀여웠던 탓에 함께 사진을 찍고 싶어하는 손님들로 인해 가게 안이 붐비기 시작했고, 금세 혼란스러워졌다. 쿠죠 리우는 한숨을 쉬며 이 사람들을 어떻게 음식 부스로 옮길지 고민하기 시작했다.","자, 이게 바로 특별 교육을 받은 전문 메이드가 만든 핸드드립 커피입니다! 풍부한 향, 부드러운 바디감, 입안 깊이 남는 커피의 맛이 메이드 카페의 높은 수준을 증명해주었다. 덕분에 금방 입소문을 탔고, 매출은 수직 상승했다.","니카이도 미키","미식 교류회","자신이 정성 들여 만든 요리에 아무도 관심을 보이지 않아 고심하던 니카이도 미키는 축제를 기회삼아 미식 교류회를 열고 모두를 시식에 초대하기로 했다. 그녀는 교류회에서 어떤 요리를 선보이면 좋을지 의견을 묻는다.","니카이도 특선 요리","니카이도 미키는 자신 있어하는 방울토마토 딸기 마파두부를 선보였다. 그녀는 방울토마토의 산미와 딸기의 단맛이 마파두부의 매운맛을 완벽하게 중화할 수 있다고 생각했다. 하지만 시식회가 끝난 후, 요리를 먹고 나서 세상이 빙글빙글 도는 것 같은 어지럼증을 느꼈다는 불만이 많이 접수됐고… 보건실은 사람들로 가득 찼다. 니카이도 미키는 요리 솜씨가 형편없다는 비판을 담은 쪽지도 받았다. \"매운맛은 미각이 아니라 통각이라고!!!\"","니카이도 미키는 며칠동안 공들여 연구한 구운 초콜릿 오징어 먹물 가지를 꺼냈다. 그녀는 검은색 음식은 머릿결을 좋게 하고, 노화를 늦추고, 패운을 좋아지게 한다고 생각했다. 뜻밖에도 이 \'명품 요리\'는 열광적인 반응을 불러일으켰다. 비록 호기심과 타인에 대한 복수심 덕분이긴 했지만, 어쨌든 성공을 거두었다…","평범한 가정식 요리","니카이도 미키는 실수하기 어려운 클래식한 요리, 달걀 볶음밥을 선보였다. 하지만 어째서인지 이 달걀 볶음밥은 어두운 기운을 내뿜는 것 같아서, 미식 교류회에 온 사람들 모두 도전할 용기가 나지 않는다고 했다. 하루가 지났지만, 미식 교류회에서 미식 교류는 단 한 번도 일어나지 않았다.","니카이도 미키는 치킨 카레 덮밥을 선보였다. 밥 위에 덮인 치킨과 카레는 모두 구입한 것이고, 자신은 단지 데우기만 했다고 여러 번 설명했지만, 여전히 아무도 관심을 보이지 않았다. 마침 학교로 몰래 들어온 불량배 무리가 부스 앞을 지나갔고, 공짜 음식인 걸 알고서는 입에 마구 집어넣기 시작했다... \"바, 밥에 독이 들었어!\" 그들이 병원으로 실려 가기 전에 남긴 마지막 말이었다.","낮잠 파티","축제 날에도 어김없이 출근해야하는 보건 선생님 키사라기 아야네는 잠을 자면서 돈을 벌고 싶어 하는 아르바이트생들을 위해 낮잠 파티를 열기로 했다. 그런데 파티 참가자들을 어떻게 재우지?","직접 ASMR하기","키사라기 아야네는 목소리를 낮추었다. 부드럽고 달콤한 목소리가 왼쪽 이어폰을 통해 들려왔다 \"자장, 자장……\" 그 후로 아무 소리도 나지 않았다. 어떤 세심한 사람은 그녀가 자기 스스로를 재웠다는 걸 눈치챘다.","키사라기 아야네는 의외로 ASMR에 뛰어난 재능을 가지고 있었다. 그녀는 참가자들에게 베개를 누르는 소리, 주사기 속 액체를 짜는 소리, 청진기로 증폭된 자신의 심장박동 소리 등을 들려주었다... 참가자들은 마치 엄마 품에 안긴 것 같은 평온함을 느끼며 깊은 잠에 빠졌고, 코골이 소리가 이어졌다.","키사라기 렌의 회의 녹음 틀기","뜻밖에도 이 녹음은 매달 열리는 \'문제아\' 비판 회의의 녹음 파일이었다. 모두가 키사라기 렌이 학교 안의 \'유명 인사들\'이 최근 어떤 말썽을 부렸으며, 어떤 시험 과목을 망쳤는지 설명하는 내용을 흥미롭게 들었다. 모두 이런 녹음 파일을 더 들려달라며 열광했고, 아무도 잠들지 않았다.","\"간단히 세 가지만 말씀드리겠습니다...\" 이 말은 참가자들의 DNA를 건드리기라도 한듯 강력한 관성에 이끌려 미리 준비해 둔 낮잠 매트 위로 줄줄이 엎드러졌다. 모두가 깊은 잠에 빠졌고 뒤이어 코골이 소리가 들려왔다.","유즈","정의의 제재","정의의 마녀 유즈가 축제 보안 임무에 자원했다. 의심스러운 사람을 만났을 때, 유즈는 어떤 태도로 대응하는 게 좋을까?","엄격하게","유즈와 레서판다즈는 자신과 타인에게 엄격하자는 원칙에 입각해 잘못을 저지른 사람을 절대로 봐주지 않았다. 추격 과정에서 유즈는 부스 여섯 개, 꽃마차 두 대, 노인 한 명을 넘어뜨렸다... 유즈는 지금 학생회 사무실에서 꾸중을 듣고 있다.","유즈와 레서판다즈가 축제를 망치려는 장난꾸러기 학생들에게 심판의 주먹을 연달아 내리꽂은 덕분에 축제 현장에는 정의와 절대적인 질서만이 남았다.","친절하게","유즈가 레서판다즈와 축제 현장을 돌아다니자, 그들의 지나친 친절함에 사진을 찍으려는 구경꾼이 수도 없이 몰려들었고, 현장에는 오히려 소란이 일었다.","유즈와 레서판다즈는 너그럽고 친절한 태도로 장난꾸러기 학생들을 변화시키려 했다. 이 방법은 성공을 거두었을 뿐만 아니라, 새로운 정의의 사도들까지 확보하게 되어 더욱 멋진 순찰대를 탄생시켰다.","카구야히메","제안이 아닌 명령","카구야히메는 축제를 찾는 방문객들에게 신을 섬길 기회를 주고 싶다며 당신에게 명당자리를 마련해 달라고 요청한다.","승낙한다","뜻밖에도 카구야히메는 공물에 있어서 매우 까다로웠고, 보석 외에는 아무것도 마음에 들어 하지 않았다. 카구야히메는 하루 종일 공물을 하나도 받지 못했다. 그녀는 추천해준 자리의 풍수가 나쁘기 때문이라고 결론지었다. 당신에게 벌을 주기 위해, 카구야히메는 당신이 갓 산 치즈 빵 속의 치즈를 모두 겨자로 바꿔버렸다.","첫 번째로 공물을 올린 당신은 토끼 귀를 만질 수 있게 되었다. 그런데 예상 밖에도 저주 효과가 발생해서, 당신에게 진짜 토끼 귀가 생기고 말았다. 사람들은 이를 부러워하며 똑같은 토끼 귀를 갖고 싶어 했다. 그렇게 카구야히메 앞에 긴 줄이 이어졌지만, 신의 총애는 언제나 단 한 사람에게만 주어지는 것. 결국 당신은 뜻하지 않게 이번 축제의 중심인물, 유일한 토끼 귀 천사가 되었다.","매우 기쁘게 승낙한다","명당을 찾은 당신은 카구야히메를 한참이나 기다렸지만, 그녀는 하루가 지나도록 나타나지 않았다. 이치히메에게 그녀가 옆에 있는 부스에서 이치히메를 괴롭히고 있다는 고자질을 들었고, 그 고자질을 듣고 나서야 카구야히메가 당신과의 약속을 잊어버렸다는 걸 알게 되었다.","공물을 바치러 온 사람들이 다양한 공물을 들고 길게 줄을 섰다. 모두가 공물을 바치고 귀여운 토끼 귀의 신을 보는 것을 진심으로 원하는 모양이다.","엘리사","목장 지식 강좌","엘리사는 축제에서 모두에게 자신의 고향을 소개하고 싶다. 하지만 강연 시간은 제한되어 있다. 어떤 부분을 중점적으로 추천해야 할까?","아름다운 초원","엘리사가 두 번째 파트 \'아름다운 초원, 나의 집\'에 대해 이야기할 때, 뽀요용이 앞에 앉은 선생님의 가발을 잡아당기고 물어 뜯는 바람에 강좌가 강제로 중단되고 말았다.","엘리사의 설명은 청중들에게 마치 그 현장에 있는 듯한 느낌을 주었다. 배경 음악 속 테너 파트가 부르는 \"나에겐 보이지 않는 날개가 있어\"의 부분에서 현장의 분위기는 최고조에 달했다. 모든 사람들이 엘리사가 말하는 아름다운 목장 생활을 점점 더 동경하기 시작했다.","새하얀 양 떼","세 번째 파트 \"목장의 갓 태어난 어린 양 떼\"에 대해 이야기할 때, 지나치게 진지해진 엘리사가 어린 양의 이름을 전부 나열하는 바람에 청중들은 졸기 시작했다.","뽀요용이 무대 위에서 엘리사의 연설에 맞춰서 보여준 순하고 귀여운 모습은 사람들의 이목을 끌었다. 사람들은 현대 사회에서 최고의 반려동물은 사실 어린 양이라고 표현했다. 축제에서는 \"인생의 세 가지 과업은 밥 먹고, 잠자고, 뽀요용 쓰다듬기다\"라는 말까지 유행하기 시작했다.\"","카비","패배의 조짐","카비는 고민에 빠졌다. 모두의 주목을 받는 운동선수가 그녀에게 경기 결과를 물어봤기 때문이다. 주변을 둘러싼 사람들의 기대섞인 눈빛에 카비는 그녀가 본 패배의 조짐을 말하기 어려워졌다. 사실대로 말해야할까?","숨긴다","카비는 선수의 경기에 영향을 미치고 싶지 않아서 진실을 숨기기로 했다. 운동선수는 승리를 거머쥔듯 점술 결과에 기삐했다. 하지만, 뜻밖에 경기에서 방심하며 연속으로 패배를 거듭했고 , 점괘를 믿으면 안됐다며 슬퍼했다.","카비는 결국 자신이 본 패배의 조짐을 말하지 않았다. 선수는 심리적 압박 없이 경기에 나설 수 있었고, 매우 치열한 경기를 치렀다. 비록 상대에게 아쉽게 패하긴 했지만, 해당 경기에서 보여준 멋진 플레이는 명장면에 뽑히면서 많은 스포츠 팀의 러브콜을 받았다.","말한다","카비는 진실을 말했고, 운동선수의 열정은 사라져버렸다. 이후 훈련을 하면서도 패배에 대한 생각과 자신을 응원해주는 사람들을 실망시킬 거라는 생각을 떨칠 수 없었다. 결국 심리적 압박으로 인해 경기에서 물러날 수 밖에 없었다.","카비는 진실을 말했고, 주변은 순식간에 조용해졌다. 그러나 운동선수는 카비의 일깨워줌에 고마워했고, 미소와 함께 자신은 포기하지 않을 거라며 주변 사람들을 안심시켰다. 경기에서 전력을 다해 싸웠지만 패배를 했다. 하지만 이후 패자 부활전에서 승리하며 다음 경기 진출 자격을 획득했다.","후지타 카나","노래와 춤, 아니면 게임","후지타 카나가 학교 축제의 저녁 파티 공연에 초대받았다. 그녀는 자신이 잘하는 노래와 춤을 보여주는 게 좋을지, 아니면 새로운 모습을 보여주는 게 좋을지 묻는다.","노래와 춤","무대 위의 후지타 카나는 여느 때와 마찬가지로 빛났고, 형광봉, 응원 용품 등을 파는 축제 부스의 수익까지 이끌어 냈다. 하지만 그녀가 평소 보여주는 무대와 별반 다르지 않아서, 사람들에게 특별한 추억을 남기지는 못했다.","축제 무대의 장비에 원인 모를 문제가 발생해 음악이 뚝 끊기고, 무대 조명도 갑자기 꺼졌다. 하지만 후지타 카나의 빛나는 모습은 그런 상황에서도 사라지지 않았다. 관객들은 그녀의 외침에 따라 휴대폰의 플래시를 켜고 그녀와 합창하기 시작했다. 모두에게 특별하고 잊을 수 없는 밤이었다.","무대에서 게임 라이브 방송","축제 무대의 대형 스크린에는 후지타 카나가 플레이하고 있는 게임 화면이 송출됐다. 그녀의 캐릭터가 사망하자 무대에서 분노의 외침이 울려 퍼졌는데, 그 소리가 너무 우렁찬 나머지 관객들은 잠시 당황하고 말았다. 후지타 카나는 곧장 평소의 목소리와 미소를 되찾았지만, 당일 \'후지타 카나, 우렁찬 남자 목소리\'로 인기 검색어를 장식했다.","축제 무대의 대형 스크린에는 후지타 카나가 플레이하고 있는 게임 화면이 송출됐다. 그녀는 섬세한 컨트롤과 센스있는 플레이를 자랑하는 동시에 관객들과도 소통하며 프로그램의 효과를 극대화했다. 팬들은 이런 새로운 형식의 팬미팅은 처음이라며 감탄했다. 더 중요한 것은 자신의 아이돌이 알고 보니 게임 고수였다는 사실이었다!","모리카와 아야코","옛 학교 건물의 친구","모리카와 아야코는 옛 학교 건물의 친구들을 축제에 초대하고 싶다며, 당신의 동의를 구한다.","동의한다","학생회에 많은 민원이 접수되었다. 물건이 갑자기 사라지거나, 이유 없이 넘어지거나, 볶음밥을 먹다가 목에 걸리거나, 차가운 물을 마시다가 체하거나... 모두가 옛 학교 건물의 유령들이 사람들을 상대로 꾸민 장난이라고 생각해, 유령을 봉인할 퇴마 의식을 열어달라고 요구했다.","사회 공포증을 가지고 있는 모리카와 아야코는 곁에 \'친구\'가 많아져 훨씬 편안해 보였다. 그녀는 사람들로 붐비는 축제에서 보기 드문 달콤한 미소를 지었고, 이 장면은 누군가의 손에 사진으로 찍혀 학교 게시판에 올라갔다. 많은 사람들이 사진의 주인공이 누구인지 묻는 댓글을 달기 시작했고, 아사바 고등학교의 축제에는 자발적인 행사, \'신비한 미소녀 찾기\'가 시작되었다.","동의하지 않는다","사회 공포증을 가진 모리카와 아야코는 축제 한 구석에 홀로 앉아 있었다. 하나코, 레이코, 사다코가 그녀 곁에 있었지만, 그녀의 불안함을 해소시켜 주지는 못했다. 축제에서는 유령 소녀의 왼손에 닿기만 해도 저주를 받게 되어 한 달 내내 방총당한다는 이야기의 괴담이 돌기 시작했다.","모리카와 아야코가 혼자서 축제에 참여하는 게 불안해서 그런다는 걸 알고 있었기에 옛 학교 건물의 친구들을 축제에 초대하는 대신 직접 그녀와 함께 축제에 참여하기로 했다. 두 사람은 운이 필요한 모든 게임 부스에서 기적을 만들어냈고, 모리카와 아야코는 당신이 곁에 있어서 좋은 운이 따르는 거라고 말했다. 이날 하루 아주 많은 수확을 얻을 수 있었다.","후지모토 키라라","축제 메이크업","어떤 스타일의 축제 메이크업을 고를지 고민하던 후지모토 키라라가 두 가지 스타일의 메이크업 사진을 보내왔다. 둘 중 어느 쪽을 골라볼까?","자연스러운 메이크업","당신이 선택한 자연스러운 메이크업을 하고 축제를 찾은 후지모토 키라라는 다른 소녀들은 전부 심혈을 기울여 개성 넘치는 스타일로 꾸미고 왔다는 걸 알았다. 주변의 소녀들을 본 후지모토 키라라는 갸루의 자존심을 지키기 위해 급하게 메이크업을 수정해야 했고, 결국 축제의 화려한 공연을 놓치고 말았다.","후지모토 키라라의 자연스러운 메이크업은 축제에서 많은 감탄을 자아냈다. 여고생의 풋풋하고 순수한 분위기가 물씬 풍기는 청순 메이크업이 그녀의 뛰어난 화장 기술을 드러냈다. 그날 그녀는 학교에서 눈부신 주목의 대상이 되었다. 모든 게 옳은 선택을 해준 당신 덕분이었다.","화려한 메이크업","축제 당일 후지모토 키라라는 의장대 멤버로 등장했다. 소박한 교복에 지나치게 화려한 메이크업을 하고 나타난 그녀는 다른 멤버들과 전혀 어울리지 않았고, 심지어 사람들의 관심을 끌려는 목적 아니냐는 의심까지 받았다. 평소 털털하던 그녀도 이번만큼은 마음이 상해 혼자서 휴게실로 숨어버렸다.","아사바 고등학교 학생들의 생기발랄하고 다채로운 생활을 보여주기 위해, 축제에는 특별히 패션쇼가 준비되어 있었다. 화려하면서도 대담한 메이크업을 한 후지모토 키라라는 담당자의 눈에 띄어 메인 모델로 선정되었고, 그녀는 갸루의 길을 모두에게 완벽하게 선보였다.","이치히메","대식가 도전냥","이치히메의 대단한 실력으로 이번 대식가 도전 규칙이 특별히 변경되어, 상위 다섯 명이 릴레이 방식으로 이치히메에게 도전하게 되었다. 놀란 이치히메는 이미 타코야키를 여러 접시 먹어 치웠다. 빨리 대책을 세우지 않으면 타코야키 부스의 재고가 바닥날 거다.","이치히메는 할 수 있다","상위 다섯 명의 도전자들이 각자 자신 있는 음식을 선택했다. 맵고 뜨거운 냄비 요리, 8시간 동안 얼린 수박, 대게 찜 등등... 이치히메는 뜻밖에 세 번째 릴레이 주자의 차례에 복통을 호소하며 병원으로 실려갔다. 이런 식으로 먹다가는 강철로 만든 위에도 구멍이 날 거다냥!","이치히메의 위가 블랙홀과 연결되어 있다는 사실은 더 이상 비밀이 아니었지만, 당신은 혹시 모를 상황에 대비해 경기에 사용될 음식이 안전한지 한 번 더 검사했다. 결국 이치히메는 모두의 기대를 저버리지 않고 우승을 차지했다. 경기가 끝난 후 그녀가 당신을 만나자마자 한 첫마디는 바로 \"주인아, 주인아! 간식 선물 세트 가지고 왔냥? 이치히메 배 고프다냥.\"","반드시 참가할 필요는 없다","뜻밖에도 이번 대회를 위해 3일 전부터 아무것도 먹지 않았던 이치히메는 대회에 참가할 수 없게 되자, 타코야끼 부스에 있는 타코야끼를 전부 먹어치웠고, 당신은 결국 판매자의 눈물 공세를 받으며 돈을 지불할 수밖에 없었다... 얼마나 들었냐고? 당신은 덤덤하게 말했다. \"앞으로 석 달 동안은 손가락만 빨아야 할 정도지. ”","\"심사위원은 심사위원석에 앉아야지.\" 당신의 설득에 이치히메는 더 이상 대회에 참가하지 않기로 결정하고, 이번 대회의 심사위원이 되었다. 다섯 명의 뛰어난 대식가 선수들과 단순히 맛있는 요리를 전부 맛보고 싶은 마음으로 대회에 참여하기 시작했던 이치히메 모두에게 더 아름다운 결과였다.","야기 유이","과학 강연 주제","학생회의 부탁을 받아, 축제 기간 중 야기 유이는 과학 강연을 열어 달라고 부탁했다. 하지만 어떤 주제로 강연을 해야 좋을지 정하지 못하고 있는데, 강연을 열어달라고 부탁했으니, 어떤 주제를 정하면 좋을지 같이 생각해보자.","어떤 타일을 버릴까? - 축제 버전","야기 유이는 참신한 주제로 강연을 열겠다는 마음가짐으로 강연에 임했다. 그녀는 많은 주제를 준비했고, 이는 관중들의 열띤 토론을 이끌어냈다. 그러나 그녀의 목소리가 너무 작았던 나머지, 관중들의 목소리에 묻히고 말았고, 강연은 혼란스러워졌다.","비록 야기 유이는 자신의 마작 실력이 강연을 할 정도는 아니라고 생각이 되었지만, 당신의 판단을 믿기로 했다. 현장에서 여러번 1위를 차지하며 관객들의 열정이 타올랐고, 박수 소리가 울려퍼졌다. 착각인지는 모르겠지만, 야기 유이의 얼굴이 조금 빨개진 것 같기도 했다.","관측자 효과","과학 이론 지식은 고등학생들에게 조금 심오한 주제였기에, 강연을 들으러 온 학생은 많지 않았다. 몇 분 후, 강의실은 낮잠 파티의 새로운 거점이 되었다. 당신을 조용히 바라보는 야기 유이의 눈빛에서는 왠지모를 비난이 느껴졌다.","강연은 성공적이었다. 유이의 명료한 설명이 과학 이론과 마작 경기와 함께 어우러지며 진지하게 배우고자 하는 학생들을 끌어들였다. 학교의 관리자들도 매우 만족해하며, 아사바 고등학교에서 강좌를 10회 더 열기로 결정했다.","로봇 대항전","축제에서 로봇 대항전이 개최되었고, 미라이도 특별 초대를 받아 참가하게 되었다. 하지만 미라이는 자신의 과학 연구와 실습 능력이 다른 학생들보다 훨씬 뛰어나기에, 대회에서 일부러 실력을 조금만 발휘해야 할지 고민하고 있다.","실력을 10%만 발휘하기","미라이는 로봇을 10%만 충전했고, 경기는 시작하자마자 끝나버렸다. 다른 참가자들은 일부러 실력을 발휘하지 않은 미라이의 행동은 자신들과 경기를 존중하지 않은 거라며, 미라이의 참가 자격을 취소해 달라고 요구했다.","미라이는 자신이 경기에서 이기는 것보다 다른 학생들에게 승리의 기쁨을 느끼게 해주는 게 더 중요하다고 생각했다. 그래서 농담도 할 줄 알고, 어려운 질문에도 대답할 수 있는 커뮤니케이션 능력을 가진 로봇을 가지고 왔다. 경기는 예상외로 치열하게 진행되었고, 경기장 주변은 구경꾼들로 가득 찼다. 경기가 끝난 후 모두가 좋은 친구가 되었다.","최선을 다하기","미라이는 로봇 대항전에서 자신의 실력을 마음껏 발휘하기로 결심하고, 가장 자랑스럽게 생각하는 전투 로봇 \'학살자\'를 들고 나왔다. 미라이는 \"그런데 \'학살자\'는 한 가지 센스 있는 기능이 있어요...\" 라고 말을 마치자마자 미소를 지으며 적극적인 지원자 한 명을 골라 무대로 올라오게 했다. \'학살자\'는 그 학생을 공주 안듯 앞으로 안아 올린 뒤, 모든 청중들이 들을 수 있게 큰 소리로 외쳤다: \"BMI 28.9, 과체중입니다!\" 정말 다양한 의미로 \'학살자\'였다.","미라이는 로봇 대항전에서 자신의 실력을 마음껏 발휘하기로 결심하고, 가장 자랑스럽게 생각하는 전투 로봇 \'Love&Peace\'를 들고 나왔다. 키가 2미터에 달하는 \'Love&Peace\'는 멀리 있는 적을 상대하기 위해 적을 자동 추적하는 미사일을 탑재했으며, 가까이 있는 적을 상대하기 위해 상대가 피할 수 없는 강한 자성이 있는 자석과 고온의 화염방사기를 갖추고 있다. \'Love&Peace\'가 무대에 오르자, 누구도 감히 도전하지 못하고 하나둘씩 대회에서 물러났다. 하지만 로봇의 이름에 담긴 아름다운 의미처럼, 축제의 치안은 훨씬 좋아졌다.","인술 연습","많은 사람이 모이는 축제 기간은 흔치 않은 인술 훈련의 기회다. 란세이는 성공한다면 자신에게 소고기 열 조각을 추가한 초호화 라멘 한 그릇을 보상하기로 결심했다. 이에 그녀는 특별히 스승님께 조언을 구하러 왔다. 어디서 훈련하는 게 제일 효과적일까?","카비의 점술 부스 아래","엄격한 훈련을 받은 닌자 란세이는 은신하는 동안 아무리 웃긴 일이 있어도 웃지 않는다. 참을 수 없는 정도가 아니라면... \"슈퍼히어로는 타이츠 안에 팬티를 또 입나요?\", \"전선과 접지선이 동시에 물에 빠졌을 때 뭐부터 건져야 하나요?\" ...점술을 보러 온 사람들은 카비에게 이상한 질문만을 해댔고, 탁자 아래에 숨어 있던 란세이는 결국 참지 못하고 웃음을 터뜨리고 말았다... 훈련은 실패였다.","가장 위험한 곳이 바로 가장 안전한 곳이다. 사람들로 북적이는 인기 만점 점술 부스는 란세이에게 조금도 긴장을 풀 기회를 주지 않았다. 란세이는 은신술을 사용해 탁자 아래에 몸을 숨기고 조심스럽게 숨을 쉬며, 곧 먹게 될 라멘 속의 소고기를 먼저 먹을지 마지막까지 남겨둘지 고민하는 데 집중했다. 하루가 지나갔고, 당신을 제외하고는 누구도 그녀의 존재를 알아채지 못했다.","유즈의 레서판다즈 가운데","란세이는 변신술을 사용해 유즈의 레서판다즈 가운데로 섞여 들어가는 데 성공했다. 여정 내내 귀여운 레서판다들이 사람들의 시선을 끌어모았지만, 다행히 란세이는 발각되지 않았다. 란세이가 기뻐하며 자신에게 초호화 라멘을 상으로 내리려던 찰나, 캣챗에 사진 한 장이 올라왔다... 란세이는 미소녀로 변신하는 데 너무 익숙한 나머지 사진 속에서 습관적으로 미니 스커트를 입은 채 레서판다로 변신해 있었다.","란세이는 변신술을 극한까지 사용하면 \'세속의 은둔자\'가 될 수 있으며, 이것이 바로 최고의 은신술이라고 생각했다. 란세이는 주로 인간으로 변신했지만, 이번에는 작은 동물로 변신해 보고 싶었다. 란세이는 닌자술 발동 후, \'펑\' 소리와 함께 레서판다가 되었고, \'숑\' 하고 유즈의 순찰대에 빠르게 합류했다. 엉덩이를 들고 꼬리를 흔드는 동작이 다소 서툴렀지만, 어쨌든 성공이었고, 유즈의 뒤를 따르는 레서판다가 네 마리가 되었다는 사실을 누구도 알아차리지 못했다.","니노미야 하나","책 교환 행사","니노미야 하나는 축제에서 안 읽는 책 교환 프로그램을 진행하고자 한다. 실명제가 좋을까, 아니면 익명제가 좋을까?","실명제","어째서인지, 모두들 <모의고사 모음집>, <초고난도 수학 문제 100선>, <용감하게 언어와 인사하기>와 같이 학교에서 흔히 볼 수 있는 책들을 교환하려고 했고, 참가자도 소수에 불과했다. 니노미야 하나는 꽤 곤혹스러워졌다.","책 교환 활동은 실명제로 진행되어서, 책을 제출하고 받는 사람들은 모두 자신의 이름을 기록해야 했다. 이런 교환 방식이 참여 인원 수와 열정에 다소 영향을 미쳤을 수 있지만, 그래도 많은 사람들이 이 프로그램을 통해 취미와 관심사가 같은 친구들을 찾아내는 데 성공했다. 어쨌든 자신이 추천한 무언가가 상대방에게 긍정적인 피드백을 받는 건 기쁜 일인가보다.","익명제","익명제는 학생들의 열정을 끌어올렸지만, 동시에 혼란도 가져왔다. 제출된 책들은 아주 다양했으며, 마치 모두가 다른 사람들에게 자신의 특별한 취향을 보여주고 싶어 안달 난 것처럼 보였다. 일부 독자들은 자신에게 새로운 세계의 문이 열렸다고 했지만, 대다수는 여전히 납득하기 어려워했고, 결국 이번 활동은 학생회의 긴급 투입으로 종료되었다.","실명제는 공유라는 행위를 지나치게 투명하게 만들기 때문에, 니노미야 하나 역시 어느 정도 프라이버시를 유지하면 자신과 같이 내성적이지만 공유를 즐기는 학생들의 용기를 북돋울 수 있다고 생각했다. 많은 학생들이 이번 공유 행사를 통해 자신의 취향을 벗어나 더욱 마이너하고 개성 있는 책들과 접촉할 수 있었다. 모두가 행사에서 즐거움을 얻는 것을 보며, 니노미야 하나는 이전에는 없었던 만족감을 얻을 수 있었다.","링랑","시식 심사위원","링랑은 이 축제에서 오로지 요리 대회의 심사 위원이 되는 것만을 바랄 뿐 다른 소원은 없다며, 기회를 달라고 말한다.","승낙한다","링랑은 소원대로 요리 대회의 심사위원이 되었지만, 생각처럼 공정하지는 않았다. \"미국식 스테이크, 10점! 부대찌개, 10점! 오므라이스, 10점! 사천식 돼지고기 볶음, 10점! 표고버섯 덮밥, 마이너스 점수, 탈락!\" 링랑의 점수는 결국 무효로 처리되었지만, 참가자들에게 이번 요리 대회가 전문성 없는 대회였다는 인상을 남겼다.","링랑의 평가가 상상한 만큼 가치 있거나 전문적이지는 않았지만, 시식하는 동안 링랑이 보인 푹 빠져들은 듯한 표정, 놀라운 섭취 속도, 그리고 아낌없는 칭찬은 대회 참가자들에게 다른 종류의 심리적 만족감을 선사했으며, 심지어는 대회에서 상을 받은 것과 같은 성취감을 줬다. 대회가 끝난 후에도 많은 사람들이 링랑에게 음식을 가져다주며, 음식을 즐기는 그녀의 표정을 보고 싶어 했다.","거절한다","링랑은 시식대에서 가장 가까운 관객석에 앉았고, 심사위원이 젓가락으로 음식을 집어 입에 넣을 때마다 \"그건 무슨 맛이에요?\", \"맛있어요?\"와 같은 당황스러운 질문을 퍼부었다. 심사위원들은 링랑의 순수하고 사랑스러운 눈빛에 음식을 혼자 먹을 수 없었고, 결국 음식들은 모두 링랑의 입으로 들어갔다. 심사위원들은 음식을 맛보는 링랑의 표정을 바탕으로 추측한 평점을 제공했다.","요리 대회의 테마가 공개되었다. 이한시의 표고버섯 재배지로부터 후원이 있었기 때문에 이번 요리 대회에서는 해당 재배지에서 생산된 표고버섯을 사용해야 했다. 테마를 확인한 링랑은 표고버섯이라는 식재료에 대한 경멸을 표했고, 당신의 결정에 대해서도 이해와 동의를 전했다. 그리고는 돌아서서 다른 미식 부스로 가 지난 몇 주 동안 모은 돈을 털어 실컷 먹기 시작했다.","테라사키 치호리","뉴스 기획","테라사키 치호리는 학교 축제에 대한 특집 보도를 하려고 한다. 하지만 한 섹션의 주제를 정하지 못해 당신에게 의견을 구하려고 한다.","가장 인기 있는 이벤트","범상치 않아 보이는 두꺼운 봉투를 받아보니, 그 안에는 치호리가 직접 손으로 작성한 80장의 축제 활동에 대해 다양한 측면에서 연구한 설문조사가 들어있었다. 그녀는 당신을 특별 기자로 초청해 아사바 고등학교에 설문지를 나눠달라고 요청했다. 하루 종일 바쁘게 움직이고 나서야 이 편집장이 당신을 무료 노동력으로 사용했다는 생각이 들었다.","테라사키 치호리는 당신에게 축제에서 가장 인기있는 이벤트를 다각도로 분석한 보고서를 보냈다. 첫 번째로 인기 있던 이벤트는 후지타 카나의 공연이었고, 두 번째는 쿠죠리우의 카페가 이름을 올렸다. 이 보고서는 이후 축제 계획에 있어 훌륭한 참고 자료가 될 것 같다.","미소녀가 가장 많은 이벤트","테라사키 치호리는 자세한 보고서를 보내왔고, 거기에는 각 이벤트에 참여한 미소녀의 수와 데이터가 파이 차트로 기록되어 있었다. 그와 함께 당신에 대한 정보, \'여색을 밝힌다\'도 조용히 기록해두었다. 알게 모르게 당신은 치호리의 뉴스의 새로운 소재가 된것 같다.","테라사키 치호리가 자세한 보고서를 보내왔다. 보고서를 받은 뒤 \"미소녀가 가장 좋아하는 이벤트\"에서 1위를 차지한 이벤트부터 직접 조사했고, 데이터 뒤에 숨겨진 정보까지 발로 뛰며 조사했다. 결국 홍보 방식 개선과 참여자 취향에 맞도록 이벤트를 업그레이드하여 많은 양의 축제 자금을 얻을 수 있었다.","학생회 멤버","과학 대중화에 필요한 축제 자금이 부족하고, 청중들이 앉을 자리도 부족합니다. 회장님께서 직접 만든 디저트를 맛볼 수 있을지는 당신에게 달려 있습니다.","보통으로 주기","더 많이 주기","오늘 수업 없음","오락 이벤트 부스의 인기가 엄청나요! 더 많은 자금을 제공해 주신다면, 학생들이 더욱 신나게 놀 수 있을 거예요!","나는야 정의의 사도","축제 행사가 다양하고 여기저기에 재밌는 게 많아서, 눈이 어지러울 정도로 돌아다니는 사람이 많습니다. 보안 요원을 더 많이 배치해 주세요!","소규모 보안 요원 추가 투입","대규모 보안 요원 추가 투입","방총은 끝이 아니다","올해 축제에서 열리는 마작 대회는 어떤 모드로 진행되나요?","오락 모드","경쟁 모드","모험 채널 팬","드디어 오늘이군요. 스포일러 부탁합니다. 보물찾기 이벤트 장소는 강의동인가요, 아니면 학교 전체인가요?","강의동","학교 전체","축제 프로그램은 아주 다양하지만, 안전이 최우선입니다. 축제의 순조로운 진행을 위해, 행사 자금으로 안전 상식 강좌를 진행할 필요가 있을까요?","필요하다","필요 없다","문단에 내가 없으면 안 되지","축제의 독서 구역이 썰렁합니다. 의자를 더 편안한 소파로 교체한다면 개선 효과가 클 것 같습니다. 어떻게 생각하시나요?","지식 탐구를 위해 소파를 구매한다","계속 의자를 사용한다","천생 연기자","축제 저녁에 있을 심리 공포극 <방총 2>에 미스터리한 BGM을 추가하면 모두가 비명을 지르게 할 수 있을 것 같으네요, 이에 연극 동아리 회원들은 현장 분위기를 끌어올릴 커다란 스피커 구매를 신청합니다!","구매한다","본능적인 공포에 다른 걸 물들일 필요는 없다","보안 요원","축제 현장 순찰 같은 중요한 업무는 반드시 제대로 완수해야 합니다. 통일된 무전기를 지급해 주신다면 즉시 소통이 가능해져 우리 보안 요원들의 실력을 더욱 잘 발휘할 수 있을 겁니다.","무전기를 구매한다","구매하지 않는다","비즈니스 전문가","긴장하지 마세요. 저는 자금을 신청하러 온 게 아니라, 제안을 하러 왔습니다. 이한시의 유명한 브랜드들을 축제 프로그램에 초대하는 게 어떨까요? 투자가 있으면 행사 자금을 계속해서 마련할 수 있을 겁니다.","투자를 받지 않고 자유로운 축제를 보장한다","자금 유동성이 중요하니 투자를 유치한다","게임 고수","게임 대회의 장비가 너무 구식입니다. 장비를 업그레이드해서 선수들의 게임 환경을 향상시킬 수 있을까요?","장비를 바꾼다","아직 그럭저럭 쓸만하다","보안 요원","길거리 음식 부스의 인기가 엄청납니다. 부스의 방문객 수를 제한해야 할까요?","방문객 수를 제한한다","원래대로 영업한다","홍보부 멤버","학교 신문의 면적이 제한적입니다. 이번 축제 특집 기사에 축제의 흥미로운 프로그램들을 더 많이 작성할까요, 아니면 우리 학교 축제의 전통인 과학 대중화 프로그램을 더 많이 작성할까요?","전통 과학 대중화 프로그램","흥미로운 프로그램","올해 축제는 정말 재밌어요. 보안 요원들이 너무 진지하다는 게 다소 흠이지만요. 다들 캐릭터 의상을 입고 순찰한다면 저는 별 다섯 개를 줄 거예요!","보안 요원에게 캐릭터 의상 입히기","보안 요원의 엄숙함 유지하기","전교 1등인 걸 어떻게 알았지","공부에 몰두하는 게 저의 축제 참여 방식이에요. 학생들이 도서관에서 소란을 피우지 않도록 인력을 배치해 주실 수 있나요?","범생이를 위해 인력 배치하기","경비가 부족하다","학교 토론팀 팀원","격렬한 논의 끝에, 이번 축제의 토론 대회 주제가 \'자신과의 싸움에서 승리하는 것은 내가 이긴 것인가/진 것인가\'로 결정되었습니다. 이 주제가 오락 토론 주제일까요, 아니면 심각한 토론 주제일까요?","오락 토론 주제","심각한 토론 주제","내 포커 카드가 맞았다","학교 밖에 마술을 잘하는 친구들을 좀 알고 있습니다. 친구들이 우리 학교에서 공연할 수 있도록 신청해도 될까요?","동의한다","동의하지 않는다","열정적인 학생","저희 집은 식당을 운영하고 있습니다. 축제 활동으로 바쁜 친구들에게 무료 점심 식사를 제공하고 싶습니다. 하지만 수량이 한정적인데, 어디로 배달하는 게 좋을까요?","마작부의 학생들에게 배달하기","헬스부의 학생들에게 배달하기","수공예 애호가","안녕하세요? 축제에서 수공예품 부스를 열고 싶은데, 남는 부스가 없는 것 같습니다. 혹시 해결해 주실 수 있을까요?","네, 제가 마련하겠습니다","죄송합니다, 선착순이에요","오라스는 시작일 뿐이다","곧 축제 경기가 진행됩니다. 기나긴 남풍전에서 어떻게 해야 멘탈을 유지할 수 있을까요?","이 문제는 너무 어려우니, 하지 않는 것을 추천한다","탕야오를 합리적으로 사용하여 진행 속도를 높인다","결정장애","실례합니다, 선택이 어려운 사람은 축제에서 도대체 무엇을 해야 할까요? 결정하기 어려워요!","그냥 조용히 구경만 하는 건 어떤가요","알고 보니 선택은 저만 어려워하는 게 아니었네요","열정적인 선생님","아사바 고등학교의 선생님들도 축제에 힘을 보태고 싶습니다. 뭘 도우면 될까요?","분위기 띄우기","보안팀에 합류하기","익명의 학생","축제에서 제 마음대로 해도 될까요?","이 신청은 이미 학생회에 전달되었습니다","학교 규칙을 숙지하세요","보안 요원","축제 질서를 어지럽힌 몇몇 학생들을 잡았습니다. 잘못을 인정하긴 하지만, 다음에도 같은 잘못을 할 것 같은데, 어떻게 처리할까요?","문제의 학생들에게 축제 구역을 청소하게 한다","학생회 회원에게 맡긴다","귀신의 집 NPC는 나야 나","축제에서 귀신의 집이 빠질 수 없죠! 완벽한 귀신의 집 기획안은 마무리만 남았습니다. 도망자들이 잊을 수 없을만한 벌칙을 생각해 주세요!","벌칙으로 함께 NPC 되기","벌칙으로 시험지 10세트 풀고 가기","축제의 소방 안전은 매우 중요합니다. 학생들의 소방 안전 의식을 어떻게 높일 수 있을까요?","소방 모의 훈련을 실시하기","소방 상식 강연을 개최하기","패션 동아리 멤버","패션 동아리는 축제에서 동아리 멤버의 디자인을 전시하고 싶습니다. 마네킹을 사용하여 전시할까요, 아니면 학생들이 직접 모델이 되어 T자형 스테이지 패션쇼를 진행할까요?","마네킹 사용하기","T자형 스테이지 패션쇼 진행하기","축제에서 동인지 판매 부스를 허가할까요?","허가한다","허가하지 않는다","고급 자동 마작 테이블을 갖춘 기술 전시회가 이번 축제의 히트 프로그램이 되어 표 구하기가 어렵습니다. 사전 예약하지 않은 학생들도 들어가서 관람할 수 있도록 허락할까요?","관람을 허락한다","관람을 허락하지 않는다","신청서 심사 및 사건을 통해 획득할 수 있는 추가 축제 자금: {0}","신청서 심사 및 사건 실패 시 성공으로 전환될 수 있는 확률: {0}%","업그레이드 후 축제 자금으로 더 많은 신청서 구매 가능","신청서 구매 시 비용 감소: {0}","축제 지표 증가 시 추가 획득: {0}","E-","E","E+","D-","D","D+","C-","C","C+","B-","B","B+","A-","A","A+","S","SS","SSS","버려진 물병","맛있는 새우","장식용 조개껍질","페퍼로니 피자","초코 와플","크루아상","장난감 물총","마사지 건","우산","액세서리 거치대","리치봉 초커","크리스탈 공룡","노란 오리 시소","바다로 부터 받은 선물로 섬에는 새우가 넘쳐납니다. [tag]새우[/tag]의 가격이 대폭 [tag]하락[/tag]할 예정입니다.","어느 전문가들이 말하길, 새우는 면역력을 올려주고, 수면의 질을 향상시키며, 패운을 높여준다고 합니다. [tag]새우[/tag]의 가격이 대폭 [tag]상승[/tag]할 예정입니다.","최근 생산된 [tag]장식용 조개껍질[/tag] 품질에 문제가 생겨, 쉽게 부서진다고 합니다. [tag]장식용 조개껍질[/tag]의 가격이 대폭 [tag]하락[/tag]할 예정입니다.","어느 유명한 배우가 조개 껍질로 된 귀걸이를 하고 나오면서 새로운 유행이 시작되었습니다. [tag]장식용 조개껍질[/tag]의 가격이 대폭 [tag]상승[/tag]할 예정입니다.","익명의 시민이 폭로하길, 베이커리의 빵이 맛있는 이유는 중독성 물질을 첨가하였기 때문이라고 합니다. [tag]베이커리[/tag]의 모든 상품 가격이 대폭 [tag]하락[/tag]할 예정입니다.","맛집 프로그램 \"혀 끝의 아일랜드\"에 \"베이커리, 맛의 비밀\"이 방영됩니다. [tag]베이커리[/tag]의 모든 상품 가격이 대폭 [tag]상승[/tag]할 예정입니다.","섬마을 학교의 일부 학생이 물총 놀이를 하던 중 오염된 물에 안구가 감염되어 많은 학부모의 반발을 샀으며, 결국 물총이 금기 품목으로 지정되었습니다. [tag]장난감 물총[/tag]의 가격이 대폭 [tag]하락[/tag]할 예정입니다.","내일은 고온의 날씨로 인해 바닷가에 물총 놀이가 성행할 것으로 보입니다. [tag]장난감 물총[/tag]의 가격이 대폭 [tag]상승[/tag]할 예정입니다.","일부 시민들이 불만을 제기하길, 섬마을에서 판매하는 마사지 건이 멍을 유발하고, 마치 진짜 총에 맞은 듯 아프다고 합니다. [tag]마사지 건[/tag]의 가격이 대폭 [tag]하락[/tag]할 예정입니다.","전문가들이 말하길, 마사지 건을 장기적으로 사용할 시 결석을 분쇄할 수 있다고 합니다. [tag]마사지 건[/tag]의 가격이 대폭 [tag]상승[/tag]할 예정입니다.","내일은 폭우가 예상됩니다. [tag]우산[/tag]의 가격이 대폭 [tag]상승[/tag]할 예정입니다.","내일은 섬마을 학교의 휴교일입니다. [tag]섬마을 학교[/tag]의 모든 상품 가격이 가격이 대폭 [tag]하락[/tag]할 예정입니다.","내일은 섬마을 학교의 운동회가 열립니다. [tag]섬마을 학교[/tag]의 모든 상품 가격이 가격이 대폭 [tag]상승[/tag]할 예정입니다.","마작 문화의 거리의 마스코트 연기자가 스캔들에 휩싸였습니다. [tag]마작 문화의 거리[/tag]의 모든 상품 가격이 가격이 대폭 [tag]하락[/tag]할 예정입니다.","제36회 \"섬마을 배 마작 대회\"의 시작으로 인해 마작 문화의 거리는 관광객으로 북적이고 있습니다. [tag]마작 문화의 거리[/tag]의 모든 상품 가격이 가격이 대폭 [tag]상승[/tag]할 예정입니다.","최근 섬마을에서 유행 중인 자연으로 돌아가자는 캠페인으로 인해, 사람들은 편안하고 따뜻한 침대에서 자는 것 보다 야외에서의 취침을 더 선호합니다. [tag]리조트[/tag]의 모든 상품 가격이 가격이 대폭 [tag]하락[/tag]할 예정입니다.","리조트에 묵으면 새벽에 레서판다가 순찰을 하는 신기한 광경을 목격할 수 있다는 소문이 많은 여행객의 이목을 끌고 있습니다. [tag]리조트[/tag]의 모든 상품 가격이 가격이 대폭 [tag]상승[/tag]할 예정입니다.","해피 아일랜드에 오신 \n여러분을 환영합니다!","공원 순찰","HIBI 귀신의 집 채널","다채로운 극장","도전! 인형 뽑기!","인간사 새옹지마","\"미식\"여행","한여름의 불꽃놀이","신비한 나라의 모험","수족관 관광일지","낭만 가득 놀이 공원","다음을 기대하며……","SAMU 해피 아일랜드","신시아 스튜디오","신시아","세계 일등 카나","딸랑딸랑딸랑","히비키 오늘 라방함?","너만 생각하면 즐거워","신시아 사랑해","신시아에 중독","신시아의 꼭대기를 걷다","기분 나쁜 건 너","설렘은 최대한 빨리","출근 냄새 없애기","신시아-여신 강림 버전","닉네임 안중요","신샤있어 다행","세계 최고 카나","분홍 머리의 집념","카나의 머리핀","곧 섬에 도착합니다! 여행객 여러분, 이 CatChat 게시물 아래에 체크인 기록을 남겨주세요! 이제 신비로운 해피 아일랜드 여행을 시작합니다. //[tag]#추첨#[/tag]21일동안 SAMU 해피 아일랜드 시범 운영 곧 시작\n당첨된 여러분 축하합니다~ [tag]@레아 @당첨되면 물구나무로 머리감음 @상대방이 보낸 원숭이 @카비[/tag] 등 이한시 행운의 여행객들이 이번 섬 방문 기회를 획득하셨습니다! 전체 당첨자 명단은 [여기]에서 확인하세요→[tag]전체 당첨자 명단[/tag]","모두 [SAMU 해피 아일랜드]에 온 걸 환영해! 카나는 놀이공원이 너무너무 기대돼!","우와아 나도 당첨됨! 나도!! 이제 카나 보러 가야겠다!! [tag]@신시아 언니의 옷장 너희[/tag] 언니도 일하러 올 것 같은데, 이런 내부 정보, 고마워하지 않아도 돼.","후후, 선생님은 정말 기대되는걸.[tag]@카비 @유즈[/tag]","Welcome to SAMU Joy Island!","해피 아일랜드에 초대해 줘서 고마워. 히비키의 실감나는 해피 아일랜드 체험 방송은 지금부터 예약할 수 있어, 히비키가 모두를 깜짝 랜선 여행으로 데려가 줄게!!:[tag]웹 링크[/tag]","좋았어! 행운의 선택을 받은 활기 넘치는 청춘 고등학생이 간다!","헤헤, 이거 소풍이라고 할 수 있나?[tag]@모리카와 아야코 @이치노세 소라 @스즈미야 안쥬[/tag]","와! 따뜻한 섬에서 어떤 자연 풍경을 만날 수 있으려나? 헤헤, 카메라 준비 완료!","띡, 작사 체크인.","환영합니다, {name} 작사님! SAMU 해피 아일랜드에서 즐거운 시간 보내세요!","환영합니다, 미라이 작사님! SAMU 해피 아일랜드에서 즐거운 시간 보내세요!","이 댓글은 자동 응답이었구나.","ㅠㅠ 아니에요. SAMU가 직접 다는 거예요.","공식 계정에서 댓글 창을 확인하다니!","SAMU는 여러분께 친근한 공식 계정이 되기 위해 노력할거랍니다~ 작사님들, 앞으로 저와 많은 소통 부탁드려요!","햇빛, 해변, 워터파크, 내가 간다!","스승, 소생은 완전무장이 끝났소. 이번 여행에서 스승의 안전을 반드시 지켜드리겠소!","완전무장이라니…… 뭘 가져온 거야?","평상시에 사용하는 쿠나이, 마름쇠 말고도 이번에는 특별히 아버지께서 최근에 단조하신 카타나 한 자루를 특별히 가져왔소. 순철로 만들어져 아주 날카롭소.","…… 약속해 줘, 이 물건들은 집에 두고 오겠다고. 해피 아일랜드는 안전하니까 몸만 오면 돼.","운명은 조금만 잘못도 폭격을 일으켜요. 덤벙대는 여행객이 오랫동안 줄을 서다가 가게 앞에 도착해서야 자신이 줄을 선 곳이 점괘를 보는 곳이라는 걸 알았을 때…… 그 절망한 모습이란, 후후.","역시 내가 줄 서고 있는 곳은 카비의 점술 부스인가보군, 후후.","음…… 사실 이미 마감 중이에요. 스승님, 오늘 아직 [tag]@유즈[/tag] 못 보셨죠? 아마 스승님 근처에서 돌아다니고 있을 거예요.","그래?[tag]@유즈[/tag]","큐르! 그냥 돌아다니는게 아니라 순찰이에요! 그리고 유즈는 이미 극장 근처에서 순찰 중이라고요, 그쪽이 아니라!","응, 선생님은 유즈처럼 착한 아이는 거짓말하지 않을 거라고 믿어, 그렇지?","큐르르…… 사실 극장까지는 아직 거리가 조금 돼요. 곧 도착할 테니 바로 순찰을 시작할 거라고요……","휴, 정말 아쉽네. 오랜만에 너희 둘이랑 놀이공원에서 하루 종일 놀면서 선생님의 의무를 다하려고 했는데…… 됐어, 오늘은 너희끼리 놀아.","알겠어요, 스승님.","큐르! 알았어요, 선생님!","섬 놀이공원까지 휴가를 왔는데, 카비는 왜 아직도 점을 보고 있는 거야? 놀러 안가?","점을 보고 있다기보다는, 운명의 계획을 기다리고 있는 거죠.","어떤 계획?","운명은 저에게 이 섬에서 가장 큰 즐거움을 만나려면 점술사의 신분을 유지해야 한다고 알려줬어요.","네가 말하는 만남이라는 게 혹시……","재물운이죠. 이곳의 여행객들은 점술에 관심이 많아요. 장사가 잘돼서 정말 기쁘다니까요.","내일도 가게 오픈 할거야? 미리 와서 줄 서게.","수정 구슬이 내일은 장사를 하지 않는다고 보여주네요.","하지만 누군가와 동행한대요, 그 대상은 당신이군요.","[tag]#HIBI 귀신의집 채널 #[/tag]히메카와 히비키님의 해피 아일랜드 특별 방송을 더 보고 싶으시다고요? 걱정 마세요! 하이라이트 편집본이 업로드됐습니다! [tag]@히메카와 히비키[/tag] 이번 오싹한 모험 방송에서 어떤 재밌는 일이 기다리고 있을까요? 방송 다시 보기는 [여기]에서 확인해주세요 →[tag]웹 링크[/tag] [tag]#SAMU 해피 아일랜드 영업중 #[/tag]편집본 보러가기 →[tag]웹 링크[/tag]","추가로, 모든 여행객 여러분 지금 \"유령 기숙사\"에 평가를 남겨주세요! 해당 게시물을 공유하고 체험 후기를 남겨주시면, 해피 아일랜드에서 준비한 상품 획득의 기회가 주어집니다!","으음…… 영상을 보니 현장에 다시 돌아간 것 같아…… [tag]@니노미야 하나[/tag] 정말 미안해, 리사리사가 일부러 먼저 도망간 게 아니야…… 그 기숙사의 종 소리가 학교 종 소리랑 똑같아서, 리사리사가 순간 놀라서 뛰, 뛰쳐나간 거라구……","별 다섯 개. 닌자 수련하기 딱 좋은 장소이오.","사다코가 재밌는 친구를 만나서…… 정말 즐거웠대.","평범했어","평가를 거기 있는 새 친구들에게 전해줬어…… 정말 미안하대. 앞으로 모두에게 더 많은 즐거움을 줄 수 있도록 노력하겠다고 했어……","{name}, 다시 체험하러 갈 거야? 이번에는 다들 열심히 연습했으니까, 저번보다 나을 거야……","훌륭했어","깔끔한 평가 고마워. 히비키가 개인적으로 경품을 하나 지원하기로 했으니까 오늘 밤 꼭 날 찾아와!","황실 극장의 도장 퀘스트는 도대체 뭐야? \"사자 왕위 쟁탈전\" 에서 사자의 포효 소리가 무슨 뜻인지 알아맞히라니…… 세 가지 선택지 중에 애초에 정답이 없는 거 아니야?[tag]@SAMU 해피 아일랜드[/tag]","안녕하세요, 여행객님. 말씀해 주신 내용은 접수 되었으며 현재 확인하는 중입니다! 시범 운영 개선에 기여해 주셔서 감사합니다.","다른 연극으로 바꿔보는 것도 괜찮아. 다른 두 연극의 문제는 좀 더 쉽게 답할 수 있을 거야…… 아마도.","……기념 도장을 찍으려고 공연을 연속으로 세 번 본 사람이 너였구나. 어쩐지 그 직원이 나한테 계속 실패를 두려워하지 말라면서 어떤 손님은 삼고초려 어쩌고라고 말하더라니…… 정말 대단한 인내심을 가졌군……","넌 절대 이해 못해, 이런 걸 바로 인간의 한계에 도전하는 굴하지 않는 정신이라고 한다고!","한나도 공연을 볼 때 비슷한 얘기를 했었어.","쯧…… 어쩐지 너를 어디서도 못 찾나 했더니, 다른 사람이랑 공연을 보고 있었군.","우연이야, 정말 우연. 나츠키, 후유미, 이브도 마주쳤는걸.","허, 그렇게 많은 사람들이랑은 마주쳤으면서 왜 나랑은 안 마주친 거야?","내가 어떻게 알아…… 잠깐만, 너 설마 나랑 같이 놀고 싶다는 건 아니겠지?","하?! 절대 아니니까 멋대로 추측하지 마. 나는 바쁜 몸이라고!","정말이니까 괜한 생각하지마. 그냥 롤러코스터 앞을 지나가다가 너랑 같이 타서 네가 놀라는 꼴을 보면 재밌겠다고 생각했을 뿐이라구.","알겠어?","알겠어, 이따가 같이 롤러코스터 타러 가자.","흥, 이따가 롤러코스터 타면서 울지나 말라고.","[tag]@시노미야 나츠키[/tag] 오빠, 이게 바로 인형 뽑기 기계가 하룻밤 사이에 사라진 이유야. 평행우주 같은 게 아니라고……//[tag]@SAMU 해피 아일랜드[/tag]: 여행객 여러분, 해피 아일랜드의 인형 뽑기 기계에 발생한 일부 오류로 인해 오늘부터 수리 예정입니다. 인형 뽑기 기계의 화려한 복귀를 기다려 주세요! 섬의 다양한 게임기도 많이 즐겨주시기 바랍니다!","허, 어려도 너무 어려. 공식 발표는 보통 진실을 가리기 위한 겉치레일뿐이야. 후유미 대마왕아, 인간성이라는 걸 너무 믿지 마.","인간성이고 뭐고 난 오빠부터 안 믿을 거거든!","후유미야, 오빠는 버리고 나랑 놀자![tag]@시노미야 후유미[/tag]","오빠 혼자 있으면 사고 칠까 봐 걱정되긴 하지만…… 버릴래. 우리끼리 놀러 가자!","나는 널 이해해. 사실대로 말하면 이 평행 세계가 생긴 건…… 나와 관련이 있어.[tag]@시노미야 나츠키[/tag]","나의 동료여, 조용한 곳으로 가서 자세히 얘기 나누게.","이걸 보면 당신은…… 무엇이 떠오르나요?\n(첨부 사진: 수족관의 해파리)","와! 수족관의 해파리야?! 어떻게 우리 몰래 갈 수 있어!","지나가다 아는 사람을 봐서…… 한번 들어가 봤어요……","니노미야는 뭐가 떠올라?","…… 제 자신이 떠올랐어요…… 투명하고, 존재감 없고…… 그저 흐름에 떠밀려 다니는……","왜 그렇게 말하는 거야?","{name}이(가) 수족관에 들어가는 걸 보고 따라 들어왔어요…… 하지만 {name}은(는) 거기서 모두와 즐겁게 대화하고 있었죠…… 그래서 저도 기대했는데…… 결국…… 해파리 앞에서 오래 서 있었지만 {name}은(는) 마치 해파리들을 지나치듯 저를 못 본 것 같아요……","엥???","싱싱한 해파리들이네. 냉채로 해 먹으면 분명 맛있을 거야.","…… 그런 생각은 너무 뜬금없네요.","음, 오늘 수족관에서 들은 어떤 주제들 때문에 세뇌당한 것 같아.","섬에 오기 전의 나: 휴가란 장소만 바꿔서 일하는 것\n지금의 나: 그 말 취소\n(첨부 사진: 밤, 대관람차 위에서 부딪히는 두 개의 와인 잔)","우와, 오늘 밤은 치호리 혼자 야근하는 게 아닌가보네. 특별한 분위기가 느껴지는걸.","와인잔에 포도주스를 담는 것도 주최측의 방식 중 하나겠지……","모든 연령대를 위한 놀이공원이니까. 근데 네 포인트는 이 때의 분위기가 아니라 잔에 담긴 포도주스였던 거야?","그때…… 치호리가 너무 가까이 다가와서 쑥스러웠어……","그렇다면 좀 더 깊이 알아볼 필요가 있겠네. 내일 새로운 의뢰부터 시작해 보자.","짧은 휴식의 이면에는 보통 힘든 노동이 숨겨져 있지, 예를 들면 나처럼……","오늘 저녁 식사가 만족스럽지 못했나 보네. 내일 한 번 더 기회를 줄 수 있을까?","오늘 미키 점장님이 평소보다 더 예뻐 보였는디! 점장님은 정성껏 고른 퓨전 요리를 요리를 잘 아는 친구들한테 나눠줬다고 혀! 그래서 기분이 아주 좋아 보이네 그려! 역시, 우아함은 내면에서부터 나오는 거여! 통 크게 나누는 것은 우아한 lady의 멋진 품격이지! 오늘 또 하나 배운겨!","네가 공범이었구나……","뭐? 공범…… 무슨 뜻이여?","너희 천화각 사장님은 유명한 보석 디자이너면서 왜 항상 음식 연구만 하는 거야?","미키 점장님이 놀 때는 본업은 잊고 즐겨야 된다고 혔어!","하지만 미키는 이한시에 있을 때도 그러잖아???","아이고, 누가 월급 루팡을 안 좋아하겄어? 넌 안 좋아혀?","[tag]#불꽃놀이 최고의 관람 장소[/tag] 여러분이 알려준 팁 덕분에 불꽃놀이를 사람 많은 광장에서 보지 않을 수 있었어. 히비키는 색다른 방법으로 근처에 속도가 느린 롤러코스터를 찾았지. 롤러코스터 타면서 불꽃놀이를 본다는 건…… 뭐랄까, 불꽃도 잘 보이고…… 붐비지도 않고…… 밤바람도 상쾌했고…… 그런데! 이건 왜 말해주지 않았던 거야! 사진이 이렇게 찍힐 줄은 몰랐어!!\n(첨부 사진: 불꽃놀이가 펼쳐진 밤하늘을 배경으로, 롤러코스터에서 얼굴을 찡그리고 있는 히메카와 히비키의 귀여운 캐릭터.)","ㅋㅋㅋㅋㄱㄱㅋㅋㅋㄲㅋㅋㄲㅋㄱㄱ","ㅋㅋㅋ 신규 업적 달성이네.","하하하, 어쩐지 불꽃놀이하는 동안 롤러코스터에서 계속 비명이 들리더라니!","예술적인 사진이네. 다시는 재현할 수 없는 순간이잖아.","그래……? 맘에 드는 모양이네? 그럼 내일 밤 불꽃놀이에서 너도 같은 스타일로 한 장 찍어보는 게 어때?","왜 나는 안 불렀어?","좀 아쉬운 모양이군…… 다음, 다음엔 꼭 부를게! 그때 돼서 쫄지나 마!","기쁜 마음으로 촬영 일정이 드디어 시작됐는데, 예상 밖에도 연예인보다 먼저 쓰러진 건 나, 코무로였어. 전날 잠을 제대로 못 자서 그런지 섬에 도착하자마자 일사병에 걸렸거든…… 다행히 해피 아일랜드의 의무실에 명의가 있어서, 약을 먹고 나니 머리도 안 어지럽고 눈도 안 침침해졌어. 다시 우리 언니랑 열 세트는 찍을 수 있을 것 같았지. 그런데 누가 알았겠어? 겨우 한 시간 정도 우리 언니가 놀이공원 근처를 돌아다니다가 촬영용 소품인 풍선을 지나가는 꼬마에게 줘 버렸을 줄이야! (대신에 평범한 풍선 하나를 받아왔더라고…… 그걸 아주 소중하게 여기는 것 같았어……) 어쨌든 순간 눈앞이 깜깜해져서 다시 의무실로 돌아가서 누워야 하나 싶었는데…… 그래도 역시 우리 언니는 사진 천재야…… 제대로 된 풍선 없이도 더 환상적인 소품을 찾아내서 작품을 완성했거든…… 역시 우리 언니!!! 말이 길었네, 더 많은 멋진 사진들은 정식 공개를 기다려줘! 하하, 먼저 비하인드 컷 하나 보여줄게!\n(첨부 사진: 신시아의 인연 일러스트의 일부)","쓸데없이 말이 많아. 다음번에 또 마작하다 밤새워서 스케줄을 망치면, 널 천장에 매달아서 소품으로 쓸 거야.","ㅠ_ㅠ 그럴리가요 언니! 절대로 다시는 안 그럴게요!!!!","언니, 절 매달아 줘요! 저 할 수 있어요! (뒤틀린 사랑 속 이성적 하트)","너무너무너무너무너무 예뻐!!!!","아아아아아 역시 우리 언니야! 우리 슈퍼모델은 역시 자기만의 생각이 있는 법이지!","3초 안에 원본 사진 보여줘 [tag]@신시아[/tag]","정식 공개를 기대해! (PS: 신시아 언니를 새로 팔로우한 친구구나. 코무로가 따뜻한 충고를 하자면, 지난번에 감히 우리 언니를 멘션한 사람의 무덤에 자란 풀이 벌써 언니 키만하단다?)","재미없어. 현장에서 두 눈으로 직접 본 건 인정하지 않겠다는 거야?","???","그게 소품 풍선이었다고!?","내가 풍선이나 흔들고 있을 정도로 한가하다고 생각하는 건 아니겠지?","타로 카드가 나에게 이한시에 약재를 더 많이 가져오라고 하긴 했지만, 실제 소비량은 예상보다 훨씬 많았어…… 후후, 운명은 이렇게 변화무쌍하지. 마치 내 소원을 들어줄 착한 아이를 봤지만…… 그 정체가 예상 밖이었던 것처럼……","약재는 제가 미리 좀 준비했어요. 이따가 스승님 방으로 가져다 드릴게요.","카비는 역시 점술에 소질이 있는걸, 선생님의 곤경을 미리 예견한 거야?","운명은 절대적이지만, 스승님은 고의일 수도 있죠…… 그렇지 않나요?","후후, 유즈 데려오는 걸 잊지 말렴. 우리 셋이서 같이 안 잔지 오래됐잖아?","그렇다면 이 예상치 못한 일에 만족하나요?","만족? 하하, 선생님은 지금 판단하기에는 이르다고 생각하는데…… 하지만 운명의 흐름을 지켜보는 과정 자체가 아름다운 거 아닐까?","레아씨가 이한시에 온 이유가 얘 때문인건 가요?","음…… 맞는 것 같기도 하고 아닌 것 같기도? 이 문제는 확답하긴 어려워. 선생님은 먼저 상대가 착한 아이인지 확인해야 하니까.","붉은 여왕 역할을 맡은 사람의 현실 고민: 정말 이상하네, 오늘 관광객들이 전부 네 쪽으로 갔어?[tag]@힐리[/tag]","아니. 한두 그룹밖에 없어. 직원 말로는 대부분 너희 쪽으로 갔다던데.","그래? 그런데 나는 점심 때부터 관광객을 전혀 못봤는걸.","네가 바로 붉은 여왕이었구나!","우히히, 이제야 발견한 것이냐? 바.보.녀.석! 하지만 다른 사람들은 모두 이 몸이 단단히 내쫓았느라. 오직 너만이 신의 총애를 받을 자격을 얻었지. 감동했느냐?","엥?! 당신, 붉은 여왕 쪽으로 왔었던 거야? 나는 전혀 못 봤는데.","진실은 하나야. 붉은 여왕인 척하는 토끼가 모두를 중간에서 가로챘어…… 나까지 포함해서.","사라도 NPC하러 온 거였어?!","맞아, 아쉽게도 당신이 나한테 오지 않았어, 붉은 여왕의 춤을 보여주고 싶었는데.","붉은 여왕의 춤이 뭐야?","후후, 관광객들을 기다리는 동안 느낌이 오는 대로 춰본 춤인데, 당신만 괜찮다면 오늘 밤 춤을 춰 줄게.","[tag]#분실물 관련 안내[/tag] 존경하는 여행객 여러분, 해피 아일랜드를 방문하는 동안 개인 소지품을 잘 보관해 주세요. 만약 실수로 잃어버리신 경우, 저희에게 즉시 연락해 주시기 바랍니다. 또한 이 [CatChat] 아래에 댓글을 남기시면 다른 친절한 여행객들의 도움을 받으실 수도 있답니다.","누군가의 방총 토비 기록을 관광객 센터에 가져다 놓았습니다.","20여 년 동안 잃어버린 여자친구를 찾아요. 놀이공원의 점술가가 이 섬에 여자친구가 있댔어요!","집 나간 머리카락을 찾습니다. 의무실에서 만난 빨간 머리의 의사가 회사가 아닌 곳에 있으면 머리카락을 되찾을 수 있다고 했어요……","역시 화목하고 즐거운 해피 아일랜드군.","모든 관광객 분들이 도움 덕분이죠!","이건 직접 쓴 대답이야?","ㅜㅜ SAMU를 놀리지 말아주세요. 저 정말 열심히 일하고 있다구요!","훌륭한 태도군.","오늘도 해피 아일랜드에는 활기찬 기운이 가득하네요.","약속해 줘, 행복하고 즐거운 해피 아일랜드 여행이 영원히 끝나지 않을 거라고.","이 세상에 영원히 끝나지 않는 여행은 없지만…… 원한다면 언제든 다시 오실 수 있어요.","마작 바람이 이 섬까지 불어왔군.\n(첨부 사진: 해변의 마작 테이블)","어디?","응? 다들 마작 하고 싶었던 거야?","와, 회장이 좋은 장소를 발견했네. 나도 좀 가고 싶은걸.","위치 보냈어. 여기는 특별히 조성된 해변 마작 구역이야.","곧 갈게!","천천히 와, 기다릴게.","놀이기구와 마작…… 선택의 문제네.","그러면 와서 나랑 마작 한 판 할래? 여기 공기도 좋고, 경치도 정말 멋져. 너랑 같이 마작을 두고 싶기도 하고.","[tag]#여행은 평범한 일상에서의 탈출[/tag] [tag]#낯선 도시에 가면 더 용감해지고 자신감이 [/tag]생긴다 역시 네티즌들이 요약을 잘하네.","그게 네가 술 취해서 새벽 3시에 삽 들고 호텔 방 문 앞에 서서 바다로 나가자면서 내 잠을 깨울 이유가 되진 않는데.","풉, 나데시코의 가장 대단한 점이 취했을 때랑 안 취했을 때랑 똑같은 거잖아…… 네가 말려서 다행…… 이지?","그럴 리가? 당연히 동영상으로 찍어서 나중에 기사 소재로 쓰려고 저장해뒀지.","…… 어쨌든 나는 다시 이한시로 돌아가야 하니까, 이 일은 기사에 넣지 말아 줘.","공감해. 낯선 곳에서는 더 신나기 마련이잖아.","낯선 곳에서 한 모든 행동은 곧 삭제될 내용일 뿐이지…… 물론 몇몇 장난꾸러기 친구들이 저장해 놓지 않는다면 말이야.","바다에서 뭐 좀 건져온 거 있나?","가끔은 내게 스킬 같은 게 없다는 걸 인정하게 될 때가 있어.","보이는 것: 해변 놀이공원 여행 \n진실: 야외 10km 크로스컨트리 훈련\n(첨부 사진: 시라이시 나나의 오늘의 운동 어플 화면, 시라이시 나나의 걸음 수가 제일 높음, 키사라기 아야네의 걸음 수는 꼴찌)","젊어서 그런지 체력이 대단하네. 힘이 넘쳐…… 대단해.","키사라기 선생님!!! 내일은 늦잠 자지 마세요. 부회장님도 일을 내려놓고 우리랑 같이 놀러 나왔어요. 휴간데 선생님도 같이 놀아야죠!","휴, 하지만 야외 활동에…… 낮에…… 줄 서기까지…… 난 항복이야. 오늘의 나는 더 이상 사촌 동생을 부추겨서 할로윈 인어공주 코스프레를 입게 했던 예전의 파티걸이 아니야……","누가 특전사 아니랄까봐.","그러니까. 내일 일정 보내 뒀어. 아침 6시! 전화할게, 꼭 와!","적당히 쉬는 건 어때?","걱정 마. 내일은 여유로운 일정이라구.","잘 됐네, 어디 가는데?","마사지! 추나! 아프고 즐겁지! 게다가 근막 마사지도 예약해 놨어, 고마워할 필요는 없어!","???","테마 레스토랑 한정 세트 메뉴…… 왜 이렇게 익숙한 맛이 나는기가?","공원 안의 마작 테마 레스토랑 말이냥!?","응.","냥! 이치히메도 가고 싶은데, 예약하기 어렵다냥!","세 배나 비싼 값을 주고, 이한시의 체인 패스트푸드점이랑 똑같은 맛이라니. 안 묵는 게 낫데이.","세 배라…… 음, {name} 거덜나겠네.","식당 음식 맛이 별로였군요. SAMU가 기록해 뒀습니다. 열심히 피드백을 정리할게요!","기억하기론 옆 섬에 체인점 식당이 하나 있었던 것 같은데, 지리적인 걸 고려해 보면…… 멍, 설마 그 체인점에서 직접 공급하는 제품은 아니겠지멍.","에이…… 상인이라믄 효율과 수익을 신경 쓰는 기가, 이해는 된데이.","네가 다른 사람을 논할 자격이 있나멍?","관광지에 오픈한 거니까, 맛은 그냥 용서해 줘.","네 말은 우리 복수쌍전관도……","그런 생각은 멈춰!","안좋은 경험을 할뻔했네. 고마워, 미리 차단해야겠다.","아직 안 먹어본기가? 아이고, 캣챗을 너무 빨리 올렸데이. 네가 먹으러 갈 때까지 기다렸어야 하는 긴데.","우리 행복은 함께 나누고, 어려움은 각자 알아서 극복하자.","젊은이, 어려움을 겪어야 성장할 수 있데이, 다 널 위한기다.","으음, 해피 아일랜드에서 여러분이 보내준 엽서를 받았어! 다들 정말 즐거웠나 보구나.","치오리 건 아직 못 받았어?","에? 치오리도 나한테 엽서를 보냈어? 으음…… 아직 도착 안 했나 봐.","엽서 아니야. 섬에서 인형을 너무 많이 뽑았는데, {name} 그 바보가 그렇게 많이는 못 가져간다고 하더라고. 그래서 너한테도 나눠줬지.","귀여운 인형들이었어? 레이나는 정말 기대되는걸? 고마워, 치오리.","평범한 인형일 뿐인걸. 특별한 건 아니니까 너무 기대하진 마.","치오리 아가씨, 이제 막 보냈으니 이한시에는 적어도 모레쯤 도착할 거예요. 열 개 넘는 인형을 큰 택배 상자에 포장했잖아요.","!!! 서민들의 물류는 그렇게 느려?","섬의 물류가 좀 느린 것 같긴 하네요. 남은 인형들은 돌아가서 다른 친구들에게 직접 전해주는 게 좋을 것 같아요.","흥, 그럼 그러자.","정식 영업할 때는 레이나도 같이 올 거지?","하지만 놀이공원에는 내가 탈 수 있는 기구가 많지 않은걸…… 나랑 같이 놀면, {name}이(가) 재미없을 거야.","놀이공원에서 뭘 하는지보다 누구랑 노는지가 제일 중요한 거지. 나는 레이나랑 놀고 싶어.","와아! 그렇다면, 다음에는 꼭 레이나랑 놀자. 나도 {name}랑 같이 놀이공원에 가고 싶은걸.","Éternité의 커피가 마시고 싶어.","{name}, 돌아오면 꼭 Éternité에 와줘. 레이나가 가게에서 최신 특제 아이스 음료를 준비해 줄게.","아이와 혹시라도 떨어지게 될까봐 주문한 이 신기한 물건, 의외로 좋네요.\n첨부 사진: 미아 방지용 어린이 줄","진작 알았다면 리사리사랑 뽀요용도 이걸 사용했을 텐데!! 링크 좀 줘!","오빠랑 엄마한테도 하나씩 사주고 싶어지는 걸…… 지금 주문하면 항공 배송 되나요……?","링크 부탁드립니다.","?","관광객이 생각보다 많아서요…… 완벽한 치오리 아가씨의 안전을 위해서라도, 미리 조심하는 게 좋을 것 같아요!","네? {name}도 어린 친구를 데리고 왔나요?","응, 어떤 애들은 실제로 나이가 어리고, 어떤 애들은 정신 연령이 어려. 이번 여행에서 이게 꼭 필요할 것 같은 예감이 들거든.","하나로 충분할까? 사람들이 정말 많다면 같이 온 모든 사람이 하나씩 필요하지 않을까?","후후, 사실 두 개 샀답니다. {name}이(가) 가끔은 정말 어린애 같아서 신경이 쓰이거든요.","해피 아일랜드는 역시 즐겁네요. 며칠 전 연재 중단을 발표했던 작가님이 오늘 갑자기 연재를 재개했어요…… 놀이공원과 새로워진 소설 연재, 두 배의 행복을 얻었네요.","아, 마이도 봤어요…… 그 작가님, 소설 정말 잘 쓰시는데…… 기뻐요.","풉, 작가님의 최신 근황을 봤나요…… 이런 일이 일어날 줄은 몰랐는데.","네네…… 봤어요…… 웃는 게 살짝 양심 찔리는 일이긴 하지만…… 정말…… 참을 수가 없네요……","나도 알려줘.","작가님이 연재를 중단한 이유가 해피 아일랜드에 놀러 오기 위해서였대요. 그런데 동화의 성에서 편집자와 마주치는 바람에 지금 해피 아일랜드 호텔에서 \'감금\'된 채로 연재 중이래요.","작가와 편집자가 모두 시범 체험권을 추첨으로 받다니, 정말 대단한 우연이네.","그게 아니에요, 주인님. 작가가 계약한 플랫폼이 샘 그룹 소속이라, 편집자는 직원 자격으로 체험을 온 거예요.","그래서 더 웃긴 거죠.","무슨 소설이야?","당연히 애정에 대한 엄청난 집착을 묘사하는 책이죠. 내면의 갈등 속에서 욕망이 피어나는 고전적인 장면이 있고, 그리고 육체가 끊임없이 부딪히며 유혹적인 소리를 내는 \"환생을 하고서야 내 원수도 환생했다는 걸 알았다\" 예요.","…… 책 제목만 봐서는 네가 묘사한 장면과 관련이 있는지 전혀 알 수가 없겠는데.","간단한 짐 싸기 절차: 여행 가방을 연다→ 레서판다를 꺼낸다→ 옷을 넣는다→ 레서판다를 꺼낸다→ 생필품을 넣는다→ 레서판다를 꺼낸다→ 간식을 넣는다→ 여행 가방을 닫는다→ 여행 가방을 연다→ 레서판다를 꺼낸다……","선생님의 약재도 이렇게 알아서 여행 가방에 들어가 준다면 좋을 텐데.","큐르! 다음에 선생님이 짐 싸실 때 유즈가 가서 도와드릴게요!","내 몸도 여행 가방에 넣을 수 있다면 좋겠는걸. 한숨 자고 일어나면 목적지에 도착하는 거지.","키사라기 선생님, 주인 없는 여행 가방은 보통 목적지가 아니라 분실물 보관소로 보내질 거라구요, 큐르.","와! 리사리사도 똑같은 절차를 거쳤는데. 여행 가방에 도대체 무슨 마력이 있는 걸까!","이치히메는 주인(의 지갑)만 여행 가방에 넣으면 된다냥!","하하하, 그럼 당연히 청춘의 싱그러운 마음도 챙겨야지!","여행 가방에 어떻게 마작이 없을 수 있지?","큐르르, 역시 이한시의 유명 작사답네…… 정의로운 세계에는 너처럼 초심을 잃지 않는 정신이 필요하지!","내 여행 가방에 여유 공간이 많아. 레서판다를 넣을 수 있어!","큐르르…… {name}은(는) 자기 여행 가방에 레서판다즈 하나가 아까부터 들어가 있다는 걸 전혀 눈치채지 못했나보네……","바다에 왔으니, 사진을 좀 찍어야지.\n첨부 사진 1: 신시아의 건강식 + 해산물","와, 언니 오늘도 건강식이네요!","이건 딱 봐도 미인이 먹을 음식이네. 보이진 않지만, 오늘도 분명 언니에 미모에 반해서 물고기가 도망가고, 새들도 땅으로 떨어지고, 달도 구름 뒤로 숨고 꽃도 부끄러워할 거라구!","너무 예쁘다, 언니! 미인과 바다는 최고의 궁합이야! (상상 중)","으흑흑흑흑 언니 언제쯤 셀카 좀 올려줄 수 있어요? 언니의 눈부신 미모가 그리워요.","우리 밥 먹고 일정이 뭐야?","여기까지 왔으니까…… 바닷가 산책하면서 소화 좀 시키자.","좋아.","사진 잘 나왔네, 근데 다음엔 우리 다음번엔 우리 심심한 건강식은 안 먹으면 안 될까?","별로였어? 당연히 되지. 이따가 비서한테 우리 저녁 안 먹는다고 얘기해 둘게.","??? 식사를 건너뛰자는 뜻은 아니었어!","기념품 가게에서 예쁜 편지지를 샀어…… 나중에 이걸로 이한시의 학생들과 소통할 게 기대되는걸.","같은 도시에 있으면서 학생들과 편지로 소통할 필요가 있을까요?","글씨체는 보통 사람들의 마음을 반영하니까…… 재밌잖아. 너도 지금부터 이런 좋은 습관을 들여봐.","저도 레아 선생님의 편지를 받고 싶어요.","착한 아이네, 제일 적절한 시기에 받게 될 거야.","[tag]#후지타 카나의 배달 프로필 닉네임은 오락실을 제패한 여자[/tag] 수치심으로 매장 당할 뻔한 하루였어…… 열심히 일하시는 배달원님 감사합니다. 다음번엔 꼭 문자랑 전화를 잘 확인할게요……","인기 검색어 보고 들어온 친구들, 데이터 아끼게 해 주지. 후지타 카나가 해피 아일랜드의 오락실에서 게임에 너무 열중하느라 배달 온 걸 못 들었는데, 배달원이 오락실 중앙에서 큰 소리로 닉네임을 불렀대. 하하하!","하하하하하하하 우리의 아이돌이 웃음거리가 됐네, 하지만 아주 착실한 아이돌이라구!","오락실을 제패한 여자 ㅋㅋㅋ 우리 카나는 사랑이야!","식탐과 인생을 맞바꿀뻔 했네.","너 너무 크게 웃었어, 다음에 게임 같이 안 해줄거야아아아!","뭐 시켰어?","고마워, 하지만 묻지 말아줘. 매니저 언니한테 혼나고 있는 중이야…… [울음][울음][울음]","오늘은 시범 운영 마지막 날입니다. SAMU 해피 아일랜드를 사랑해 주신 여러분께 감사드립니다. 정식 오픈 후 다시 만날 날을 기대해 주세요! PS: 이번 해피 아일랜드 체험에서 남기고 싶은 말씀이 있다면, 언제든지 남겨주세요!","재밌었어요. 정식 오픈이 기대돼요.","나 다시 올 거야. 순수 관광객 신분으로 말이야.","하루는 워터파크의 플라잉 덕이 고장나서 작동이 안됐는데, 직원이 정말 침착하게 플라잉 덕이 오늘 좀 피곤해서 좀 쉬면 괜찮아질 거라고 말하더라구. 하하…… 그 순간 해피 아일랜드의 모든 놀이기구가 살아있는 것처럼 느껴졌어! 파이팅! 정식 오픈을 기대할게!","다시 만날 날을 기대할게요!","작사님, 응원 감사드립니다! 다음에 만나요!","풉! 이렇게 형식적인 대답이라니, 너도 자동 응답처럼 느껴져.","힘내요, 다음번엔 더 좋아지길 바라요!","네가 제출한 설문조사가 효과를 발휘할 거야.","작사님, 너그러운 이해에 감사드립니다. 다음번에는 더 잘할게요!","제1챕터","제2챕터","제3챕터","정식 입사 전, 나는 \"죽운\" 사장님 미나미 후우카와 최종 면접을 봤다.\n처음 만났던 그날, 임시 비서의 업무가 결코 간단하지 않다는 것을 알아챘다.","길일이 왔으니 신을 맞이하리.\n\"죽운\" 기념일 축제의 중요한 이벤트인 \"신맞이 축제\" 준비로 한창이다.\n하지만 무당 아원의 제사가 번번이 실패하며, 신이 인간 세상에 오지 않는 문제가 생기는데……\n행사의 감독관인 나는 도움을 주어야 한다…… 그런데 그녀들은 누구람?\n신비로운 무속 문화와 다채로운 희극의 전승자…… 무쌍가의 소녀는 나를 데리고 사건의 진상을 찾으러 다니며, 미나미 후우카의 고향인 오래된 대지의 신비한 베일을 벗겨낸다.","약속대로 작업 장소인 \'무쌍 경매장\'에 도착하여 \'죽운\' 연례 자선 행사의 준비 상황을 점검하려고 했다. \n그때, 끔찍한 장면을 목격했다. 경매장에서 폭력적인 강도 사건이 벌어지고 있었다!\n나는 유일한 목격자로서 미나미 후우카에게 중책을 맡게 되었다. 반드시 이 사건을 해결하고 전시품을 되찾아야 한다!\n수많은 어려움을 겪은 끝에, 마침내 범인의 흔적을 찾았다.\n알고 보니, 전시품의 도난은 이 사건의 빙산의 일각에 불과했다......","무쌍가의 오래된 찻집 \'미접다관\'은 \'죽운\'의 새로운 파트너로 미나미 후우카에게 선택받았다.\n사업 논의의 중책을 맡고 찻집에 찾아갔지만 사장 페이밍은 협업을 거절하라는 당부만 남긴 채 자취를 감췄고, 업계 사람들의 질투로 인한 도발에 대처하는 임무는 점원 유엔샤오에 이어 계약을 원하는 나에게까지 넘겨졌다.\n협업을 성사하기 위해서는 \'미접다관\'을 도와 업계 사람들과 다도 대결을 할 수밖에 없다. \n그러나 페이밍의 다도를 깨우쳤다고 해도, \'죽운\'의 상업 비밀을 노리는 또 다른 사람들이 우리를 기다리고 있는데……","\'죽운\' 상회에는 수많은 고수가 있다. 강호인들은 미나미 후우카의 측근 네 명을 \'매난국죽-사군자\'라 부른다. 축제가 다가오며 \'죽운\' 본부에 일을 도와주러 간 나는 이 신비로운 인물들을 만나게 됐다. 그런데 본부에서 일어나는 이상한 일들은 사군자와 관련있어 보인다. 사군자의 의도는 대체 무엇일까? 죽운 축제는 과연 무사히 진행될 수 있을까?","기념일 준비 작업이 무사히 절반을 넘어섰고, 미나미 후우카에게 업무를 보고하는 날이 다가왔다. 이날, 홀로 죽운 본사에서 미나미 후우카의 사무실 문을 두드렸다……","모든 사건이 마무리되었고, \'죽운\' 축제도 무사히 끝났다. 그리고 환송회 밤, 나는 미나미 후우카에게서 의외의 모습을 보게 되는데……","죽운의 초대","길일 신맞이 노래","성도의 변주곡","다도 대결 행진곡","군자의 협주곡","약속의 간주곡","축제의 찬송가","미나미 사당","무쌍 경매장","미접다관","죽운 본부","네가 메이가 나 대신 고용한 임시 비서인가? 꽤 괜찮은데?","이번에 할 일은 곧 있을 \'죽운\' 기념일의 각종 준비 작업을 감독하는 거야.","쉽게 말해 \'감독관\'이지.","감독관…… 그러니까, 소위 프로젝트 매니저라는 거죠. 잘 이해했습니다. 사람들에게 미움을 사는 직업이군요.","그런 것 같네. 그렇지 않았다면 전임 감독관이 \'우연히\' 부상을 당해서 네가 대신 오게 되지 않았을 테니까.","표정이 많이 굳어졌네?","걱정 마, 그냥 농담한 거야. \'죽운\'에서는 직원들이 쉽게 다치지 않아. 너희 모두가 내 소중한 \'노동 자산\'이니까.","저는 무엇을 해야 하나요?","여기 업무 리스트가 있어. 여기 4개의 장소가 적혀있으니, 해당 장소에 가서 책임자를 만나고 작업 진행 상황을 확인하면 돼.","강유상제의 태로를 기억하도록 해.","강유상제?","감독관이라면 그에 맞는 강함과 굳셈이 있어야 해. 만약 직원들이 제시간에 일을 완료하지 못할 때는 엄격하게 대해야 할 필요가 있어.","동시에 상급자로서의 넉넉한 마음씨도 필요해. 직원들의 능력이 부족하다면 그들에게 즉시 도움을 줄줄도 알아야 하지.","듣기만 해도…… 쉽지 않네요.","관리에는 충분한 경험과 기술이 필요해. 이 부분에 문제가 있다면 언제든 \'죽운\'의 총 매니저인 메이에게 물어보면 돼.","알겠습니다.","그래, 그럼 빨리 가서 일을 시작해볼까.","맞다, 시간이 날 때 \'죽운\'의 회계사인 죽 씨를 찾아가봐. 네 모든 급여는 그가 지급할 거야.","어떤 성과를 보여줄지 아주 기대되네. 나의 새.비.서.","미나미 사당 챕터1을 열람하시면 해당 보상을 획득하실 수 있습니다.","미나미 사당 챕터3을 열람하시면 해당 보상을 획득하실 수 있습니다.","무쌍 경매장 챕터1을 열람하시면 해당 보상을 획득하실 수 있습니다.","무쌍 경매장 챕터3을 열람하시면 해당 보상을 획득하실 수 있습니다.","미접다관 챕터1을 열람하시면 해당 보상을 획득하실 수 있습니다.","미접다관 챕터3을 열람하시면 해당 보상을 획득하실 수 있습니다.","죽운 본부 챕터1을 열람하시면 해당 보상을 획득하실 수 있습니다.","죽운 본부 챕터3을 열람하시면 해당 보상을 획득하실 수 있습니다.","이한시 도착.","믿음이 있는 곳, 그곳이 바로 무대.","꿈을 향해 달린다, 초심을 잃지 않고.","고등학생 아이돌의 기묘한 표류.","매일 첫 2회 등급전 혹은 이벤트 대국에서 획득하는 인기도 보너스: {0}%→{1}%","등급전 혹은 이벤트 대국에서 순위로 획득하는 인기도 보너스: {0}%→{1}%","등급전 혹은 이벤트 대국에서 화료로 획득하는 인기도 보너스: {0}%→{1}%","트렌드에 대한 심도 깊은 연구","연습 후 최적의 휴식 공간","더 큰 옷장과 더 화려한 의상","화장품","향불","차","소원 혹은 사건 달성 성공 시, 신력 추가 증가 {0}","소원 혹은 사건 달성 실패 시, 성공으로 변할 확률: {0}%","신사 지표가 오를 시, 추가 증가 {0}","E","E+","D","D+","C","C+","B","B+","A","A+","S","S+","SS","SS+","SSS","SSS+","Ex","Ex+","【청소 떠넘기기다냥!】","냥? 마작을 하지 않아도 소원을 이룰 수 있다니, 엄청 편리하다냥… 그렇다면 이번 달 신사 청소를 모두 멍지로와 주인에게 떠넘기겠다냥!","이치히메, 뒤를 돌아볼래?","이치히메가 뒤를 돌아본 순간, 당신과 눈이 마주치며 분위기가 얼어붙었다. 퍼뜩 정신을 차린 그녀가 도망치려 했지만, 당신은 재빨리 그녀를 붙잡아 신사 청소의 보조를 시킬 수 있게 되었다. 이후, 이치히메는 종일 \'주인의 임무\'를 위해 동분서주했고, 아무것도 모르는 멍지로가 고생하는 이치히메를 보며 모든 청소를 자발적으로 떠맡았다. 결국, 이치히메의 소원이 이루어진 셈이다!","이치히메가 뒤를 돌아본 순간, 당신과 눈이 마주치며 분위기가 얼어붙었다. 퍼뜩 정신을 차린 그녀가 도망쳤고… 이런, 당신은 그만 그녀를 놓치고 말았다. 이후, 이치히메는 종일 당신을 피해 다녔을 뿐만 아니라, 스트레스를 푼다는 핑계로 도라야끼를 잔뜩 사 먹었고, 당신의 코인을 왕창 써버렸다!","이치히메, 내가 봐준다…","아기 고양이에게 무슨 잘못이 있겠는가? 당신은 이치히메의 속셈을 파헤치기보단, 문제의 본질을 파악했다. 당신은 청소의 달인 쿠죠 리우에게 도움을 요청했고, 혼천 신사의 청소 방식을 개선했다. 이치히메와 멍지로 모두 행복해졌다!","당신은 이치히메의 소원을 들어주었지만, 그 때문에 멍지로 보호 협회로부터 심각한 항의를 받게 되었다. 멍지로에게 무슨 잘못이 있겠는가? 결국, 당신은 새해 축제 업무를 처리하면서 혼천 신사의 청소 업무까지 떠맡게 되었다. 당신의 과로를 대가로 이치히메와 멍지로는 행복한 시간을 누리게 되었다.","미나미 후우카","【연말 선물】","한 해 동안 열심히 일한 \'죽운\'의 직원들을 위해 미나미 후우카가 풍성한 연말 선물을 준비하려 한다. 어떤 것을 선물해야 직원들이 가장 기뻐할까?","선물 상자를 준다","미나미 후우카는 풍성하고 실용적인 선물을 예쁘게 포장하여 직원들에게 나눠주었다. 무척이나 만족한 직원들은 \'CatChat\'에 사진을 공유했고, \'죽운\'은 \'꿈의 직장\'이라는 별명을 얻으며 이한시에서 더 큰 명성을 얻게 되었다.","직원들은 선물 상자가 지나치게 화려한 데다, 쓸데없이 크기만 크다고 느꼈다. 결국, 선물 상자들은 구석에 방치되어 먼지만 쌓이는 신세가 되었다. 기껏 준비한 명절 선물이 천덕꾸러기가 되어버렸다.","콘서트 표를 준다","누구에게나 마음속 아이돌이 존재하는데, 마침 직원들은 모두 한 아이돌을 좋아했다. 콘서트 현장에 울리는 팬들의 합창 소리가 어찌나 컸던지, 마치 초대형 노래방에 온 것 같았다. 아이돌은 팬들이 자신에게 노래를 불러주러 왔다며 기뻐했다.","콘서트 표가 선물이라는 소식을 듣고 직원들은 뜻밖에 기뻐했다. 소문에 의하면 콘서트 표를 되팔면 꽤 많은 돈을 벌 수 있다고 했다.","【맹인 점쟁이】","웬펑은 축제에서 한 맹인 점쟁이를 발견한다. 그 점쟁이는 뛰어난 운세 풀이 실력으로 많은 사람들을 사로잡고 있었다. 그 탓에 웬펑의 손님이 줄어들었을 뿐만 아니라, 맹인 점쟁이의 지지자들이 웬펑을 사기꾼 가짜 맹인이라며 매도하기 시작했다. 웬펑은 이 상황을 어떻게 해결해야 할까?","선글라스를 벗어본다","웬펑 역시 문제의 원인이 선글라스에 있다고 생각했고, 결국 선글라스 없이 손님을 맞이하기로 한다. 그는 축제 동안 주로 관상과 손금을 보았고, 맹인 점쟁이와 분야가 겹치지 않았다. 더욱이 그는 운세뿐만 아니라 복을 맞이하고 화를 피하는 방법을 다양하게 알고 있었기에 손님이 점점 많아졌다. 덕분에 맹인 점쟁이의 지지자들도 더는 문제를 제기하지 않게 되었다.","웬펑은 당신의 조언을 받아들여 선글라스를 벗었다. 처음에는 효과가 좋았고, 장사도 잘되기 시작했다. 하지만 축제에 놀러 온 단골손님들은 불만을 느꼈다. 선글라스를 벗은 웬펑의 모습은 무언가 허전해 보인다……","맹인의 진위를 알아본다","웬펑은 사람이 없는 틈을 타 맹인 점쟁이의 근처에 코인을 몇 개 놓아두었다. 예상대로, \'맹인 점쟁이\'는 주변을 은밀히 살피더니 재빨리 코인을 가방에 넣었다. 웬펑은 그 모습을 촬영한 뒤 그를 찾아갔고, 상황을 알아차린 맹인 점쟁이는 조용히 자리를 떠났다.","웬펑은 속임수, 도둑 촬영, 웃긴 표정 등 여러 방법을 시도했지만, 맹인 점쟁이는 좀처럼 빈틈을 보이지 않았다. 결국, 웬펑은 의심을 끝까지 입증하지 못한 채 상황을 마무리해야 했다.","치시","【업무 협력】","이렇게나 많은 관광객이라니, 이 몸이 솜씨를 발휘할 절호의 찬스잖아! 치시가 사사궁에 소원을 빌러 온 관광객을 대상으로 인연을 맺어주려고 한다. 허락해 줘야 할까?","허락한다","새해 소원 중에는 연애와 관련된 소원이 상당히 많이 포함되어 있었다. 치시 덕에 사제님은 이와 관련된 많은 일을 해결할 수 있었고, 높아진 소원 성취율 덕분에 사사궁에 대한 신뢰도도 높아졌다.","어떤 소원을 빌어도 연애와 관련된 방식으로 이루어지는 바람에, 사사궁에 \"함부로 소원을 빌지 말라\"는 말이 떠돌기 시작했다. 지나치게 많은 인연의 실로 인해 사람들의 걱정과 혼란이 늘어나고 말았다.","거절한다","신도들의 공물을 독점하길 원하는 궁주님을 떠올리며, 당신은 사사궁의 소원은 궁주님께 맡기는 것이 옳다는 말과 함께 치시에게 다른 장소에서 활동하기를 권유했다. 당신의 세심한 배려에 감동한 치시는 매력 복주머니를 선물했고, 사제님은 당신을 한층 더 눈여겨보게 되었다.","거절당한 치시는 단순하지만 가장 효과적인 \'손님 경쟁\'을 시작했다. 사사궁 입구에 숨어 소원 비는 사람들을 관찰하며 목표를 물색하기 시작한 것이다. 그러나 치시는 이에 너무 몰입한 나머지, 사사궁 이외의 지역에서 들어오는 연애 관련 소원을 모조리 놓쳐버렸다!","히메카와 히비키","【특별 방송】","설 기간 동안 히메카와 히비키가 사사궁 축제 현장에서 방송을 진행하려고 한다. 그녀의 요청을 승낙할까?","승낙한다","방송이라면 역시 히메카와 히비키가 전문이다. 그녀는 만반의 준비를 하여 시청자들에게 사사궁을 멋지게 소개하였고, 방송이 끝난 후 사사궁은 순식간에 핫플레이스로 등극했다. 그 결과 공물이 대폭 증가하였고, 사제님은 당신의 선택에 크게 만족하였다.","히메카와 히비키의 방송은 극적인 연출로 유명하다. 그녀는 시청자의 관심을 끌기 위해 사제님을 인터뷰하며, 사사궁에서 이루어진 재물, 학업, 평안 등 다양한 소원을 심층적으로 파헤쳤다. 그러나 얼마 지나지 않아 방송은 허위 과장 광고로 신고를 받았고, 사제님은 길길이 날뛰며 방송을 중단시켰다.","거절한다","명절에는 성실한 방송인도 휴식이 필요한 법이다. 당신은 히메카와 히비키에게 일을 잠시 멈추고 평범한 관광객처럼 시간을 보낼 것을 제안했다. 그녀는 제안을 받아들였지만, 축제에서 그녀를 알아본 팬들이 영상을 촬영해 온라인에 올렸고 화제를 모았다. 귀엽고 소탈한 그녀의 반전매력은 예상치 못한 호응을 얻었고, 사사궁은 그녀의 팬들에게 성지순례 장소로 유명해졌다. 결국, 그녀와 사사궁 모두 윈윈이었던 셈이다.","요청을 거절당한 히메카와 히비키는 곧바로 다른 장소를 물색했고, 이치히메의 승낙 하에 혼천 신사에서 신년 축제 방송을 진행했다. 유명 방송인의 영향력 덕에 혼천 신사는 대성황을 이루었고, 반면에 사사궁은 한산해지고 말았다.","스즈미야 안쥬","【프로그램 충돌】","질문: 동일한 작탁의 두 작사가 동시에 1등 소원을 빈다면, 이 프로그램 충돌은 어떻게 해결하면 좋을까요?","공물의 질로 결정한다","길고 복잡한 계산 끝에, KR-976은 자신이 가장 좋아하는 딸기 우유를 공물로 바쳐 1등을 얻어내기로 했다. 딸기 우유를 잃은 KR-976은 극한의 스트레스 탓에 도리어 계산 능력이 폭증했고, 이후 모든 판에서 승리를 거두었다. 결과적으로 소원은 성공리에 이루어졌다.","당신의 대답을 들은 KR-976은 손에 든 딸기 우유를 뚫어져라 바라보며 외쳤다. \"경고! 새로운 충돌 발생! 최고의 공물과 가장 좋아하는 음식이 일치합니다. 올바른 처리 방향은 무엇입니까?\" 결국, KR-976은 다시 혼란에 빠지고 말았다.","소원을 자세하게 적도록 한다","점수 1등, 도라패 수 1등, 리치 횟수 1등, 방총 횟수 1등… 이와 같은 방식으로 궁주님이 제공한 \'조정 프로그램\'을 적용하자, KR-976은 충돌이 모두 해결된 것을 깨달았다. 작사마다 자신의 업적을 쌓으며 모두 만족스러운 결과를 얻어냈다.","소원을 자세하게 적도록 하는 규칙은 사람들이 제기한 문제를 효과적으로 해결할 수 있었다. 하지만 길이가 글자 수 제한을 한참 초과했기에, 당신은 글을 모두 읽기 어려운 줄임말로 고쳐 써내야 했고, 궁주님을 기함하게 하였다.","잭스","【사냥꾼의 선택】","새해에는 검술이든 마작이든, 더 강해질 거다! 어이! 다음은 뭐부터 훈련해야 하지?","올해는 공격을 우선시한다","공격이 최고의 방어라는 말처럼, 당신은 잭스에게 공격 훈련에 집중할 것을 제안했다. 그 결과, 잭스는 새로운 스킬 \'초 진심 필살 일격\'을 습득했다! 그 후, 그의 치명타 확률과 마작 점수가 눈에 띄게 향상되었다.","잭스의 공격은 매우 강해졌지만, 반대로 방어가 약점이 되고 말았다. 마작에서 큰 역을 만들려다 상대방에게 선수를 빼앗기듯, 유연하고 민첩한 상대를 만날 때마다 잭스는 자신의 한계를 느끼게 되었다……","올해는 방어를 우선시한다","회피 능력을 단련하고 인내심을 충분히 갖는다면, 아무리 공격이 약하더라도 승리를 거머쥘 순간이 찾아오기 마련이다. 그것은 전장에서든, 작탁 위에서든 마찬가지이다. 당신은 잭스에게 방어 훈련에 집중하도록 권유했다. 그 결과, 잭스는 새로운 스킬 \'초 회피 능력\'을 습득했다! 그 후, 그의 방총 회피 능력과 화료 속도가 눈에 띄게 향상되었다.","잭스는 방어 훈련에만 매진한 나머지, 절대 패배할 리 없다는 믿음에 사로잡혀 공격 훈련을 소홀히 했다. 그 결과, 대결을 끝내지 못하는 상황이 잦아졌고, 작탁에서 유국이 빈번히 발생하게 되었다……","【새해맞이 대청소】","매년 새해맞이 대청소를 할 때마다 치오리 아가씨가 더는 입지 않을 오래된 옷이 잔뜩 발견된다. 버리기는 아깝고, 보관하자니 공간을 너무 차지한다. 쿠죠 리우는 이를 어떻게 처리해야 할까?","필요한 사람에게 기부한다","미카미 치오리와 상의한 뒤, 쿠죠 리우는 오래된 옷을 기부했다. 기진맥진해졌지만, 누군가에게 도움이 되었다는 생각에 그녀는 행복해졌다. 치오리 아가씨 역시 그녀의 행동을 자랑스러워했다.","쿠죠 리우가 자신의 옷을 기부했다는 것을 알게 된 미카미 치오리는 매우 슬퍼했다. 그 옷들에는 리우와의 소중한 추억이 담겨 있었던 것이다. 이를 알게 된 쿠죠 리우는 크게 후회하며, 앞으로는 모든 일을 치오리 아가씨와 상의하기로 다짐했다.","그냥 보관한다","쿠죠 리우는 오래된 옷을 기부하지 않고 남겨두기로 했다. 그녀는 옷을 정리하며 미카미 치오리와의 추억을 떠올리고 행복해했다. 오래된 옷을 정리하는 일은 그녀에게 업무가 아닌, 행복한 경험으로 남게 되었다.","쿠죠 리우는 오래된 옷을 남겨두었다. 그러나 완벽주의인 그녀는 위생 사각지대를 조금도 용납하지 않았고, 매일 옷을 정리하는 데 몰두했다. 하지만 옷은 날이 갈수록 늘어나기만 했다. 공간은 충분했지만 정리하는 사람이 늘어나지 않으니, 그녀는 언젠가 완벽하게 정리할 수 없는 날이 오리란 것을 깨달았다……","죠","【재미있는 밤】","죠는 평범한 신사 축제가 재미없다고 생각한다. 그는 당신에게 자신이 궁주님을 위해 재미있는 연극을 보여주겠다고 제안했다.","어떻게 할 건지 확인해 본다","죠는 내일을 기대하라는 말만 남길 뿐이었다. 당신은 과거에 그가 저질렀던 장난을 떠올리며 미리 대처하기로 했고, \'Gemini\'의 피에로 공연이 예정되어 있다는 소식을 미리 공개했다. 죠는 박장대소를 하고는 약속대로 다음 날 단원들과 함께 방문객들에게 멋진 공연을 선보였다. 떠나기 전, 죠는 당신에게 감사 인사를 했다. \"당신의 행동 덕분에 사람들에게 웃음을 주는 피에로인 나도 함께 재미를 느낄 수 있었답니다.\" 그는 당신과의 다음 협력도 기대하게 되었다.","지루함에 도전하는 이를 좋아하는 죠는 당신을 보며 박장대소를 터뜨리곤, 내일을 기대하라는 말과 함께 떠났다. 다음 날, 당신은 살짝 부는 바람에도 그의 장난이 아닐까 노심초사하고 있었다. 과한 경계심의 결말은, 사제님이 당신을 놀리기 좋은 사람이라고 생각하게 된 것이었다. 그녀의 미소를 보며 당신은 문득 깨달았다. 죠가 준비한 재미있는 연극이…… 당신이었다는 사실을.","역시 거절한다","얼마 전 있었던 죽운 축제에서 죠가 \'재미\'를 어떻게 생각하는지 알게 된 당신은 즉시 제안을 거절했다. 겉보기에는 평온한 것 같았던 밤이 지나고, 다음날 당신이 거리로 갔을 때 모든 상점의 블랙리스트에 죠의 이름이 올라가 있었다. 무슨 일이 일어났는지는 알 수 없지만, 전화 너머로 들리는 죠의 목소리는 어제보다 훨씬 밝았다.","얼마 전 있었던 죽운 축제에서 죠가 \'재미\'를 어떻게 생각하는지 알게 된 당신은 즉시 제안을 거절했다. 겉보기에는 평온한 것 같았던 밤이 지나고, 다음날 당신이 거리로 갔을 때 모든 상점의 블랙리스트에 죠의 이름이 올라가 있었다. 무슨 일이 일어났는지는 알 수 없지만, 상점 주인들이 당신을 에워싸기 시작했다. 아무래도 큰일이 난 것 같다.","유엔샤오","【설 휴가】","페이밍은 유엔샤오에게 한 달간 설 휴가를 주었다. 그녀와 \'호궈\'는 당신과 함께 즐거운 설 명절을 보내고 싶어하지만, 당신은 휴가 없이 설 내내 사사궁에서 열심히 일해야 한다……","사사궁으로 초대한다","이한시에 고대 전설 속 싸움의 신의 탈것이 있었다니? 사제님은 뜻밖에도 \'호궈\'에게 관심을 드러내며 당신의 제안을 흔쾌히 받아들였다. \'호궈\'는 사사궁에서 맛있는 음식을 먹으며 신나게 놀았고, 사제님과 유엔샤오도 마작패로 짝맞추기 게임을 하며 즐거운 시간을 보냈다.","사사궁에 소원을 빌러 오는 사람이 점점 많아졌는데, 어쩐지 \'호궈\'를 보기 위한 것 같았다. 지나치게 열정적인 방문객들에 놀란 \'호궈\'는 유엔샤오에게 배운 쿵후로 매일같이 높은 궁벽을 타고 올랐다. 결국, 당신은 \'호궈\'를 잡으러 이리저리 뛰어다니며 고생하게 되었다.","미안하지만 거절한다","유엔샤오는 함께 설을 보낼 수 없는 당신의 사정을 이해하고, 그런 당신을 안쓰러워하며 사사궁의 업무를 돕기로 했다. 그녀의 도움으로 당신은 매일 두 시간씩 일찍 퇴근할 수 있었고, 덕분에 유엔샤오, \'호궈\'와 함께 설날 저녁 식사하자는 약속을 지킬 수 있었다.","유엔샤오는 아쉬운 마음을 뒤로 한 채 당신과 작별 인사를 했다. 그녀는 휴일을 충실히 보내기 위해 매일 화 위칭과 쇼핑을 하거나 아원과 맛집을 돌아다녔고, 새로운 친구도 잔뜩 사귀었다. 그녀가 보내준 사진 속에는 축제의 즐거운 분위기가 가득했고, 그 사진을 본 당신은 끝나지 않는 야근이 더더욱 길게만 느껴졌다……","한나","【마음과 솜씨】","새해가 되니 친구들에게 자수 선물을 하고 싶은 생각이 드는겨. 근디, 내가 과연 잘 만들 수 있을지가 걱정되는구먼……","선물은 마음이 중요하다","한나는 당신의 조언을 따랐다. 결과물은 시중에 나와 있는 완성도 높은 수공예품에 미치지 못했지만, 한나만의 독특한 디자인이 두드려졌다. 친구들은 세상에 단 하나뿐인 선물을 받고 매우 기뻐했다.","친구들은 선물을 받고 매우 기뻐했다. 단지, 뱀의 해인데 어째서 코끼리가 수놓아져 있는지 의아해했을 뿐이다. 한나는 큰 충격을 받고 말았다……","신의 힘으로 완성도를 높인다","한나는 자수 디자인에 대한 영감이 넘쳐났지만, 기술이 부족해 이를 제대로 구현하지 못하고 있었다. 사제님이 신통력을 발휘해 자수의 선을 매끄럽고 뚜렷하게 만들어주었고, 한나의 아이디어가 하나씩 빛을 보기 시작했다. 친구들은 선물을 받고 한나의 뛰어난 디자인 센스에 감탄했다.","사제님이 신통력을 발휘해 한나의 자수를 놀랍도록 정교하게 만들어 주었다. 친구들은 선물을 받고 어디서 산 자수인지 의아해했다. 그것이 한나의 작품이라는 것을 믿는 사람은 아무도 없었고, 결국 한나는 좌절하고 말았다.","【명절의 찻집】","설 연휴 동안 오랜만에 보는 일가친지들과 함께 \'미접다관\'을 방문하는 손님이 늘었다. 여기까진 좋은 일인 듯하나, 일부 손님이 차를 마신 뒤 불면증에 시달린다며 불만을 제기했다. 페이밍은 이를 어떻게 해결해야 할지 고민 중이다.","차 대신 과일 주스를 제공한다","\'미접다관\'은 명절 동안 과일 주스와 차가 포함된 패밀리 세트를 출시했다. 이 때문에 차를 즐기는 손님과 즐기지 않는 가족, 친구들이 모두 찻집에 모여 이야기를 나누며 따뜻한 명절을 만끽할 수 있었다. 덕분에 \'미접다관\'에 대한 입소문이 퍼져나갔다.","\'미접다관\'은 뜻밖에 차 대신 과일 주스로 유명해졌고, 손님들이 몰려들어 신제품 \'너에게 행운 주스\'의 사진을 찍어 기념했다. 하지만 폭발적인 주스 판매량과는 달리, 차 주문량은 점점 줄어들어 주객전도가 되어버렸다.","경고 문구를 써놓는다","페이밍은 매장에 안내 게시판을 달아, 모든 차 음료의 카페인 함량과 불면증 유발 가능성을 자세하게 표기했다. 찻집을 방문한 손님들은 이를 참고해 적합한 차를 고를 수 있게 되었으며, 카페인 함량이 높은 차를 마시고 불면증에 시달리지 않게 되었다.","유엔샤오가 설 휴가를 떠난 사이, 새로 고용한 알바생이 자료를 잘못 입력해 모든 차 음료의 불면증 위험 등급이 10배 높게 표기되고 말았다. 이 탓에 손님들은 \'미접다관\'의 방문을 꺼리게 되었고, 매장의 매출이 크게 감소하며 큰 손실을 보게 되었다.","미카미 치오리","【시간의 마법】","리우가 이곳이 영험하다고 하길래 혹시나 해서 치오리도 와 봤어. 설 연휴를 좀 더 늘려달라는 소원을 들어주지 않아도 치오리는 당신들을 탓하지 않을 거야. 하지만 만약 들어준다면…… 자, 이 오리구이는 리우가 몇 시간이나 줄 서서 사 온 거니까 남기지 말고 먹도록 해!","함께하는 시간을 늘려준다","이한시에 내린 갑작스러운 폭설로 인해 항공편이 지연되면서, 미카미 치오리는 부모님과 함께 이틀이라는 시간을 더 보낼 수 있었다. 그들은 함께 눈사람을 만들거나 눈싸움을 했고, 축제를 구경하며 아름다운 추억을 남겼다.","이한시에 내린 갑작스러운 폭설로 인해 항공편이 이틀간 연기되었다. 그러나 미카미 치오리는 부모님이 업무 지연 때문에 초조하고 불안해하는 모습을 보며 깊은 죄책감을 느꼈다.","함께하는 시간을 소중히 한다","가족과 함께하는 시간을 늘릴 수는 없지만, 더 의미 있게 바꿀 수는 있다. 미카미 치오리는 부모님과 함께 축제를 구경하며 사진으로 많은 추억을 남겼고, 부모님과 함께 사사궁에서 소원을 빌었다. 그렇게 함께한 모든 순간이 한층 소중하고 특별하게 느껴졌다.","미카미 치오리는 부모님과의 여행 계획을 꼼꼼히 준비했지만, 지나치게 신경을 쓴 나머지 깊은 스트레스에 빠지고 말았다. 아무리 계획을 짜도 완벽하지 않다고 느낀 그녀는, 결국 모든 계획을 쿠죠 리우에게 맡겨버렸다. 여행은 즐거웠지만, 마음 한구석엔 떨쳐버릴 수 없는 아쉬움이 남았다.","키타미 사와코","【설날 저녁 식사】","아이와 함께 설맞이 장보기에 나선 키타미 사와코는 친구 가족이 올해 설날엔 식당에서 저녁 식사를 할 거라는 아이의 말을 듣게 되었다. 그 말을 듣고 키타미 사와코는 올해엔 본인 가족도 식당에서 설을 맞이해야 할지 고민되기 시작했다.","설날엔 집에서 먹어야 한다","키타미 사와코 역시 설날 저녁 식사의 핵심은 가족이 식탁에 둘러앉아 한 해 동안 있었던 일들을 나누며 가족의 사랑이 담긴 음식을 즐기는 것이라고 생각했다. 역시나 올해의 설음식도 언제나처럼 맛있었다.","예년과 마찬가지로 키타미 사와코는 가족과 함께 맛있는 설음식을 즐겼다. 하지만 풍성한 식사 뒤에는 엉망이 된 그릇과 냄비가 가득했다. 부엌 청소를 마친 그녀는 한숨을 내쉬며 말했다. \"요리는 즐겁지만, 설거지는 최악이야!\"","외식을 시도해본다","새해는 새로운 시도와 즐거움을 의미하기도 한다. 설날 저녁, 키타미 사와코는 아이를 데리고 식당을 방문했는데, 그곳에서 아이가 친구를 만나고 깜짝 놀라며 즐거워했다. 아이 얼굴에 가득한 미소를 보며, 키타미 사와코는 새로운 한 해에 대한 기대감으로 가슴이 설렜다.","이한시의 식당은 대부분 설날 저녁 예약이 차 있었다. 키타미 사와코는 겨우 한 곳을 찾아낼 수 있었지만, 그녀의 손맛에 비하면 한참 부족한 가공식품만 먹을 수 있었다. 그 탓에 설날을 기념하는 열기가 조금 식어버리고 말았다.","후지","【복수쌍전관의 손님맞이】","새해가 다가오자, 후지는 복수쌍전관에서 손님맞이 행사를 준비하려 한다. 하지만 어떤 행사를 열면 좋을지 고민 중이다.","\'친구 초대\' 이벤트를 한다","\'친구 초대\' 이벤트는 순조롭게 진행되었다. 기존 고객들이 새로운 고객들을 데리고 왔고, 할인 혜택은 최대치로 제공되었다. 새로운 고객들은 초심자의 운으로 천화, 지화 등 다양한 방식으로 승리를 얻어냈다. 복수쌍전관의 장사는 크게 흥했고, 사사궁도 긍정적인 영향을 받을 수 있었다.","\'친구 초대\' 이벤트는 성황리에 진행되었다. 기존 고객들이 새로운 고객들을 데리고 왔고, 할인 혜택은 최대치로 제공되었다. 그러나 복수쌍전관은 이와 관련된 부정적인 피드백도 받게 되었다. 쏟아지는 \'초대 요청\' 탓에 \'해피 프라이데이\'의 할인 정보를 놓친 손님들이 속출한 것이다.","하네만 무료 이벤트를 한다","복수쌍전관에서 하네만 이상을 달성한 작사에게 무료 이벤트를 제공했다! 이는 복수쌍전관 사상 유례없는 혜택이었고, 도장은 대성황을 이루며 문턱이 닳을 정도로 손님이 몰렸다.","복수쌍전관에서 하네만 이상을 달성한 작사에게 무료 이벤트를 제공했다! 복수쌍전관 사상 유례없는 혜택이었지만, 후지의 환한 미소에 작사들은 묘한 불길함을 느꼈다. 후지 사장의 호의를 누린 대가로, 무언가 끔찍한 일이 일어날 것 같다는 예감이…… 결국 설 연휴 동안 복수쌍전관은 오히려 평소보다 한산해지고 말았다.","화 위칭","【록이냐 전통극이냐】","화 위칭은 밴드 \'썬더스톰\'의 새해 공연에서 전통극과 록 음악을 결합한 무대를 선보이려고 한다. 그녀가 고민 중인 두 가지 방향 중 어느 쪽이 나을까?","전통극 중심에 록 요소 추가","화 위칭은 무사의 모습으로 무대에 올라, 시원시원한 가사와 깔끔한 몸짓으로 관객들의 환호를 끌어냈다. 공연이 절정에 다다르자, 그녀는 록 음악을 활용해 분위기를 최고조로 끌어올렸다. 관객들은 신나게 몸을 흔들며 감동의 눈물을 흘렸고, \"새로운 시대가 왔다, 록 윌 네버다이!\"라 외쳤다.","화 위칭은 무사의 모습으로 무대에 올라, 시원시원한 가사와 깔끔한 몸짓을 선보였다. 그러나 관객들은 공연장을 잘못 찾아왔나, 이게 정말 록 공연이 맞나 의문을 품었다.","록 중심에 전통극 요소 추가","화 위칭은 클래식한 록 음악을 부르며 무대를 달궜고, 관객들은 노래에 맞추어 머리를 흔들며 열광했다. 후렴이 끝나자, 화 위칭은 가장 자신 있는 전통 가락을 한 소절 선보였고, 관객들은 전통과 현대의 완벽한 조화에 감탄했다.","화 위칭은 클래식한 록 음악을 부르며 무대를 달궜고, 관객들은 노래에 맞추어 머리를 흔들며 열광했다. 후렴이 끝나자, 화 위칭은 전통 가락을 한 소절 선보였고, 관객들은 당혹감을 감추지 못했다. 결국, 공연장의 분위기가 어색해지고 말았다.","화 위바이","【관리 방침】","화 위바이는 평소 \'부몽\' 단원들을 엄격히 가르치지만, 단원들은 설 연휴만이라도 쉬고 싶어 한다. 극단 관리를 어떻게 하면 좋을까?","땀 흘리지 않고 얻는 건 없다","무대 위의 3분은 무대 밑 10년의 노력에서 비롯된다는 말처럼, 화 위바이는 설 연휴 동안에도 \'부몽\'의 단원들이 연습을 게을리하지 않도록 엄격히 지도했다. 한 단원이 연습 장면을 \'CatChat\'에 올렸고, 이는 큰 화제를 불러일으키며 더 많은 사람이 전통극에 관심을 갖게 했다.","무대 위의 3분은 무대 밑 10년의 노력에서 비롯된다는 말처럼, 화 위바이는 설 연휴 동안에도 \'부몽\'의 단원들이 연습을 게을리하지 않도록 엄격히 지도했다. 하지만 엄격한 지도로도 자유를 갈망하는 마음을 완전히 억누를 수 없었고, 단원들의 연습 성과는 기대에 미치지 못했다.","채찍과 당근은 관리자의 덕목","화 위바이는 극단의 관리 방식도 시대에 맞춰 변화해야 한다고 생각했고, 지난 1년간 고생한 \'부몽\'의 단원들을 설 연휴 동안 푹 쉬게 했다. 그 결과, 휴식을 마친 단원들은 이전보다 더 활기찬 모습으로 무대에 복귀해 훌륭한 공연을 선보였다.","화 위바이는 극단의 관리 방식도 시대에 맞춰 변화해야 한다고 생각했고, 지난 1년간 고생한 \'부몽\'의 단원들을 설 연휴 동안 푹 쉬게 했다. 그러나 하루를 쉬면 내가 알고, 이틀을 쉬면 스승이 알며, 사흘을 쉬면 관객이 안다 했던가. 연습을 쉬었던 단원 중 상당수가 눈에 띄게 퇴보한 모습을 보였다.","???","【뱀의 이별】","시간이 정말 빠르구나. 올해의 축제도 거의 끝났어. 보수는 잘 받았느냐? 이곳의 풍습과 사람은 정말 흥미롭지만, 이제 더 넓은 세상을 보러 떠나야겠구나.","안녕, 당신을 기억할게","이별의 밤이 되어서야 당신은 깨달았다. 축제 운영으로 바빴던 탓에 정작 당신과 사제님은 축제를 제대로 즐기지 못했던 것이다. 북적이는 시장을 함께 거닐며, 당신은 사제님에게 여러 음식을 추천했다. 그녀는 당신이 추천한 모든 음식이 입에 잘 맞는다 했다. 문득, 당신은 사제님의 자태가 처음 만났을 때의 고고함과는 사뭇 달라졌음을 느꼈다…… 사제님의 발걸음이 점점 빨라졌고, 당신은 가까스로 그녀를 따라갔다. 그 순간, 그녀의 모습이 어딘가 변한듯한 느낌이 들었다……","보고싶으면 언제든 돌아와","인망 높은 촌장","몇 년째 봄마다 심한 가뭄에 시달리고 있어요. 땅이 갈라져 파종도 어려운 상황입니다. 궁주님, 도와주세요!","봄에 비를 내려준다","가뭄에 강한 씨앗을 준다","우리 아이가 1등","하아…… 아이의 마작 실력이 학업 성적만큼 늘었으면 좋겠어요.","두 마리 토끼를 다 잡을 수는 없는 법이다","학업 -2","다 큰 초등학생","소원을 빌만한 일이 딱히 없어요. 그래도 굳이 빌어본다면…… 새해맞이 밤 장터에서 사제님과 함께 놀고 싶어요.","사제님은 바쁘시다","흔쾌히 수락한다","겨울이 너무 추워요","연말이 다가오며 날씨가 추워졌지만, 형편이 어려워 두꺼운 옷은커녕 마작 세트를 살 여유도 없어요.","겨울옷을 한 벌 건넨